import React, { useState } from 'react';
import { 
  Send, 
  Info, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2
} from 'lucide-react';
import { FACULTY_DATA, SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, TheoryAttributes, LabAttributes, FeedbackEntry } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [facultyId, setFacultyId] = useState('');
  const [subjectId, setSubjectId] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const [scores, setScores] = useState<Record<string, number>>({});

  const handleScoreChange = (metric: string, val: number) => {
    setScores(prev => ({ ...prev, [metric]: val }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyId || !subjectId) return alert('Select Faculty and Subject');

    setIsSubmitting(true);

    // Simulate Blockchain Transmission & Anonymization
    await new Promise(resolve => setTimeout(resolve, 2000));

    const entry: FeedbackEntry = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      facultyId,
      subjectId,
      data: scores as any,
      timestamp: Date.now(),
      encryptedHash: btoa(JSON.stringify(scores)).substr(0, 32)
    };

    onSubmit(entry);
    setIsSubmitting(false);
    setIsSubmitted(true);
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-200 shadow-xl text-center max-w-2xl mx-auto flex flex-col items-center">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 animate-bounce">
          <CheckCircle2 size={40} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4">Feedback Submitted!</h2>
        <p className="text-slate-500 mb-8 leading-relaxed">
          Your feedback has been anonymized, encrypted, and recorded on the private ledger. 
          Your identity was scrubbed before submission.
        </p>
        <button 
          onClick={() => setIsSubmitted(false)}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all"
        >
          Submit Another
        </button>
      </div>
    );
  }

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden animate-in slide-in-from-bottom duration-500">
      <div className="p-8 bg-slate-900 text-white flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold flex items-center gap-3">
            <Lock className="text-blue-400" size={24} />
            Anonymous Feedback Portal
          </h2>
          <p className="text-slate-400 text-sm mt-1">SRK Institute of Technology (CSE Dept)</p>
        </div>
        <div className="flex bg-slate-800 p-1 rounded-xl">
          <button 
            onClick={() => setType(FeedbackType.THEORY)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${type === FeedbackType.THEORY ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
          >
            <BookOpen size={16} /> Theory
          </button>
          <button 
            onClick={() => setType(FeedbackType.LAB)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${type === FeedbackType.LAB ? 'bg-blue-600 text-white' : 'text-slate-400'}`}
          >
            <FlaskConical size={16} /> Lab
          </button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-600 uppercase tracking-wider">Select Faculty</label>
            <select 
              value={facultyId}
              onChange={(e) => setFacultyId(e.target.value)}
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            >
              <option value="">Choose a Faculty Member</option>
              {FACULTY_DATA.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-600 uppercase tracking-wider">Subject Title</label>
            <select 
              value={subjectId}
              onChange={(e) => setSubjectId(e.target.value)}
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            >
              <option value="">Choose a Subject</option>
              {SUBJECTS.map(s => <option key={s.id} value={s.id}>{s.name} ({s.code})</option>)}
            </select>
          </div>
        </div>

        <div className="space-y-6">
          <div className="flex items-center justify-between border-b border-slate-100 pb-2">
            <h3 className="font-bold text-slate-800 text-lg uppercase tracking-tight">Performance Metrics</h3>
            <span className="text-xs text-slate-400 italic">Score from 1 (Poor) to 5 (Excellent)</span>
          </div>

          <div className="grid gap-4">
            {metrics.map((metric, idx) => (
              <div key={metric} className="flex flex-col sm:flex-row sm:items-center justify-between p-5 rounded-2xl bg-slate-50 border border-slate-100 group hover:border-blue-200 transition-all">
                <span className="font-semibold text-slate-700">{idx + 1}. {metric}</span>
                <div className="flex items-center gap-3 mt-3 sm:mt-0">
                  {[1, 2, 3, 4, 5].map(val => (
                    <button
                      key={val}
                      type="button"
                      onClick={() => handleScoreChange(metric, val)}
                      className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all ${
                        scores[metric] === val 
                          ? 'bg-blue-600 text-white scale-110 shadow-lg' 
                          : 'bg-white text-slate-400 hover:bg-slate-200'
                      }`}
                    >
                      {val}
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="p-4 bg-amber-50 border border-amber-100 rounded-2xl flex gap-4">
          <Info className="text-amber-500 shrink-0" size={20} />
          <p className="text-xs text-amber-800 leading-relaxed">
            By clicking submit, your data will be cryptographically hashed. The resulting hash is signed with a one-time voting token issued to your ID, ensuring nobody—not even the HOD—can link this feedback back to your login.
          </p>
        </div>

        <button 
          disabled={isSubmitting}
          className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold shadow-lg shadow-blue-200 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
        >
          {isSubmitting ? (
            <><Loader2 className="animate-spin" /> Anonymizing & Recording...</>
          ) : (
            <><Send size={20} /> Submit Anonymous Feedback</>
          )}
        </button>
      </form>
    </div>
  );
};

export default FeedbackPortal;

