import React, { useState } from 'react';
import { 
  Send, 
  Info, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature
} from 'lucide-react';
import { SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);

  // Matrix State: [SubjectId][MetricIndex] = Score
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  // Determine subjects based on type to match images exactly
  // Theory: ML, CD, CNS, OOAD, MSD
  // Lab: ML Lab, CD Lab, MSD Lab, CNS Lab
  const currentSubjects = type === FeedbackType.THEORY 
    ? SUBJECTS 
    : SUBJECTS.filter(s => s.id !== 'OOAD').map(s => ({ ...s, name: s.name + ' Lab' }));

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate that all cells are filled
    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) {
      return alert('Please provide ratings for ALL subjects and ALL attributes before submitting.');
    }

    if (!hasSigned) {
      return alert('Please acknowledge the digital signature to proceed.');
    }

    setIsSubmitting(true);

    // Simulate Blockchain Batch Transmission
    await new Promise(resolve => setTimeout(resolve, 2500));

    // In a real system, we'd emit multiple entries or a batch hash
    const batchEntry: FeedbackEntry = {
      id: `batch-${Date.now()}`,
      type,
      facultyId: 'batch-multi',
      subjectId: 'batch-multi',
      data: matrixScores as any,
      timestamp: Date.now(),
      encryptedHash: btoa(JSON.stringify({ matrixScores, suggestions })).substr(0, 32)
    };

    onSubmit(batchEntry);
    setIsSubmitting(false);
    setIsSubmitted(true);
  };

  const resetForm = () => {
    setIsSubmitted(false);
    setMatrixScores({});
    setSuggestions('');
    setHasSigned(false);
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-200 shadow-xl text-center max-w-2xl mx-auto flex flex-col items-center animate-in zoom-in duration-300">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 shadow-inner">
          <CheckCircle2 size={40} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-4">Batch Feedback Recorded</h2>
        <p className="text-slate-500 mb-8 leading-relaxed">
          Your collective ratings for all subjects have been anonymized and cryptographically sealed on the SRK-IT Feedback Chain.
        </p>
        <button 
          onClick={resetForm}
          className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
        >
          Submit New Batch
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-500">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
        {/* Header Section */}
        <div className="p-8 bg-slate-900 text-white flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <div className="flex items-center gap-3 mb-1">
              <div className="p-2 bg-blue-600/20 rounded-lg">
                <ShieldCheck size={20} className="text-blue-400" />
              </div>
              <h2 className="text-2xl font-bold tracking-tight">Student Feedback Matrix</h2>
            </div>
            <p className="text-slate-400 text-sm">SRK Institute of Technology • CSE Dept • 2024-25</p>
          </div>

          <div className="flex bg-slate-800 p-1.5 rounded-2xl self-start">
            <button 
              type="button"
              onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${type === FeedbackType.THEORY ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
              <BookOpen size={18} /> CLASS (Theory)
            </button>
            <button 
              type="button"
              onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${type === FeedbackType.LAB ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
            >
              <FlaskConical size={18} /> LABORATORY
            </button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-0">
          {/* Legend Area */}
          <div className="px-8 py-4 bg-slate-50 border-b border-slate-200 flex flex-wrap gap-6 items-center text-xs font-bold text-slate-500 uppercase tracking-widest">
            <span>Rating Scale:</span>
            <div className="flex gap-4">
              <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-600"></div> 5: Excellent</span>
              <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-400"></div> 4: Very Good</span>
              <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-slate-400"></div> 3: Fair</span>
              <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-amber-400"></div> 2: Poor</span>
              <span className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> 1: Very Poor</span>
            </div>
          </div>

          {/* Matrix Table */}
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-50">
                  <th className="p-6 text-left border-b border-r border-slate-200 min-w-[300px] bg-slate-50 sticky left-0 z-10 shadow-[2px_0_5px_rgba(0,0,0,0.02)]">
                    <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Attributes for Feedback</span>
                  </th>
                  {currentSubjects.map(s => (
                    <th key={s.id} className="p-6 text-center border-b border-slate-200 min-w-[120px]">
                      <span className="block text-sm font-bold text-slate-700">{s.name}</span>
                      <span className="block text-[10px] text-slate-400 font-mono mt-1 opacity-60">ID: {s.code}</span>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {metrics.map((metric, mIdx) => (
                  <tr key={mIdx} className="hover:bg-blue-50/30 transition-colors group">
                    <td className="p-6 border-r border-slate-200 bg-white group-hover:bg-blue-50/50 sticky left-0 z-10 shadow-[2px_0_5px_rgba(0,0,0,0.02)]">
                      <div className="flex gap-4 items-start">
                        <span className="text-xs font-bold text-slate-300 w-5 mt-1">{(mIdx + 1).toString().padStart(2, '0')}</span>
                        <span className="text-sm font-semibold text-slate-700 leading-snug">{metric}</span>
                      </div>
                    </td>
                    {currentSubjects.map(s => (
                      <td key={s.id} className="p-4 text-center">
                        <div className="flex flex-col items-center justify-center gap-1">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''}
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))}
                            className={`w-16 p-2 text-center font-bold rounded-xl border appearance-none cursor-pointer transition-all outline-none focus:ring-2 focus:ring-blue-500/20 ${
                              matrixScores[s.id]?.[mIdx] 
                                ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                                : 'bg-slate-50 border-slate-200 text-slate-400 hover:border-blue-300'
                            }`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          <span className="text-[9px] font-bold text-slate-300 uppercase tracking-tighter">Points</span>
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="p-8 space-y-8 bg-white border-t border-slate-200">
            {/* Suggestions */}
            <div className="space-y-4">
              <label className="text-sm font-bold text-slate-700 uppercase tracking-wider flex items-center gap-2">
                <MessageSquare size={18} className="text-blue-500" /> 
                Your suggestions for overall improvements
              </label>
              <textarea 
                value={suggestions}
                onChange={(e) => setSuggestions(e.target.value)}
                placeholder="Share your thoughts on lab conditions, syllabus pace, or departmental facilities..."
                className="w-full p-6 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all min-h-[140px] text-slate-700 shadow-inner"
              />
            </div>

            {/* Signature & Privacy Policy */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-end">
              <div className="p-6 bg-blue-50/50 border border-blue-100 rounded-2xl">
                <div className="flex gap-4 items-start">
                  <div className="p-2 bg-blue-600 rounded-lg mt-1 shrink-0">
                    <Lock size={16} className="text-white" />
                  </div>
                  <div className="space-y-2">
                    <h4 className="font-bold text-blue-900 text-sm">Blockchain Privacy Protocol</h4>
                    <p className="text-xs text-blue-800 leading-relaxed opacity-80">
                      Your response is bundled into a single transaction. A <strong>Zero-Knowledge Proof (ZKP)</strong> verifies your eligibility without recording your Student ID in the payload. The HOD only sees the aggregate "Feedback Points".
                    </p>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex items-center gap-3 p-4 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer hover:bg-slate-100 transition-colors select-none"
                     onClick={() => setHasSigned(!hasSigned)}>
                  <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${
                    hasSigned ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-300'
                  }`}>
                    {hasSigned && <CheckCircle2 size={16} />}
                  </div>
                  <div>
                    <span className="text-sm font-bold text-slate-700 block">Digital Verification</span>
                    <span className="text-[10px] text-slate-400 uppercase tracking-widest flex items-center gap-1">
                      <Signature size={12} /> Sign and Acknowledge
                    </span>
                  </div>
                </div>

                <button 
                  disabled={isSubmitting}
                  className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-bold shadow-2xl transition-all flex items-center justify-center gap-3 disabled:opacity-40 active:scale-[0.98]"
                >
                  {isSubmitting ? (
                    <><Loader2 className="animate-spin" /> Sealing Anonymous Batch...</>
                  ) : (
                    <><Send size={20} /> Submit Complete Semester Feedback</>
                  )}
                </button>
              </div>
            </div>
          </div>
        </form>
      </div>

      <div className="flex items-center justify-center gap-2 text-slate-400 text-xs py-4">
        <Lock size={12} /> Securely monitored by SRK-IT CSE Blockchain Node • Block #84931-B
      </div>
    </div>
  );
};

