import React, { useState } from 'react';
import { 
  Send, 
  Info, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  XCircle
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);

  // Matrix State: [SubjectId][MetricIndex] = Score
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Review the following college feedback suggestion for abusive language, profanity, toxicity, or harassment. 
        Suggestion: "${text}"`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN, description: "True if content is toxic or abusive" },
              reason: { type: Type.STRING, description: "Brief reason for rejection" }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "You are an academic content moderator. Flag any swearing, insults, or hate speech as abusive. Be strict but allow constructive criticism."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      console.error("AI Validation Error:", error);
      return { isAbusive: false }; // Fail-safe: allow if AI fails, though ideally we'd block
    } finally {
      setIsAnalyzing(false);
    }
  };

  const currentSubjects = type === FeedbackType.THEORY 
    ? SUBJECTS 
    : SUBJECTS.filter(s => s.id !== 'OOAD').map(s => ({ ...s, name: s.name + ' Lab' }));

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAbuseError(null);

    // 1. Basic Validation
    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please provide ratings for ALL subjects and ALL attributes.');
    if (!hasSigned) return alert('Please acknowledge the digital signature to proceed.');

    // 2. AI Content Moderation
    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Abusive language detected. Please use professional language.");
      return;
    }

    setIsSubmitting(true);

    // Simulate Blockchain Batch Transmission
    await new Promise(resolve => setTimeout(resolve, 2500));

    const batchEntry: FeedbackEntry = {
      id: `batch-${Date.now()}`,
      type,
