  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  XCircle,
  ShieldAlert
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);

  // Matrix State: [SubjectId][MetricIndex] = Score
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze this student feedback suggestion for a college faculty: "${text}". 
        Check for:
        1. Profanity or abusive language.
        2. Personal insults or harassment.
        3. Non-academic toxic behavior.

        Respond ONLY in JSON format.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN, description: "True if content is toxic, profane, or abusive" },
              reason: { type: Type.STRING, description: "Professional explanation for rejection" }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "You are an automated academic content moderator for SRK Institute of Technology. You must block any feedback that contains swearing, insults, or harassment. Constructive criticism about teaching methods is allowed, but must be polite."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      console.error("AI Integrity Check Error:", error);
      // In case of error, we proceed but log it. For maximum safety, you could block on error too.
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  const currentSubjects = type === FeedbackType.THEORY 
    ? SUBJECTS 
    : SUBJECTS.filter(s => s.id !== 'OOAD').map(s => ({ ...s, name: s.name + ' Lab' }));

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAbuseError(null);

    // 1. Completion Validation
    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) {
      return alert('Please provide ratings for ALL subjects and ALL attributes.');
    }

    if (!hasSigned) {
      return alert('Digital signature acknowledgment is mandatory.');
    }

