export const SOLIDITY_CONTRACT_CODE = `
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SRKInstituteFeedback {
    struct FeedbackMetadata {
        string dept;      // CSE, ECE, AIDS etc.
        string semester;  // 1.1, 3.2 etc.
        string subject;
        string facultyId;
    }

    struct FacultyStats {
        uint256 totalScore;
        uint256 responseCount;
    }

    // Partitioned Storage: Dept -> Sem -> Subject -> Faculty -> Stats
    mapping(string => mapping(string => mapping(string => mapping(string => FacultyStats)))) private registry;
    mapping(bytes32 => bool) public nullifiers;

    event FeedbackSealed(string dept, string sem, string facultyId, uint256 timestamp);

    function submitSecureFeedback(
        bytes32 nullifier, 
        string memory dept,
        string memory sem,
        string memory subjectId,
        string memory facultyId,
        uint256 scoreSum
    ) public {
        require(!nullifiers[nullifier], "Identity already used for this batch");
        nullifiers[nullifier] = true;

        FacultyStats storage stats = registry[dept][sem][subjectId][facultyId];
        stats.totalScore += scoreSum;
        stats.responseCount += 1;

        emit FeedbackSealed(dept, sem, facultyId, block.timestamp);
    }

    function getAverage(string memory d, string memory sm, string memory sub, string memory fac) 
        public view returns (uint256) 
    {
        FacultyStats memory stats = registry[d][sm][sub][fac];
        if (stats.responseCount == 0) return 0;
        return (stats.totalScore * 100) / (stats.responseCount * 10);
    }
}
`;

import React, { useState, useEffect } from 'react';
import { 
  Send, 
  Info, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  XCircle,
  ShieldAlert
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry, User } from '../types';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User; // User passed from App to get Dept/Sem
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout, user }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);

  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze this student feedback suggestion for a college faculty: "${text}". 
        Check for profanity, insults, or harassment.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "You are an automated academic content moderator for SRK Institute of Technology. Block any feedback containing swearing or harassment. Constructive criticism about teaching is allowed."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      console.error("AI Integrity Check Error:", error);
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Filter subjects based on User's Dept and Sem
  const filteredBaseSubjects = SUBJECTS.filter(s => 
    s.department === user.department && s.semester === user.semester
  );

  const currentSubjects = type === FeedbackType.THEORY 
    ? filteredBaseSubjects 
    : filteredBaseSubjects.filter(s => s.id !== 'OOAD').map(s => ({ ...s, name: s.name + ' Lab' }));

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setAbuseError(null);

    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please provide ratings for ALL subjects and ALL attributes.');
    if (!hasSigned) return alert('Digital signature acknowledgment is mandatory.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Your suggestion contains prohibited language.");
      return;
    }

    setIsSubmitting(true);
    await new Promise(resolve => setTimeout(resolve, 2000));

    const batchEntry: FeedbackEntry = {
      id: `batch-${Date.now()}`,
      type,
      facultyId: 'batch-multi',
      subjectId: 'batch-multi',
      department: user.department!,
      semester: user.semester!,
      data: matrixScores as any,
      timestamp: Date.now(),
      encryptedHash: btoa(JSON.stringify({ matrixScores, suggestions })).substr(0, 32)
    };

    onSubmit(batchEntry);
    setIsSubmitting(false);
    setIsSubmitted(true);
    setTimeout(() => onLogout(), 4000);
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-200 shadow-xl text-center max-w-2xl mx-auto flex flex-col items-center animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-green-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-2">Feedback Recorded</h2>
        <p className="text-slate-500 mb-8 leading-relaxed font-medium">
          Data sealed on the blockchain for <span className="text-blue-600 font-bold">{user.department} {user.semester}</span>.
          <br />
          <span className="text-blue-600 font-bold">Securely logging you out now...</span>
        </p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
          <div className="bg-blue-600 h-full animate-[progress_4s_linear_forwards]"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-500">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
        <div className="p-8 bg-slate-900 text-white flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-600 rounded-2xl shadow-lg shadow-blue-500/20">
              <ShieldCheck size={28} className="text-white" />
            </div>
            <div>
              <h2 className="text-2xl font-bold tracking-tight">{user.department} Feedback Matrix</h2>
              <p className="text-slate-400 text-sm font-medium">Semester {user.semester} • CSE Dept (Autonomous)</p>
            </div>
          </div>

          <div className="flex bg-slate-800 p-1.5 rounded-2xl">
            <button type="button" onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-bold transition-all ${type === FeedbackType.THEORY ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}><BookOpen size={18} /> CLASS</button>
            <button type="button" onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-bold transition-all ${type === FeedbackType.LAB ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}><FlaskConical size={18} /> LAB</button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-0">
          <div className="px-8 py-4 bg-slate-50 border-b border-slate-200 flex flex-wrap gap-8 items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
            <span>Rating Scale:</span>
            <div className="flex gap-6">
              <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-blue-600"></div> 5: Excellent</span>
              <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-blue-400"></div> 4: Very Good</span>
              <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-slate-400"></div> 3: Good</span>
              <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-amber-400"></div> 2: Poor</span>
              <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-red-500"></div> 1: V. Poor</span>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-50">
                  <th className="p-6 text-left border-b border-r border-slate-200 min-w-[320px] bg-slate-50 sticky left-0 z-10 shadow-[4px_0_10px_rgba(0,0,0,0.02)]">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Feedback Attributes</span>
                  </th>
                  {currentSubjects.map(s => (
                    <th key={s.id} className="p-6 text-center border-b border-slate-200 min-w-[140px]">
                      <span className="block text-sm font-bold text-slate-800 leading-tight">{s.name}</span>
                      <span className="block text-[10px] text-slate-400 font-mono mt-2 opacity-70">{s.code}</span>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {metrics.map((metric, mIdx) => (
                  <tr key={mIdx} className="hover:bg-blue-50/30 transition-colors group">
                    <td className="p-6 border-r border-slate-200 bg-white group-hover:bg-blue-50/50 sticky left-0 z-10 shadow-[4px_0_10px_rgba(0,0,0,0.02)]">
                      <div className="flex gap-5 items-start">
                        <span className="text-xs font-black text-slate-300 w-5 mt-1">{(mIdx + 1).toString().padStart(2, '0')}</span>
                        <span className="text-sm font-semibold text-slate-700 leading-snug">{metric}</span>
                      </div>
                    </td>
                    {currentSubjects.map(s => (
                      <td key={s.id} className="p-4 text-center">
                        <div className="flex flex-col items-center justify-center gap-1.5">
                          <select value={matrixScores[s.id]?.[mIdx] || ''} onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))} className={`w-16 h-12 p-2 text-center font-black rounded-xl border appearance-none transition-all outline-none focus:ring-4 focus:ring-blue-500/10 ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:border-blue-400'}`}>
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          <span className="text-[9px] font-black text-slate-300 uppercase tracking-tighter">Marks</span>
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="p-8 space-y-8 bg-white border-t-2 border-slate-100">
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <label className="text-sm font-bold text-slate-800 uppercase tracking-wider flex items-center gap-2"><MessageSquare size={18} className="text-blue-600" /> Suggestions for overall improvement</label>
                {isAnalyzing && <span className="text-[10px] font-black text-blue-600 uppercase flex items-center gap-2 animate-pulse bg-blue-50 px-3 py-1 rounded-full border border-blue-100"><ShieldAlert size={12} /> AI Content Analysis Running</span>}
              </div>
              <textarea value={suggestions} onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} placeholder="Professional feedback (e.g. pace of CD syllabus, lab manual clarity)..." className={`w-full p-6 bg-slate-50 border-2 rounded-2xl focus:ring-8 outline-none transition-all min-h-[160px] text-slate-700 font-medium ${abuseError ? 'border-red-500 focus:ring-red-500/5' : 'border-slate-100 focus:ring-blue-500/5 focus:border-blue-600/30'}`} />
              {abuseError && <p className="text-red-600 text-xs font-bold uppercase tracking-tight flex items-center gap-2 bg-red-50 p-4 rounded-xl border border-red-100"><AlertTriangle size={16} /> {abuseError}</p>}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-center pt-8 border-t border-slate-100">
              <div className="p-6 bg-blue-50/40 border border-blue-100 rounded-2xl">
                <div className="flex gap-4 items-start">
                  <div className="p-2 bg-blue-600 rounded-lg shrink-0"><Lock size={18} className="text-white" /></div>
                  <div>
                    <h4 className="font-bold text-blue-900 text-sm">Dept-Partitioned Privacy</h4>
                    <p className="text-[11px] text-blue-800 leading-relaxed font-medium mt-1">Your feedback is strictly tied to <strong>{user.department} {user.semester}</strong>. Data is isolated to your HOD's dashboard only.</p>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex items-center gap-4 p-5 bg-slate-50 border border-slate-200 rounded-2xl cursor-pointer hover:bg-slate-100 transition-all group" onClick={() => setHasSigned(!hasSigned)}>
                  <div className={`w-7 h-7 rounded-lg border-2 flex items-center justify-center transition-all ${hasSigned ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-300 group-hover:border-blue-400'}`}>{hasSigned && <CheckCircle2 size={18} />}</div>
                  <div className="flex-1">
                    <span className="text-sm font-bold text-slate-800 block">Sign Acknowledgement</span>
                    <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1 mt-0.5"><Signature size={12} className="text-slate-300" /> Digital Sign Confirmed</span>
                  </div>
                </div>
                <button disabled={isSubmitting || isAnalyzing} className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase tracking-widest text-sm shadow-2xl transition-all disabled:opacity-40 flex items-center justify-center gap-3">
                  {isAnalyzing ? <><Loader2 className="animate-spin" /> Ethics Checking...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Ledger...</> : <><Send size={20} /> Finalize Submission</>}
                </button>
              </div>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default FeedbackPortal;

import React, { useState } from 'react';
import { 
  FileText, 
  ShieldCheck, 
  BarChart3, 
  Settings, 
  Code
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import TechnicalRoadmap from './components/TechnicalRoadmap';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import { FeedbackEntry, User, UserRole } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'feedback' | 'analysis' | 'roadmap'>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) {
      setActiveTab('analysis');
    } else {
      setActiveTab('feedback');
    }
  };

  const logout = () => {
    setUser(null);
  };

  if (!user) {
    return <Auth onAuthenticate={handleAuth} />;
  }

  const tabs = [
    { id: 'feedback', label: 'Submit Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3, roles: [UserRole.ADMIN] },
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
        user={user}
        onLogout={logout}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} 
          user={user}
        />

        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-[#fdfdfd]">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && <FeedbackPortal onSubmit={addFeedback} onLogout={logout} user={user} />}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

