interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout, user }) => {
  const isSessionActive = true; 

  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);

  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "Academic content moderator. Block insults."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
