  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const calculateTotal = (subjectId: string) => {
    const scores = matrixScores[subjectId] || {};
    return Object.values(scores).reduce((a, b) => a + b, 0);
  };

