          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-bold text-slate-800 mb-2">Feedback Recorded</h2>
        <p className="text-slate-500 mb-8 leading-relaxed font-medium">
          Data sealed on the blockchain for <span className="text-blue-600 font-bold">{user.department} {user.semester}</span>.
          <br />
          <span className="text-blue-600 font-bold">Securely logging you out...</span>
        </p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
          <div className="bg-blue-600 h-full animate-[progress_4s_linear_forwards]"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-500">
      {/* Official Form Header */}
      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-xl overflow-hidden print:shadow-none">
        <div className="p-10 border-b border-slate-100 bg-slate-50/50">
          <div className="flex flex-col md:flex-row justify-between items-start gap-6">
            <div className="flex gap-6 items-center">
              <div className="w-20 h-20 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-2xl shadow-xl shadow-slate-900/10">SRK</div>
              <div>
                <h1 className="text-2xl font-black text-slate-900 tracking-tight">SRK INSTITUTE OF TECHNOLOGY</h1>
                <p className="text-xs text-slate-500 font-medium max-w-md mt-1">
                  Enikepadu, Vijayawada 521108 • Approved by AICTE, Affiliated to JNTUK • Accredited with NBA & NAAC 'A' grade
                </p>
                <div className="flex gap-3 mt-3">
                   <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest">{user.department}</span>
                   <span className="px-3 py-1 bg-slate-100 text-slate-700 rounded-full text-[10px] font-black uppercase tracking-widest">SEM {user.semester}</span>
                </div>
              </div>
            </div>

            <div className="flex bg-slate-200 p-1 rounded-2xl">
              <button 
                type="button" 
                onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} 
                className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.THEORY ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <BookOpen size={16} /> CLASS
              </button>
              <button 
                type="button" 
                onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} 
                className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.LAB ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <FlaskConical size={16} /> LABORATORY
              </button>
            </div>
          </div>

          <div className="mt-8 p-4 bg-white border border-slate-200 rounded-2xl flex flex-wrap gap-x-12 gap-y-2 items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.15em]">
            <span className="text-slate-900">Rating Scale:</span>
