              <span className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-slate-400"></div> 3: Fair</span>
              <span className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-amber-400"></div> 2: Poor</span>
              <span className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-full bg-red-500"></div> 1: Very Poor</span>
            </div>
          </div>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="overflow-x-auto">
