                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Attributes for Feedback</span>
                  </th>
                  {currentSubjects.map(s => (
                    <th key={s.id} className="p-6 text-center border-r border-slate-200 min-w-[130px] bg-slate-50">
                      <span className="block text-sm font-black text-slate-900 mb-1">{s.id}</span>
                      <span className="block text-[9px] font-bold text-slate-400 uppercase tracking-tighter opacity-70">Theory Subject</span>
                    </th>
