              <span className="text-[10px] font-black text-slate-400">SELECTIVE LOGIN ENABLING</span>
            </div>
            <div className="p-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
              {DEPARTMENTS.slice(0, 8).map(dept => (
                <div key={dept} className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <h4 className="font-black text-xs text-slate-800 mb-4 border-b border-slate-200 pb-2">{dept} Department</h4>
                  <div className="flex flex-wrap gap-2">
                    {SEMESTERS.map(sem => {
                      const key = `${dept}-${sem}`;
                      const isActive = settings.activeDeptSems.includes(key);
                      return (
                        <button
                          key={sem}
                          onClick={() => toggleDeptSemAccess(dept, sem)}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all border ${
                            isActive 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-md' 
                              : 'bg-white border-slate-200 text-slate-400'
                          }`}
                        >
                          {sem}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 text-white/5"><Settings size={120} /></div>
            <h3 className="text-xl font-black mb-6 relative z-10 uppercase tracking-widest">Global Switch</h3>
            <div className="space-y-6 relative z-10">
              <div className="p-6 bg-white/5 border border-white/10 rounded-2xl">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs font-black text-slate-400 uppercase">Status</span>
                  <span className={settings.isSessionActive ? 'text-emerald-400' : 'text-red-400'}>
                    {settings.isSessionActive ? 'ACTIVE' : 'LOCKED'}
                  </span>
                </div>
                <button 
                  onClick={toggleSession}
                  className={`w-full py-4 rounded-xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-3 ${
                    settings.isSessionActive ? 'bg-red-600 hover:bg-red-700' : 'bg-emerald-600 hover:bg-emerald-700'
                  }`}
                >
                  {settings.isSessionActive ? <ToggleRight /> : <ToggleLeft />}
                  {settings.isSessionActive ? 'Emergency Stop' : 'Start Session'}
                </button>
              </div>
              <p className="text-[10px] text-slate-400 leading-relaxed font-bold uppercase">
                Stopping the session will instantly revoke student portal access across all department nodes.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Faculty CRUD Interface */}
      {activeSubTab === 'faculty' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-right duration-500">
