          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-slate-50 text-left border-b border-slate-100">
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Faculty Name</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Dept</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Primary Subject</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {faculties.map(fac => (
                  <tr key={fac.id} className="hover:bg-slate-50/50 transition-colors">
