                    <td className="p-6"><span className="px-3 py-1 bg-slate-100 rounded-lg text-[10px] font-black">{fac.department}</span></td>
                    <td className="p-6 text-sm text-slate-600 font-medium">{fac.subjects.join(', ')}</td>
                    <td className="p-6">
                      <div className="flex gap-2">
                        <button 
                          onClick={() => openFacultyModal(fac)}
                          className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                        >
                          <Edit3 size={16} />
                        </button>
                        <button 
                          onClick={() => deleteFaculty(fac.id)}
                          className="p-2 text-slate-400 hover:text-red-600 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Dataset Management: Questionnaire Editor */}
      {activeSubTab === 'dataset' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in zoom-in duration-500">
          <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2">
                <Database className="text-indigo-600" size={18} /> Theory Attribute Set ({settings.theoryQuestions.length})
              </h3>
              <button 
                onClick={() => handleSaveQuestions('theory')}
                className="p-2 hover:bg-blue-50 rounded-lg transition-colors group"
                title="Save Changes"
              >
                <Save size={18} className="text-slate-400 group-hover:text-blue-600" />
              </button>
            </div>
            <div className="p-6 space-y-4 overflow-y-auto max-h-[500px]">
              {settings.theoryQuestions.map((q, idx) => (
                <div key={idx} className="flex gap-4 items-center p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  <span className="text-[10px] font-black text-slate-300 w-4">{(idx + 1).toString().padStart(2, '0')}</span>
                  <input 
                    value={q} 
                    onChange={(e) => {
                      const newQ = [...settings.theoryQuestions];
                      newQ[idx] = e.target.value;
                      setSettings({...settings, theoryQuestions: newQ});
                    }}
                    className="flex-1 bg-transparent text-sm font-semibold text-slate-700 outline-none focus:text-blue-600 transition-colors" 
                  />
                  <button 
                    onClick={() => removeQuestion('theory', idx)}
                    className="p-1.5 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              ))}
              <button 
                onClick={() => setSettings({...settings, theoryQuestions: [...settings.theoryQuestions, 'New Theory Attribute']})}
                className="w-full p-4 border-2 border-dashed border-slate-200 rounded-2xl text-slate-400 hover:border-blue-400 hover:text-blue-400 transition-all flex items-center justify-center gap-2 font-bold text-xs"
              >
                <Plus size={16} /> Add New Attribute
              </button>
            </div>
          </div>

          <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
              <h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2">
                <Database className="text-emerald-600" size={18} /> Laboratory Attribute Set ({settings.labQuestions.length})
              </h3>
              <button 
                onClick={() => handleSaveQuestions('lab')}
                className="p-2 hover:bg-blue-50 rounded-lg transition-colors group"
                title="Save Changes"
              >
                <Save size={18} className="text-slate-400 group-hover:text-blue-600" />
              </button>
            </div>
            <div className="p-6 space-y-4 overflow-y-auto max-h-[500px]">
              {settings.labQuestions.map((q, idx) => (
                <div key={idx} className="flex gap-4 items-center p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  <span className="text-[10px] font-black text-slate-300 w-4">{(idx + 1).toString().padStart(2, '0')}</span>
                  <input 
                    value={q} 
                    onChange={(e) => {
                      const newQ = [...settings.labQuestions];
                      newQ[idx] = e.target.value;
                      setSettings({...settings, labQuestions: newQ});
                    }}
                    className="flex-1 bg-transparent text-sm font-semibold text-slate-700 outline-none focus:text-blue-600 transition-colors" 
                  />
                  <button 
                    onClick={() => removeQuestion('lab', idx)}
                    className="p-1.5 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              ))}
              <button 
                onClick={() => setSettings({...settings, labQuestions: [...settings.labQuestions, 'New Lab Attribute']})}
                className="w-full p-4 border-2 border-dashed border-slate-200 rounded-2xl text-slate-400 hover:border-blue-400 hover:text-blue-400 transition-all flex items-center justify-center gap-2 font-bold text-xs"
              >
                <Plus size={16} /> Add New Attribute
              </button>
            </div>
          </div>
        </div>
      )}

      {/* --- MODAL: FACULTY ADD/EDIT --- */}
      {isFacultyModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-950/40 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="font-black text-sm uppercase tracking-widest">{editingFaculty ? 'Edit Faculty Pair' : 'New Faculty Pairing'}</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Audit Log: {userCheck()}</p>
              </div>
              <button onClick={() => setIsFacultyModalOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <form onSubmit={saveFaculty} className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Name</label>
                <input 
                  type="text" 
                  required
                  value={facultyForm.name} 
                  onChange={(e) => setFacultyForm({...facultyForm, name: e.target.value})}
                  className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-semibold"
                  placeholder="e.g. Dr. K. Venkat"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Department</label>
                <select 
                  value={facultyForm.department}
                  onChange={(e) => setFacultyForm({...facultyForm, department: e.target.value as Department})}
                  className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-semibold appearance-none"
                >
                  {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center ml-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Subject Mapping (Codes)</label>
                  <button type="button" onClick={addSubjectField} className="text-blue-600 font-black text-[10px] uppercase hover:underline flex items-center gap-1"><Plus size={12} /> Add Field</button>
                </div>
                <div className="space-y-3">
                  {facultyForm.subjects?.map((sub, idx) => (
                    <div key={idx} className="flex gap-2">
                      <input 
                        type="text" 
                        required
                        value={sub} 
                        onChange={(e) => handleSubjectChange(idx, e.target.value)}
                        className="flex-1 p-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-600 transition-all font-semibold"
                        placeholder="e.g. CS301"
                      />
                      {facultyForm.subjects!.length > 1 && (
                        <button 
                          type="button" 
                          onClick={() => setFacultyForm({...facultyForm, subjects: facultyForm.subjects?.filter((_, i) => i !== idx)})}
                          className="p-3 text-slate-300 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={18} />
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className="pt-4 flex gap-4">
                <button type="button" onClick={() => setIsFacultyModalOpen(false)} className="flex-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-black uppercase tracking-widest text-xs transition-all">Cancel</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-blue-500/20 transition-all">Seal Record</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="flex items-center justify-center gap-4 py-8">
         <div className="h-px bg-slate-200 flex-1"></div>
         <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-2">
           <ShieldAlert size={14} className="text-blue-500" /> Administrative Action Immutable via Blockchain Audit Log
         </p>
         <div className="h-px bg-slate-200 flex-1"></div>
      </div>
    </div>
  );
};

// Mock utility for audit log
const userCheck = () => {
  const hash = Math.random().toString(36).substring(7).toUpperCase();
  return `NODE-${hash}`;
};

export default AdminDashboard;

import React, { useState } from 'react';
import { 
  Settings, 
  Users, 
  Power, 
  Plus, 
  Trash2, 
  Edit3, 
  Database, 
  ShieldAlert,
  Save,
  FileSpreadsheet,
  ToggleLeft,
  ToggleRight,
  Activity,
  UserCheck,
  X,
  CheckCircle2
} from 'lucide-react';
import { Department, Faculty, AdminSettings } from '../types';
import { DEPARTMENTS, SEMESTERS, FACULTY_DATA, THEORY_METRICS, LAB_METRICS } from '../constants';

const AdminDashboard: React.FC = () => {
  // --- STATE ---
  const [settings, setSettings] = useState<AdminSettings>({
    isSessionActive: true,
    activeDeptSems: ['CSE-3.1', 'AIDS-3.1', 'IT-2.2'],
    theoryQuestions: THEORY_METRICS,
    labQuestions: LAB_METRICS
  });

  const [faculties, setFaculties] = useState<Faculty[]>(FACULTY_DATA);
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'dataset'>('control');

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // --- HANDLERS: SESSION & ACCESS ---
  const toggleSession = () => setSettings(prev => ({ ...prev, isSessionActive: !prev.isSessionActive }));

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSettings(prev => ({
      ...prev,
      activeDeptSems: prev.activeDeptSems.includes(key)
        ? prev.activeDeptSems.filter(k => k !== key)
        : [...prev.activeDeptSems, key]
    }));
  };

  // --- HANDLERS: FACULTY CRUD ---
  const openFacultyModal = (fac?: Faculty) => {
    if (fac) {
      setEditingFaculty(fac);
      setFacultyForm({ ...fac });
    } else {
      setEditingFaculty(null);
      setFacultyForm({ name: '', department: 'CSE', subjects: [''] });
    }
    setIsFacultyModalOpen(true);
  };

  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    if (window.confirm("Confirm deletion? This record will be dropped from the active registry.")) {
      setFaculties(prev => prev.filter(f => f.id !== id));
    }
  };

  const handleSubjectChange = (idx: number, val: string) => {
    const newSubs = [...(facultyForm.subjects || [])];
    newSubs[idx] = val;
    setFacultyForm({ ...facultyForm, subjects: newSubs });
  };

  const addSubjectField = () => {
    setFacultyForm({ ...facultyForm, subjects: [...(facultyForm.subjects || []), ''] });
  };

  // --- HANDLERS: DATASET (QUESTIONS) ---
  const handleSaveQuestions = (type: 'theory' | 'lab') => {
    alert(`${type.toUpperCase()} attributes set for Academic Year 2024-25 has been sealed.`);
  };

  const removeQuestion = (type: 'theory' | 'lab', idx: number) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, labQuestions: newQ});
    }
  };

  const addQuestion = (type: 'theory' | 'lab') => {
    if (type === 'theory') {
      setSettings({...settings, theoryQuestions: [...settings.theoryQuestions, 'New Evaluation Metric']});
    } else {
      setSettings({...settings, labQuestions: [...settings.labQuestions, 'New Lab Metric']});
    }
  };

  const updateQuestionText = (type: 'theory' | 'lab', idx: number, val: string) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ[idx] = val;
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ[idx] = val;
      setSettings({...settings, labQuestions: newQ});
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl ${settings.isSessionActive ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
              <Power size={24} />
            </div>
            <button onClick={toggleSession} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase transition-all shadow-sm ${
              settings.isSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              {settings.isSessionActive ? 'Live' : 'Stopped'}
            </button>
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Session State</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{settings.isSessionActive ? 'Accepting Form' : 'Portal Closed'}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4">
            <UserCheck size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Faculty Count</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{faculties.length} Records</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4">
            <Activity size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Data Privacy</h3>
          <p className="text-xl font-black text-slate-900 mt-1">E2E Sealed</p>
        </div>

        <div className="bg-slate-900 p-6 rounded-2xl shadow-xl flex flex-col justify-between text-white">
          <div className="p-3 bg-white/10 rounded-xl w-fit mb-4 text-blue-400">
            <ShieldAlert size={24} />
          </div>
          <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Super Admin</h3>
          <p className="text-xl font-black mt-1">Full Access</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-slate-100 p-1.5 rounded-2xl w-fit border border-slate-200 shadow-inner">
        {[
          { id: 'control', label: 'Access Control', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'dataset', label: 'Attribute Set', icon: FileSpreadsheet }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {/* Control Content */}
      {activeSubTab === 'control' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-left duration-500">
          <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h3 className="font-black text-slate-900 text-[11px] uppercase tracking-widest flex items-center gap-2">
                <ShieldAlert className="text-amber-500" size={18} /> Departmental Login Permissions
              </h3>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">SELECT DEPT-SEM TO ALLOW FEEDBACK</span>
            </div>
            <div className="p-8 grid grid-cols-1 sm:grid-cols-2 gap-6">
              {DEPARTMENTS.slice(0, 8).map(dept => (
                <div key={dept} className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                  <h4 className="font-black text-xs text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between items-center">
                    {dept} Dept
                    <span className="text-[10px] text-slate-400">Matrix</span>
                  </h4>
                  <div className="flex flex-wrap gap-2">
                    {SEMESTERS.map(sem => {
                      const key = `${dept}-${sem}`;
                      const isActive = settings.activeDeptSems.includes(key);
                      return (
                        <button
                          key={sem}
                          onClick={() => toggleDeptSemAccess(dept, sem)}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all border ${
                            isActive 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-lg' 
                              : 'bg-white border-slate-200 text-slate-400 hover:border-blue-400'
                          }`}
                        >
                          {sem}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

