/**
 * SRK-IT Web3 Service (Simulation Mode)
 * Handles Pinata IPFS pinning and simulated blockchain execution.
 */

const PINATA_JWT = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..FkhdpKUPChotY4jsb5RqSmr7QQ1DmBX-TE_66vauHf4";

export interface SimulationResult {
  success: boolean;
  ipfsHash: string;
  txHash: string;
  timestamp: number;
}

/**
 * Uploads feedback payload to Pinata IPFS
 */
async function uploadToIPFS(payload: any): Promise<string> {
  try {
    const response = await fetch("https://api.pinata.cloud/pinning/pinJSONToIPFS", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${PINATA_JWT}`,
      },
      body: JSON.stringify({
        pinataContent: payload,
        pinataMetadata: {
          name: `SRK-FB-${Date.now()}`,
          keyvalues: {
            dept: payload.department,
            sem: payload.semester,
          }
        },
      }),
    });

    if (!response.ok) {
      throw new Error(`Pinata upload failed: ${response.statusText}`);
    }

    const data = await response.json();
    return data.IpfsHash;
  } catch (error) {
    console.error("IPFS Error:", error);
    throw error;
  }
}

/**
 * Sends feedback via gasless transaction simulation
 */
export async function sendGaslessFeedback(feedbackData: any): Promise<SimulationResult> {
  console.log("[Web3Service] Initiating batch submission...");

  // 1. Live IPFS Upload
  const ipfsHash = await uploadToIPFS(feedbackData);
  console.log(`[Web3Service] Live IPFS CID: ${ipfsHash}`);

  // 2. Simulated Blockchain Transaction
  // In a real scenario, this would use Ethers.js to call a meta-transaction relay
  const mockTxHash = "0x" + Array.from({length: 64}, () => Math.floor(Math.random() * 16).toString(16)).join("");

  console.log("[Web3Service] SIMULATING BLOCKCHAIN WRITE...");
  console.log(`[Web3Service] Data Partition: ${feedbackData.department} | ${feedbackData.semester}`);
  console.log(`[Web3Service] Payload Link: https://gateway.pinata.cloud/ipfs/${ipfsHash}`);
  console.log(`[Web3Service] Mock Tx Hash: ${mockTxHash}`);

  // Simulate latency
  await new Promise(resolve => setTimeout(resolve, 2500));

  return {
    success: true,
    ipfsHash,
    txHash: mockTxHash,
    timestamp: Date.now()
  };
}

