import React, { useState, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  ShieldAlert,
  Calendar,
  UserCheck,
  ExternalLink
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { SUBJECTS, THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry, User } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout, user }) => {
  const isSessionActive = true; 

  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);

  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity and professional conduct for a college faculty feedback form.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "Academic content moderator. Block insults or harassment."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  const filteredBaseSubjects = SUBJECTS.filter(s => 
    s.department === user.department && s.semester === user.semester
  );

  const currentSubjects = useMemo(() => {
    return type === FeedbackType.THEORY 
      ? filteredBaseSubjects 
      : filteredBaseSubjects.map(s => ({ ...s, name: s.id + ' Lab' }));
  }, [type, filteredBaseSubjects]);

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const calculateTotal = (subjectId: string): number => {
    const scores = matrixScores[subjectId] || {};
    return (Object.values(scores) as number[]).reduce((a, b) => a + b, 0);
  };

  const calculateSatisfaction = (subjectId: string): number => {
    const total = calculateTotal(subjectId);
    const max = metrics.length * 5;
    if (max === 0) return 0;
    return (total / max) * 100;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionActive) return alert('Feedback session is currently closed.');

    setAbuseError(null);
    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please provide ratings for ALL attributes across ALL subjects shown in the grid.');
    if (!hasSigned) return alert('Digitally signing the acknowledgment is mandatory before submission.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Your suggestion contains prohibited or unprofessional language.");
      return;
    }

    setIsSubmitting(true);

    try {
      const payload = {
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        satisfaction: currentSubjects.map(s => ({ subject: s.id, percent: calculateSatisfaction(s.id) })),
        studentEmail: user.email, // In real ZK, this is swapped for a nullifier
        timestamp: Date.now()
      };

      // 3. Live Web3 Submission
      const result = await sendGaslessFeedback(payload);
      setLastSubmission(result);

      const batchEntry: FeedbackEntry = {
        id: `batch-${Date.now()}`,
        type,
        facultyId: 'batch-multi',
        subjectId: 'batch-multi',
        department: user.department!,
        semester: user.semester!,
        data: matrixScores as any,
        timestamp: Date.now(),
        encryptedHash: result.ipfsHash
      };

      onSubmit(batchEntry);
      setIsSubmitting(false);
      setIsSubmitted(true);
      // Wait longer to let user see TX hash
      setTimeout(() => onLogout(), 8000);
    } catch (error) {
      alert("Submission failed. Please check network connection.");
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto flex flex-col items-center animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-green-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Recorded</h2>
        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 w-full mb-8 text-left space-y-3 font-mono">
           <div className="flex justify-between items-center text-[10px]">
             <span className="text-slate-400 uppercase font-black">IPFS CID</span>
             <a href={`https://gateway.pinata.cloud/ipfs/${lastSubmission?.ipfsHash}`} target="_blank" className="text-blue-600 hover:underline flex items-center gap-1">View JSON <ExternalLink size={10} /></a>
           </div>
           <p className="text-[10px] text-slate-700 break-all bg-white p-2 border border-slate-100 rounded-lg">{lastSubmission?.ipfsHash}</p>

           <div className="flex justify-between items-center text-[10px] pt-2">
             <span className="text-slate-400 uppercase font-black">Transaction Hash (Sim)</span>
             <span className="text-emerald-600 font-black">SEALED</span>
           </div>
           <p className="text-[10px] text-slate-500 break-all">{lastSubmission?.txHash}</p>
        </div>
        <p className="text-slate-500 mb-8 leading-relaxed font-medium">
          Digital seal applied to <span className="text-blue-600 font-bold">{user.department} {user.semester}</span> ledger.
          <br />
          <span className="text-blue-600 font-bold">Securely logging you out...</span>
        </p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
          <div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-700">
      {/* Official Form Style Container */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden print:shadow-none">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30">
          <div className="flex flex-col lg:flex-row justify-between items-center gap-8">
            <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
              <div className="flex items-center gap-4 mb-3">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg">SRK</div>
                <div>
                  <h1 className="text-xl font-black text-slate-900 leading-tight">SRK INSTITUTE OF TECHNOLOGY</h1>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Approved by AICTE • Affiliated to JNTUK • Accredited with NBA & NAAC 'A' grade</p>
                </div>
              </div>
              <div className="mt-2 text-[11px] font-black text-slate-600 uppercase tracking-[0.2em] border-l-4 border-blue-600 pl-4 py-1">
                Department of {user.department} - Multi-Subject Node
              </div>
            </div>

            <div className="flex flex-col items-end gap-3">
              <div className="bg-slate-900 text-white px-6 py-2 rounded-full text-[10px] font-black tracking-[0.2em] uppercase">
                Academic Year: 2024-25
              </div>
              <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
                <button 
                  type="button" 
                  onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} 
                  className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.THEORY ? 'bg-white text-blue-600 shadow-md scale-[1.02]' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <BookOpen size={16} /> CLASS
                </button>
                <button 
                  type="button" 
                  onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} 
                  className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.LAB ? 'bg-white text-blue-600 shadow-md scale-[1.02]' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <FlaskConical size={16} /> LABORATORY
                </button>
              </div>
            </div>
          </div>

          <div className="mt-10 p-6 bg-white border border-slate-200 rounded-[2rem] shadow-sm flex flex-wrap gap-y-4 gap-x-12 items-center">
            <div className="text-[11px] font-black text-slate-900 uppercase tracking-widest bg-slate-100 px-4 py-2 rounded-lg">5-Point Scale Assessment:</div>
            <div className="flex flex-wrap gap-8">
              {[
                { n: 5, l: 'Excellent', c: 'blue-600' },
                { n: 4, l: 'Very Good', c: 'blue-400' },
                { n: 3, l: 'Fair', c: 'slate-400' },
                { n: 2, l: 'Poor', c: 'amber-500' },
                { n: 1, l: 'Very Poor', c: 'red-600' }
              ].map(item => (
                <span key={item.n} className="flex items-center gap-2.5 text-[10px] font-bold text-slate-600 uppercase">
                  <div className={`w-3 h-3 rounded-full bg-${item.c}`}></div>
                  <span className="text-slate-900">{item.n}</span> {item.l}
                </span>
              ))}
            </div>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-50 border-y border-slate-200">
                  <th className="p-8 text-left border-r border-slate-200 min-w-[450px] sticky left-0 bg-slate-50 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)]">
                    <div className="flex flex-col">
                      <span className="text-[12px] font-black text-slate-900 uppercase tracking-[0.3em] mb-1">{type === FeedbackType.THEORY ? 'CLASS' : 'LABORATORY'}</span>
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Attributes for Feedback</span>
                    </div>
                  </th>
                  {currentSubjects.map(s => (
                    <th key={s.id} className="p-8 text-center border-r border-slate-200 min-w-[140px] bg-slate-50">
                      <div className="flex flex-col items-center">
                        <span className="block text-sm font-black text-slate-900 mb-1">{s.id}</span>
                        <span className="block text-[8px] font-black text-slate-400 uppercase tracking-tighter opacity-80 whitespace-nowrap">Subject Node</span>
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {metrics.map((metric, mIdx) => (
                  <tr key={mIdx} className="hover:bg-blue-50/40 transition-colors group">
                    <td className="p-8 border-r border-slate-200 bg-white group-hover:bg-blue-50/50 sticky left-0 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)]">
                      <div className="flex gap-6 items-start">
                        <span className="text-xs font-black text-slate-300 w-6 shrink-0 mt-0.5 leading-none">{(mIdx + 1).toString().padStart(2, '0')}</span>
                        <span className="text-[13px] font-semibold text-slate-700 leading-normal">{metric}</span>
                      </div>
                    </td>
                    {currentSubjects.map(s => (
                      <td key={s.id} className="p-6 text-center border-r border-slate-100">
                        <div className="relative group/select flex flex-col items-center gap-1.5">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))} 
                            className={`w-14 h-14 p-2 text-center font-black rounded-2xl border-2 appearance-none transition-all outline-none cursor-pointer text-base ${
                              matrixScores[s.id]?.[mIdx] 
                                ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-500/30 scale-110' 
                                : 'bg-slate-50 border-slate-100 text-slate-400 hover:border-blue-300 hover:bg-white'
                            }`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          <span className="text-[8px] font-black text-slate-300 uppercase tracking-tighter opacity-0 group-hover/select:opacity-100 transition-opacity">Marks</span>
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}

                {/* Official Total Satisfaction Level Row - Exactly as per source images */}
                <tr className="bg-slate-900 text-white font-black uppercase tracking-widest text-[10px]">
                  <td className="p-8 border-r border-slate-800 sticky left-0 bg-slate-900 z-20">
                    <div className="flex flex-col">
                      <span className="text-[11px] mb-1">Total Satisfaction Level = (Total points / 50 x 100)</span>
                      <span className="text-slate-500 text-[8px] font-bold">Calculation based on 10 standardized attributes</span>
                    </div>
                  </td>
                  {currentSubjects.map(s => (
                    <td key={s.id} className="p-8 text-center border-r border-slate-800 bg-slate-900/90">
                      <div className="space-y-2">
                        <div className="text-[11px] text-blue-400 font-mono tracking-tighter">{calculateTotal(s.id)} <span className="text-white/40">/ 50</span></div>
                        <div className="text-sm font-black bg-white/10 py-1 rounded-lg ring-1 ring-white/20">{calculateSatisfaction(s.id).toFixed(0)}%</div>
                      </div>
                    </td>
                  ))}
                </tr>
              </tbody>
            </table>
          </div>

          <div className="p-10 space-y-12 bg-white">
