                )}
              </div>
              <textarea 
                value={suggestions} 
                onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} 
                placeholder="Please share constructive feedback regarding curriculum pace, lab manual clarity, or overall faculty engagement..." 
                className={`w-full p-10 bg-slate-50 border-2 rounded-[2.5rem] focus:ring-8 outline-none transition-all min-h-[220px] text-slate-700 font-medium placeholder:text-slate-300 shadow-inner ${
                  abuseError ? 'border-red-500 focus:ring-red-500/10' : 'border-slate-100 focus:ring-blue-500/5 focus:border-blue-600/30'
                }`} 
              />
              {abuseError && (
                <div className="text-red-600 text-[10px] font-black uppercase tracking-tight flex items-center gap-3 bg-red-50 p-6 rounded-2xl border border-red-100 animate-in shake duration-500">
                  <AlertTriangle size={18} /> 
                  <div>
                    <span className="block mb-0.5">Automated Content Rejection</span>
                    <span className="text-red-400 font-bold">{abuseError}</span>
                  </div>
                </div>
              )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-end pt-8 border-t border-slate-100">
              <div className="space-y-6">
                <div 
                  className={`flex items-center gap-6 p-8 rounded-[2rem] border-2 cursor-pointer transition-all group ${
                    hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-2xl shadow-blue-500/30' : 'bg-slate-50 border-slate-100 hover:border-blue-400 hover:bg-white'
                  }`} 
                  onClick={() => setHasSigned(!hasSigned)}
                >
