                  className="w-full py-8 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-[11px] shadow-2xl shadow-slate-900/40 transition-all active:scale-[0.98] disabled:opacity-40 flex items-center justify-center gap-4"
                >
                  {isAnalyzing ? <><Loader2 className="animate-spin" /> Verifying Integrity...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Multi-Subject Block...</> : <><Send size={20} /> Finalize Submission</>}
                </button>
                <div className="flex items-center justify-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 py-3 rounded-xl border border-slate-100">
                  <Lock size={14} className="text-blue-500" /> End-to-End Encrypted Tunnel
                </div>
              </div>
            </div>
          </div>
        </form>
      </div>

      <div className="flex flex-col items-center gap-3 py-10 opacity-40 select-none grayscale group hover:grayscale-0 transition-all cursor-default">
         <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-200"><ShieldCheck size={32} className="text-blue-600" /></div>
         <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.6em]">SRK Institute IT Department Infrastructure</p>
         <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">Autonomous Blockchain Protocol v2.5.4</p>
      </div>
    </div>
  );
};

