  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'dataset'>('control');

  // Notification system
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // Inline Confirmation State
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // --- HANDLERS: SESSION & ACCESS ---
  const toggleSession = () => {
    setSettings(prev => ({ ...prev, isSessionActive: !prev.isSessionActive }));
    setToast({ 
      message: `Global Session ${!settings.isSessionActive ? 'Started' : 'Stopped'}`, 
      type: 'success' 
    });
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSettings(prev => ({
      ...prev,
      activeDeptSems: prev.activeDeptSems.includes(key)
        ? prev.activeDeptSems.filter(k => k !== key)
        : [...prev.activeDeptSems, key]
    }));
  };

  // --- HANDLERS: FACULTY CRUD ---
  const openFacultyModal = (fac?: Faculty) => {
    if (fac) {
      setEditingFaculty(fac);
      setFacultyForm({ ...fac });
    } else {
      setEditingFaculty(null);
      setFacultyForm({ name: '', department: 'CSE', subjects: [''] });
    }
    setIsFacultyModalOpen(true);
  };

  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
      setToast({ message: "Faculty record updated successfully", type: 'success' });
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
      setToast({ message: "New faculty pair registered", type: 'success' });
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    // Fixed: Standard filter logic applied to functional state update
    setFaculties(prev => prev.filter(f => f.id !== id));
    setConfirmDeleteId(null);
    setToast({ message: "Faculty record purged from registry", type: 'success' });
  };

  const handleSubjectChange = (idx: number, val: string) => {
    const newSubs = [...(facultyForm.subjects || [])];
    newSubs[idx] = val;
    setFacultyForm({ ...facultyForm, subjects: newSubs });
  };

  const addSubjectField = () => {
    setFacultyForm({ ...facultyForm, subjects: [...(facultyForm.subjects || []), ''] });
  };

  // --- HANDLERS: DATASET (QUESTIONS) ---
  const handleSaveQuestions = (type: 'theory' | 'lab') => {
    setToast({ message: `${type.toUpperCase()} attributes sealed successfully`, type: 'success' });
  };

  const removeQuestion = (type: 'theory' | 'lab', idx: number) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, labQuestions: newQ});
    }
  };

  const addQuestion = (type: 'theory' | 'lab') => {
    if (type === 'theory') {
      setSettings({...settings, theoryQuestions: [...settings.theoryQuestions, 'New Evaluation Metric']});
    } else {
      setSettings({...settings, labQuestions: [...settings.labQuestions, 'New Lab Metric']});
    }
  };

  const updateQuestionText = (type: 'theory' | 'lab', idx: number, val: string) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ[idx] = val;
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ[idx] = val;
      setSettings({...settings, labQuestions: newQ});
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20 relative">
      {/* Custom Toast Notification */}
      {toast && (
        <div className={`fixed top-6 right-6 z-[120] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 animate-in slide-in-from-top duration-300 ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl ${settings.isSessionActive ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
              <Power size={24} />
            </div>
            <button onClick={toggleSession} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase transition-all shadow-sm ${
              settings.isSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              {settings.isSessionActive ? 'Live' : 'Stopped'}
            </button>
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Session State</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{settings.isSessionActive ? 'Accepting Form' : 'Portal Closed'}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4">
            <UserCheck size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Faculty Count</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{faculties.length} Records</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4">
            <Activity size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Data Privacy</h3>
          <p className="text-xl font-black text-slate-900 mt-1">E2E Sealed</p>
        </div>

        <div className="bg-slate-900 p-6 rounded-2xl shadow-xl flex flex-col justify-between text-white">
          <div className="p-3 bg-white/10 rounded-xl w-fit mb-4 text-blue-400">
            <ShieldAlert size={24} />
          </div>
          <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Super Admin</h3>
          <div className="flex justify-between items-end">
             <p className="text-xl font-black mt-1">Full Access</p>
             <button onClick={() => { setFaculties(FACULTY_DATA); setToast({ message: 'Registry Reset to Defaults', type: 'success' }) }} className="p-1 hover:bg-white/10 rounded text-slate-500" title="Reset Data"><RefreshCcw size={14} /></button>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-slate-100 p-1.5 rounded-2xl w-fit border border-slate-200 shadow-inner">
        {[
          { id: 'control', label: 'Access Control', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'dataset', label: 'Attribute Set', icon: FileSpreadsheet }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveSubTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {/* Control Content */}
      {activeSubTab === 'control' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-left duration-500">
          <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h3 className="font-black text-slate-900 text-[11px] uppercase tracking-widest flex items-center gap-2">
                <ShieldAlert className="text-amber-500" size={18} /> Departmental Login Permissions
              </h3>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">SELECT DEPT-SEM TO ALLOW FEEDBACK</span>
            </div>
            <div className="p-8 grid grid-cols-1 sm:grid-cols-2 gap-6">
              {DEPARTMENTS.slice(0, 8).map(dept => (
                <div key={dept} className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                  <h4 className="font-black text-xs text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between items-center">
                    {dept} Dept
                    <span className="text-[10px] text-slate-400">Matrix</span>
                  </h4>
                  <div className="flex flex-wrap gap-2">
                    {SEMESTERS.map(sem => {
                      const key = `${dept}-${sem}`;
                      const isActive = settings.activeDeptSems.includes(key);
                      return (
                        <button
                          key={sem}
                          onClick={() => toggleDeptSemAccess(dept, sem)}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all border ${
                            isActive 
                              ? 'bg-blue-600 border-blue-600 text-white shadow-lg' 
                              : 'bg-white border-slate-200 text-slate-400 hover:border-blue-400'
                          }`}
                        >
                          {sem}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 rounded-3xl p-10 text-white shadow-2xl relative overflow-hidden flex flex-col">
            <div className="absolute top-0 right-0 p-8 text-white/5 pointer-events-none"><Power size={180} /></div>
            <h3 className="text-xl font-black mb-6 relative z-10 uppercase tracking-widest">Global Kill-Switch</h3>
            <div className="space-y-8 relative z-10 flex-1 flex flex-col justify-center">
              <div className="p-8 bg-white/5 border border-white/10 rounded-[2rem] text-center">
                <div className={`text-[11px] font-black uppercase tracking-[0.2em] mb-4 ${settings.isSessionActive ? 'text-emerald-400' : 'text-red-400'}`}>
                   Session Status: {settings.isSessionActive ? 'BROADCASTING' : 'OFFLINE'}
                </div>
                <button 
                  onClick={toggleSession}
                  className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all flex items-center justify-center gap-3 shadow-2xl ${
                    settings.isSessionActive ? 'bg-red-600 hover:bg-red-700 shadow-red-500/20' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-500/20'
                  }`}
                >
                  {settings.isSessionActive ? <ToggleRight size={24} /> : <ToggleLeft size={24} />}
                  {settings.isSessionActive ? 'Stop All Traffic' : 'Resume Session'}
                </button>
              </div>
              <p className="text-[10px] text-slate-400 leading-relaxed font-bold uppercase tracking-tight italic">
                * Toggling this affects the entire node instantly. Student portals will lock/unlock in real-time.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Faculty Content */}
      {activeSubTab === 'faculty' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-right duration-500">
          <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2">
                <Users className="text-blue-600" size={18} /> Faculty Mapping
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Link Professors to Subject Codes</p>
            </div>
            <button 
              onClick={() => openFacultyModal()}
              className="flex items-center gap-3 px-6 py-3 bg-blue-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20"
            >
              <Plus size={18} /> New Entry
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-slate-50 text-left border-b border-slate-100">
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Faculty Full Name</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Dept</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Subjects</th>
                  <th className="p-6 text-right text-[10px] font-black text-slate-400 uppercase tracking-widest">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {faculties.map(fac => (
                  <tr key={fac.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="p-6">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center font-black text-sm">{fac.name.charAt(0)}</div>
                        <span className="text-sm font-bold text-slate-800">{fac.name}</span>
                      </div>
                    </td>
                    <td className="p-6"><span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[10px] font-black text-slate-600">{fac.department}</span></td>
                    <td className="p-6">
                      <div className="flex gap-2">
                        {fac.subjects.map(s => <span key={s} className="px-2 py-0.5 bg-blue-600/10 text-blue-600 text-[9px] font-black rounded uppercase">{s}</span>)}
                      </div>
                    </td>
                    <td className="p-6 text-right relative">
                      {confirmDeleteId === fac.id ? (
                        <div className="flex justify-end items-center gap-2 animate-in slide-in-from-right duration-200">
                          <span className="text-[9px] font-black text-red-500 uppercase tracking-tighter">Are you sure?</span>
                          <button 
                            onClick={() => deleteFaculty(fac.id)}
                            className="p-2 bg-red-600 text-white rounded-lg text-[10px] font-black hover:bg-red-700 transition-colors uppercase"
                          >
                            Delete
                          </button>
                          <button 
                            onClick={() => setConfirmDeleteId(null)}
                            className="p-2 bg-slate-200 text-slate-600 rounded-lg text-[10px] font-black hover:bg-slate-300 transition-colors uppercase"
                          >
                            Cancel
                          </button>
                        </div>
                      ) : (
                        <div className="flex justify-end gap-2 md:opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => openFacultyModal(fac)} 
                            className="p-2.5 bg-slate-100 text-slate-500 hover:bg-blue-600 hover:text-white rounded-xl transition-all shadow-sm"
                            title="Edit"
                          >
                            <Edit3 size={16} />
                          </button>
                          <button 
                            onClick={() => setConfirmDeleteId(fac.id)} 
                            className="p-2.5 bg-slate-100 text-slate-500 hover:bg-red-600 hover:text-white rounded-xl transition-all shadow-sm"
                            title="Delete"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Dataset Content */}
      {activeSubTab === 'dataset' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 animate-in zoom-in duration-500">
          {[
            { type: 'theory', label: 'Theory Assessment', color: 'blue', questions: settings.theoryQuestions },
            { type: 'lab', label: 'Laboratory Assessment', color: 'emerald', questions: settings.labQuestions }
          ].map(set => (
            <div key={set.type} className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[650px]">
              <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                <div>
                  <h3 className={`font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2`}>
                    <Database className={`text-${set.color}-600`} size={20} /> {set.label}
                  </h3>
                  <p className="text-[9px] font-black text-slate-400 uppercase mt-1">Scale: 10 Core Attributes</p>
                </div>
                <button 
                  onClick={() => handleSaveQuestions(set.type as any)}
                  className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-black transition-all shadow-xl shadow-slate-900/10"
                >
                  <Save size={20} />
                </button>
              </div>
              <div className="p-8 space-y-4 overflow-y-auto flex-1 custom-scrollbar">
                {set.questions.map((q, idx) => (
                  <div key={idx} className="flex gap-4 items-center p-5 bg-slate-50 rounded-2xl border border-slate-100 group hover:border-blue-400 transition-all">
                    <span className="text-[10px] font-black text-slate-300 w-6">{(idx + 1).toString().padStart(2, '0')}</span>
                    <input 
                      value={q} 
                      onChange={(e) => updateQuestionText(set.type as any, idx, e.target.value)}
                      className="flex-1 bg-transparent text-[13px] font-semibold text-slate-700 outline-none focus:text-blue-600 transition-colors" 
                      placeholder="Enter attribute text..."
                    />
                    <button 
                      onClick={() => removeQuestion(set.type as any, idx)}
                      className="p-2 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </div>
              <div className="p-6 bg-slate-50 border-t border-slate-100">
                <button 
                  onClick={() => addQuestion(set.type as any)}
                  className="w-full py-4 border-2 border-dashed border-slate-300 rounded-2xl text-slate-400 hover:border-blue-500 hover:text-blue-500 transition-all flex items-center justify-center gap-3 font-black text-xs uppercase tracking-widest"
                >
                  <Plus size={20} /> Add Attribute Field
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Faculty Modal */}
      {isFacultyModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="font-black text-lg uppercase tracking-widest">{editingFaculty ? 'Modify Faculty Identity' : 'Secure Faculty Registration'}</h3>
                <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1 flex items-center gap-2">
                   <Activity size={12} /> Encrypted Registry Node: SRK-{Math.random().toString(36).substr(2, 6).toUpperCase()}
                </p>
              </div>
              <button onClick={() => setIsFacultyModalOpen(false)} className="p-3 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <form onSubmit={saveFaculty} className="p-10 space-y-8">
              <div className="space-y-3">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Full Legal Name</label>
                <input 
                  type="text" 
                  required
                  value={facultyForm.name} 
                  onChange={(e) => setFacultyForm({...facultyForm, name: e.target.value})}
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold text-slate-800 placeholder:text-slate-300"
                  placeholder="e.g. Dr. G. Padmaja Rao"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Primary Dept</label>
                  <select 
                    value={facultyForm.department}
                    onChange={(e) => setFacultyForm({...facultyForm, department: e.target.value as Department})}
                    className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold appearance-none cursor-pointer"
                  >
                    {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Node Type</label>
                  <div className="p-5 bg-blue-50 border-2 border-blue-100 rounded-2xl text-[10px] font-black text-blue-600 text-center uppercase">Autonomous Faculty</div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center px-2">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em]">Subject Load Mapping</label>
                  <button type="button" onClick={addSubjectField} className="text-blue-600 font-black text-[11px] uppercase tracking-wider hover:underline flex items-center gap-1.5"><Plus size={16} /> New Subject</button>
                </div>
                <div className="space-y-3 max-h-[180px] overflow-y-auto pr-2 custom-scrollbar">
                  {facultyForm.subjects?.map((sub, idx) => (
                    <div key={idx} className="flex gap-3">
                      <input 
                        type="text" 
                        required
                        value={sub} 
                        onChange={(e) => handleSubjectChange(idx, e.target.value)}
                        className="flex-1 p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-600 transition-all font-bold text-slate-700 uppercase"
                        placeholder="e.g. CD (CS302)"
                      />
                      {facultyForm.subjects!.length > 1 && (
                        <button 
                          type="button" 
                          onClick={() => setFacultyForm({...facultyForm, subjects: facultyForm.subjects?.filter((_, i) => i !== idx)})}
                          className="p-4 bg-red-50 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all"
                        >
                          <Trash2 size={20} />
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className="pt-8 flex gap-5">
                <button type="button" onClick={() => setIsFacultyModalOpen(false)} className="flex-1 py-5 bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-2xl font-black uppercase tracking-widest text-[11px] transition-all">Discard</button>
                <button type="submit" className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-2xl shadow-slate-900/20 transition-all flex items-center justify-center gap-2">
                   <CheckCircle2 size={18} /> Seal Record
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Footer Audit Message */}
      <div className="flex items-center justify-center gap-6 py-12">
         <div className="h-px bg-slate-200 flex-1"></div>
         <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] flex items-center gap-3">
           <ShieldAlert size={16} className="text-blue-600" /> Administrative Cryptographic Integrity Sealed
         </p>
         <div className="h-px bg-slate-200 flex-1"></div>
      </div>
    </div>
  );
};

