                  onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} 
                  placeholder="Please share constructive feedback regarding curriculum pace, lab manual clarity, or overall faculty engagement..." 
                  className={`w-full p-10 bg-slate-50 border-2 rounded-[2.5rem] focus:ring-8 outline-none transition-all min-h-[220px] text-slate-700 font-medium placeholder:text-slate-300 shadow-inner ${
                    abuseError ? 'border-red-500 focus:ring-red-500/10' : 'border-slate-100 focus:ring-blue-500/5 focus:border-blue-600/30'
                  }`} 
                />
                {abuseError && (
                  <div className="text-red-600 text-[10px] font-black uppercase tracking-tight flex items-center gap-3 bg-red-50 p-6 rounded-2xl border border-red-100 animate-in shake duration-500">
                    <AlertTriangle size={18} /> 
                    <div>
                      <span className="block mb-0.5">Automated Content Rejection</span>
                      <span className="text-red-400 font-bold">{abuseError}</span>
                    </div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-end pt-8 border-t border-slate-100">
                <div className="space-y-6">
                  <div 
                    className={`flex items-center gap-6 p-8 rounded-[2rem] border-2 cursor-pointer transition-all group ${
                      hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-2xl shadow-blue-500/30' : 'bg-slate-50 border-slate-100 hover:border-blue-400 hover:bg-white'
                    }`} 
                    onClick={() => setHasSigned(!hasSigned)}
                  >
                    <div className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all ${hasSigned ? 'bg-white border-white text-blue-600 rotate-12' : 'bg-white border-slate-300 group-hover:border-blue-400'}`}>
                      {hasSigned && <CheckCircle2 size={24} />}
                    </div>
                    <div className="flex-1">
                      <span className={`text-[11px] font-black uppercase tracking-[0.2em] block ${hasSigned ? 'text-white' : 'text-slate-900'}`}>Signature of Student / Date</span>
                      <div className={`flex items-center gap-2 mt-1.5 ${hasSigned ? 'text-blue-100' : 'text-slate-400'}`}>
                        <Calendar size={14} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{new Date().toLocaleDateString()}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-4 px-8 py-5 bg-amber-50 rounded-2xl border border-amber-100">
                    <ShieldAlert size={20} className="text-amber-600 shrink-0" />
                    <p className="text-[10px] text-amber-900 font-black uppercase tracking-tighter leading-normal">
                      Privacy Policy: Feedback is cryptographically isolated per department. Faculty identities are linked on-chain but student identities are discarded after nullifier generation.
                    </p>
                  </div>
                </div>

                <div className="flex flex-col gap-4">
                  <button 
                    type="submit"
                    disabled={isSubmitting || isAnalyzing} 
                    className="w-full py-8 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-[11px] shadow-2xl shadow-slate-900/40 transition-all active:scale-[0.98] disabled:opacity-40 flex items-center justify-center gap-4"
                  >
                    {isAnalyzing ? <><Loader2 className="animate-spin" /> Verifying Integrity...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Multi-Subject Block...</> : <><Send size={20} /> Finalize Submission</>}
                  </button>
                  <div className="flex items-center justify-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 py-3 rounded-xl border border-slate-100">
                    <Lock size={14} className="text-blue-500" /> End-to-End Encrypted Tunnel
                  </div>
                </div>
              </div>
            </div>
          </form>
        )}
      </div>

      <div className="flex flex-col items-center gap-3 py-10 opacity-40 select-none grayscale group hover:grayscale-0 transition-all cursor-default">
         <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-200"><ShieldCheck size={32} className="text-blue-600" /></div>
         <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.6em]">SRK Institute IT Department Infrastructure</p>
         <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">Autonomous Blockchain Protocol v2.5.4</p>
      </div>
    </div>
  );
};

export default FeedbackPortal;

import React, { useState } from 'react';
import { 
  FileText, 
  ShieldCheck, 
  BarChart3, 
  Settings, 
  Code,
  Lock
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import TechnicalRoadmap from './components/TechnicalRoadmap';
import AdminDashboard from './components/AdminDashboard';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import { FeedbackEntry, User, UserRole, Subject, Faculty } from './types';
import { SUBJECTS as INITIAL_SUBJECTS, FACULTY_DATA as INITIAL_FACULTIES } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'feedback' | 'analysis' | 'roadmap' | 'admin'>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);

  // Global State for Registry
  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) {
      setActiveTab('admin');
    } else {
      setActiveTab('feedback');
    }
  };

  const logout = () => {
    setUser(null);
  };

  if (!user) {
    return <Auth onAuthenticate={handleAuth} />;
  }

  const tabs = [
    { id: 'feedback', label: 'Submit Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3, roles: [UserRole.ADMIN] },
    { id: 'admin', label: 'Admin Power', icon: Lock, roles: [UserRole.ADMIN] },
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
        user={user}
        onLogout={logout}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} 
          user={user}
        />

        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-[#fdfdfd]">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={addFeedback} 
                onLogout={logout} 
                user={user} 
                subjects={subjects} 
              />
            )}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <AdminDashboard 
                subjects={subjects} 
                setSubjects={setSubjects}
                faculties={faculties}
                setFaculties={setFaculties}
              />
            )}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  ShieldAlert,
  Calendar,
  UserCheck,
  ExternalLink,
  SearchX,
  Database
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { THEORY_METRICS, LAB_METRICS } from '../constants';
import { FeedbackType, FeedbackEntry, User, Subject } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout, user, subjects }) => {
  const isSessionActive = true; 

  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);

  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity and professional conduct for a college faculty feedback form.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "Academic content moderator. Block insults or harassment."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  const filteredBaseSubjects = useMemo(() => {
    return subjects.filter(s => 
      s.department === user.department && s.semester === user.semester
    );
  }, [user.department, user.semester, subjects]);

  const currentSubjects = useMemo(() => {
    if (type === FeedbackType.THEORY) return filteredBaseSubjects;
    return filteredBaseSubjects.map(s => ({ ...s, name: s.id + ' Lab' }));
  }, [type, filteredBaseSubjects]);

  const metrics = type === FeedbackType.THEORY ? THEORY_METRICS : LAB_METRICS;

  const calculateTotal = (subjectId: string): number => {
    const scores = matrixScores[subjectId] || {};
    return (Object.values(scores) as number[]).reduce((a, b) => a + b, 0);
  };

  const calculateSatisfaction = (subjectId: string): number => {
    const total = calculateTotal(subjectId);
    const max = metrics.length * 5;
    if (max === 0) return 0;
    return (total / max) * 100;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionActive) return alert('Feedback session is currently closed.');
    if (currentSubjects.length === 0) return alert('No subjects mapped to your profile. Please contact Admin.');

    setAbuseError(null);
    let allFilled = true;
    currentSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please provide ratings for ALL attributes across ALL subjects shown in the grid.');
    if (!hasSigned) return alert('Digitally signing the acknowledgment is mandatory before submission.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Your suggestion contains prohibited or unprofessional language.");
      return;
    }

    setIsSubmitting(true);

    try {
      const payload = {
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        satisfaction: currentSubjects.map(s => ({ subject: s.id, percent: calculateSatisfaction(s.id) })),
        studentEmail: user.email,
        timestamp: Date.now()
      };

      const result = await sendGaslessFeedback(payload);
      setLastSubmission(result);

      const batchEntry: FeedbackEntry = {
        id: `batch-${Date.now()}`,
        type,
        facultyId: 'batch-multi',
        subjectId: 'batch-multi',
        department: user.department!,
        semester: user.semester!,
        data: matrixScores as any,
        timestamp: Date.now(),
        encryptedHash: result.ipfsHash
      };

      onSubmit(batchEntry);
      setIsSubmitting(false);
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 8000);
    } catch (error) {
      alert("Submission failed. Please check network connection.");
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto flex flex-col items-center animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 shadow-lg shadow-green-100 animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Recorded</h2>
        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 w-full mb-8 text-left space-y-3 font-mono">
           <div className="flex justify-between items-center text-[10px]">
             <span className="text-slate-400 uppercase font-black">IPFS CID</span>
             <a href={`https://gateway.pinata.cloud/ipfs/${lastSubmission?.ipfsHash}`} target="_blank" className="text-blue-600 hover:underline flex items-center gap-1">View JSON <ExternalLink size={10} /></a>
           </div>
           <p className="text-[10px] text-slate-700 break-all bg-white p-2 border border-slate-100 rounded-lg">{lastSubmission?.ipfsHash}</p>

           <div className="flex justify-between items-center text-[10px] pt-2">
             <span className="text-slate-400 uppercase font-black">Transaction Hash (Sim)</span>
             <span className="text-emerald-600 font-black">SEALED</span>
           </div>
           <p className="text-[10px] text-slate-500 break-all">{lastSubmission?.txHash}</p>
        </div>
        <p className="text-slate-500 mb-8 leading-relaxed font-medium">
          Digital seal applied to <span className="text-blue-600 font-bold">{user.department} {user.semester}</span> ledger.
          <br />
          <span className="text-blue-600 font-bold">Securely logging you out...</span>
        </p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
          <div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-700">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden print:shadow-none">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30">
          <div className="flex flex-col lg:flex-row justify-between items-center gap-8">
            <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
              <div className="flex items-center gap-4 mb-3">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg">SRK</div>
                <div>
                  <h1 className="text-xl font-black text-slate-900 leading-tight">SRK INSTITUTE OF TECHNOLOGY</h1>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Approved by AICTE • Affiliated to JNTUK • Accredited with NBA & NAAC 'A' grade</p>
                </div>
              </div>
              <div className="mt-2 text-[11px] font-black text-slate-600 uppercase tracking-[0.2em] border-l-4 border-blue-600 pl-4 py-1">
                Department of {user.department} - Multi-Subject Node
              </div>
            </div>

            <div className="flex flex-col items-end gap-3">
              <div className="bg-slate-900 text-white px-6 py-2 rounded-full text-[10px] font-black tracking-[0.2em] uppercase">
                Academic Year: 2024-25
              </div>
              <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
                <button 
                  type="button" 
                  onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} 
                  className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.THEORY ? 'bg-white text-blue-600 shadow-md scale-[1.02]' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <BookOpen size={16} /> CLASS
                </button>
                <button 
                  type="button" 
                  onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} 
                  className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.LAB ? 'bg-white text-blue-600 shadow-md scale-[1.02]' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <FlaskConical size={16} /> LABORATORY
                </button>
              </div>
            </div>
          </div>

          <div className="mt-10 p-6 bg-white border border-slate-200 rounded-[2rem] shadow-sm flex flex-wrap gap-y-4 gap-x-12 items-center">
            <div className="text-[11px] font-black text-slate-900 uppercase tracking-widest bg-slate-100 px-4 py-2 rounded-lg">5-Point Scale Assessment:</div>
            <div className="flex flex-wrap gap-8">
              {[
                { n: 5, l: 'Excellent', c: 'blue-600' },
                { n: 4, l: 'Very Good', c: 'blue-400' },
                { n: 3, l: 'Fair', c: 'slate-400' },
                { n: 2, l: 'Poor', c: 'amber-500' },
                { n: 1, l: 'Very Poor', c: 'red-600' }
              ].map(item => (
                <span key={item.n} className="flex items-center gap-2.5 text-[10px] font-bold text-slate-600 uppercase">
                  <div className={`w-3 h-3 rounded-full bg-${item.c}`}></div>
                  <span className="text-slate-900">{item.n}</span> {item.l}
                </span>
              ))}
            </div>
          </div>
        </div>

        {currentSubjects.length === 0 ? (
          <div className="p-20 flex flex-col items-center justify-center text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-[3rem] text-slate-300">
               <SearchX size={80} strokeWidth={1} />
             </div>
             <div>
               <h3 className="text-2xl font-black text-slate-900">Registry Undefined</h3>
               <p className="text-slate-500 max-w-md mx-auto mt-2 font-medium">
                 The subject node for <span className="text-blue-600 font-bold">{user.department} {user.semester}</span> hasn't been configured in the Administrative Power registry yet.
               </p>
             </div>
             <div className="flex gap-4">
                <div className="flex items-center gap-2 px-5 py-2.5 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest border border-blue-100">
                   <ShieldAlert size={14} /> Contact HOD
                </div>
                <div className="flex items-center gap-2 px-5 py-2.5 bg-slate-50 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-100">
                   <Database size={14} /> Check Mapping
                </div>
             </div>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-200">
                    <th className="p-8 text-left border-r border-slate-200 min-w-[450px] sticky left-0 bg-slate-50 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)]">
                      <div className="flex flex-col">
                        <span className="text-[12px] font-black text-slate-900 uppercase tracking-[0.3em] mb-1">{type === FeedbackType.THEORY ? 'CLASS' : 'LABORATORY'}</span>
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Attributes for Feedback</span>
                      </div>
                    </th>
                    {currentSubjects.map(s => (
                      <th key={s.id} className="p-8 text-center border-r border-slate-200 min-w-[140px] bg-slate-50">
                        <div className="flex flex-col items-center">
                          <span className="block text-sm font-black text-slate-900 mb-1">{s.id}</span>
                          <span className="block text-[8px] font-black text-slate-400 uppercase tracking-tighter opacity-80 whitespace-nowrap">Subject Node</span>
                        </div>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-blue-50/40 transition-colors group">
                      <td className="p-8 border-r border-slate-200 bg-white group-hover:bg-blue-50/50 sticky left-0 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)]">
                        <div className="flex gap-6 items-start">
                          <span className="text-xs font-black text-slate-300 w-6 shrink-0 mt-0.5 leading-none">{(mIdx + 1).toString().padStart(2, '0')}</span>
                          <span className="text-[13px] font-semibold text-slate-700 leading-normal">{metric}</span>
                        </div>
                      </td>
                      {currentSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center border-r border-slate-100">
                          <div className="relative group/select flex flex-col items-center gap-1.5">
                            <select 
                              value={matrixScores[s.id]?.[mIdx] || ''} 
                              onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))} 
                              className={`w-14 h-14 p-2 text-center font-black rounded-2xl border-2 appearance-none transition-all outline-none cursor-pointer text-base ${
                                matrixScores[s.id]?.[mIdx] 
                                  ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-500/30 scale-110' 
                                  : 'bg-slate-50 border-slate-100 text-slate-400 hover:border-blue-300 hover:bg-white'
                              }`}
                            >
                              <option value="">-</option>
                              {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                            </select>
                            <span className="text-[8px] font-black text-slate-300 uppercase tracking-tighter opacity-0 group-hover/select:opacity-100 transition-opacity">Marks</span>
                          </div>
                        </td>
                      ))}
                    </tr>
                  ))}

                  <tr className="bg-slate-900 text-white font-black uppercase tracking-widest text-[10px]">
                    <td className="p-8 border-r border-slate-800 sticky left-0 bg-slate-900 z-20">
                      <div className="flex flex-col">
                        <span className="text-[11px] mb-1">Total Satisfaction Level = (Total points / 50 x 100)</span>
                        <span className="text-slate-500 text-[8px] font-bold">Calculation based on 10 standardized attributes</span>
                      </div>
                    </td>
                    {currentSubjects.map(s => (
                      <td key={s.id} className="p-8 text-center border-r border-slate-800 bg-slate-900/90">
                        <div className="space-y-2">
                          <div className="text-[11px] text-blue-400 font-mono tracking-tighter">{calculateTotal(s.id)} <span className="text-white/40">/ 50</span></div>
                          <div className="text-sm font-black bg-white/10 py-1 rounded-lg ring-1 ring-white/20">{calculateSatisfaction(s.id).toFixed(0)}%</div>
                        </div>
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>

            <div className="p-10 space-y-12 bg-white">
              <div className="space-y-6">
                <div className="flex justify-between items-center">
                  <label className="text-xs font-black text-slate-900 uppercase tracking-[0.3em] flex items-center gap-3">
                    <div className="p-2 bg-blue-50 rounded-lg text-blue-600"><MessageSquare size={18} /></div>
                    Your suggestion for improvements:
                  </label>
                  {isAnalyzing && (
                    <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-2 animate-pulse bg-blue-50 px-4 py-2 rounded-full border border-blue-100 shadow-sm">
                      <ShieldAlert size={12} /> Ethics Validation Engine Active
                    </span>
                  )}
                </div>
                <textarea 
                  value={suggestions} 
                  onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} 
                  placeholder="Please share constructive feedback regarding curriculum pace, lab manual clarity, or overall faculty engagement..." 
                  className={`w-full p-10 bg-slate-50 border-2 rounded-[2.5rem] focus:ring-8 outline-none transition-all min-h-[220px] text-slate-700 font-medium placeholder:text-slate-300 shadow-inner ${
                    abuseError ? 'border-red-500 focus:ring-red-500/10' : 'border-slate-100 focus:ring-blue-500/5 focus:border-blue-600/30'
                  }`} 
                />
                {abuseError && (
                  <div className="text-red-600 text-[10px] font-black uppercase tracking-tight flex items-center gap-3 bg-red-50 p-6 rounded-2xl border border-red-100 animate-in shake duration-500">
                    <AlertTriangle size={18} /> 
                    <div>
                      <span className="block mb-0.5">Automated Content Rejection</span>
                      <span className="text-red-400 font-bold">{abuseError}</span>
                    </div>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-end pt-8 border-t border-slate-100">
                <div className="space-y-6">
                  <div 
                    className={`flex items-center gap-6 p-8 rounded-[2rem] border-2 cursor-pointer transition-all group ${
                      hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-2xl shadow-blue-500/30' : 'bg-slate-50 border-slate-100 hover:border-blue-400 hover:bg-white'
                    }`} 
                    onClick={() => setHasSigned(!hasSigned)}
                  >
                    <div className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all ${hasSigned ? 'bg-white border-white text-blue-600 rotate-12' : 'bg-white border-slate-300 group-hover:border-blue-400'}`}>
                      {hasSigned && <CheckCircle2 size={24} />}
                    </div>
                    <div className="flex-1">
                      <span className={`text-[11px] font-black uppercase tracking-[0.2em] block ${hasSigned ? 'text-white' : 'text-slate-900'}`}>Signature of Student / Date</span>
                      <div className={`flex items-center gap-2 mt-1.5 ${hasSigned ? 'text-blue-100' : 'text-slate-400'}`}>
                        <Calendar size={14} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{new Date().toLocaleDateString()}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-4 px-8 py-5 bg-amber-50 rounded-2xl border border-amber-100">
                    <ShieldAlert size={20} className="text-amber-600 shrink-0" />
                    <p className="text-[10px] text-amber-900 font-black uppercase tracking-tighter leading-normal">
                      Privacy Policy: Feedback is cryptographically isolated per department. Faculty identities are linked on-chain but student identities are discarded after nullifier generation.
                    </p>
                  </div>
                </div>

                <div className="flex flex-col gap-4">
                  <button 
                    type="submit"
                    disabled={isSubmitting || isAnalyzing} 
                    className="w-full py-8 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-[11px] shadow-2xl shadow-slate-900/40 transition-all active:scale-[0.98] disabled:opacity-40 flex items-center justify-center gap-4"
                  >
                    {isAnalyzing ? <><Loader2 className="animate-spin" /> Verifying Integrity...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Multi-Subject Block...</> : <><Send size={20} /> Finalize Submission</>}
                  </button>
                  <div className="flex items-center justify-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 py-3 rounded-xl border border-slate-100">
                    <Lock size={14} className="text-blue-500" /> End-to-End Encrypted Tunnel
                  </div>
                </div>
              </div>
            </div>
          </form>
        )}
      </div>

      <div className="flex flex-col items-center gap-3 py-10 opacity-40 select-none grayscale group hover:grayscale-0 transition-all cursor-default">
         <div className="p-3 bg-white rounded-2xl shadow-sm border border-slate-200"><ShieldCheck size={32} className="text-blue-600" /></div>
         <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.6em]">SRK Institute IT Department Infrastructure</p>
         <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">Autonomous Blockchain Protocol v2.5.4</p>
      </div>
    </div>
  );
};

export default FeedbackPortal;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Users, 
  Power, 
  Plus, 
  Trash2, 
  Edit3, 
  Database, 
  ShieldAlert,
  Save,
  FileSpreadsheet,
  ToggleLeft,
  ToggleRight,
  Activity,
  UserCheck,
  X,
  CheckCircle2,
  AlertCircle,
  RefreshCcw,
  BookOpen,
  CalendarDays,
  Hash
} from 'lucide-react';
import { Department, Faculty, AdminSettings, Semester, Subject } from '../types';
import { DEPARTMENTS, SEMESTERS, THEORY_METRICS, LAB_METRICS, FACULTY_DATA as DEFAULT_FACULTIES, SUBJECTS as DEFAULT_SUBJECTS } from '../constants';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ subjects, setSubjects, faculties, setFaculties }) => {
  // --- STATE ---
  const [settings, setSettings] = useState<AdminSettings>({
    isSessionActive: true,
    activeDeptSems: ['CSE-3.1', 'AIDS-3.1', 'IT-2.2'],
    theoryQuestions: THEORY_METRICS,
    labQuestions: LAB_METRICS
  });

  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'dataset'>('control');

  // Notification system
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // Modal State for Subjects
  const [isSubjectModalOpen, setIsSubjectModalOpen] = useState(false);
  const [subjectFilterDept, setSubjectFilterDept] = useState<Department>('CSE');
  const [subjectFilterSem, setSubjectFilterSem] = useState<Semester>('3.1');
  const [subjectForm, setSubjectForm] = useState<Partial<Subject>>({
    id: '',
    name: '',
    code: '',
    department: 'CSE',
    semester: '3.1'
  });

  // Inline Confirmation State
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // --- HANDLERS: SESSION & ACCESS ---
  const toggleSession = () => {
    setSettings(prev => ({ ...prev, isSessionActive: !prev.isSessionActive }));
    setToast({ 
      message: `Global Session ${!settings.isSessionActive ? 'Started' : 'Stopped'}`, 
      type: 'success' 
    });
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSettings(prev => ({
      ...prev,
      activeDeptSems: prev.activeDeptSems.includes(key)
        ? prev.activeDeptSems.filter(k => k !== key)
        : [...prev.activeDeptSems, key]
    }));
  };

  // --- HANDLERS: FACULTY CRUD ---
  const openFacultyModal = (fac?: Faculty) => {
    if (fac) {
      setEditingFaculty(fac);
      setFacultyForm({ ...fac });
    } else {
      setEditingFaculty(null);
      setFacultyForm({ name: '', department: 'CSE', subjects: [''] });
    }
    setIsFacultyModalOpen(true);
  };

  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
      setToast({ message: "Faculty record updated successfully", type: 'success' });
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
      setToast({ message: "New faculty pair registered", type: 'success' });
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    setFaculties(prev => prev.filter(f => f.id !== id));
    setConfirmDeleteId(null);
    setToast({ message: "Faculty record purged from registry", type: 'success' });
  };

  // --- HANDLERS: SUBJECT CRUD ---
  const filteredSubjects = useMemo(() => {
    return subjects.filter(s => s.department === subjectFilterDept && s.semester === subjectFilterSem);
  }, [subjects, subjectFilterDept, subjectFilterSem]);

  const saveSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!subjectForm.id || !subjectForm.name) return;

    const newSub: Subject = {
      id: subjectForm.id!,
      name: subjectForm.name!,
      code: subjectForm.code || subjectForm.id!,
      department: subjectFilterDept,
      semester: subjectFilterSem
    };

    setSubjects(prev => [...prev.filter(s => !(s.id === newSub.id && s.department === newSub.department && s.semester === newSub.semester)), newSub]);
    setToast({ message: "Subject node appended to registry", type: 'success' });
    setIsSubjectModalOpen(false);
    setSubjectForm({ id: '', name: '', code: '' });
  };

  const deleteSubject = (id: string, dept: Department, sem: Semester) => {
    setSubjects(prev => prev.filter(s => !(s.id === id && s.department === dept && s.semester === sem)));
    setToast({ message: "Subject entry deleted", type: 'success' });
  };

  const handleSubjectChange = (idx: number, val: string) => {
    const newSubs = [...(facultyForm.subjects || [])];
    newSubs[idx] = val;
    setFacultyForm({ ...facultyForm, subjects: newSubs });
  };

  const addSubjectField = () => {
    setFacultyForm({ ...facultyForm, subjects: [...(facultyForm.subjects || []), ''] });
  };

  // --- HANDLERS: DATASET (QUESTIONS) ---
  const handleSaveQuestions = (type: 'theory' | 'lab') => {
    setToast({ message: `${type.toUpperCase()} attributes sealed successfully`, type: 'success' });
  };

  const removeQuestion = (type: 'theory' | 'lab', idx: number) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, labQuestions: newQ});
    }
  };

  const addQuestion = (type: 'theory' | 'lab') => {
    if (type === 'theory') {
      setSettings({...settings, theoryQuestions: [...settings.theoryQuestions, 'New Evaluation Metric']});
    } else {
      setSettings({...settings, labQuestions: [...settings.labQuestions, 'New Lab Metric']});
    }
  };

  const updateQuestionText = (type: 'theory' | 'lab', idx: number, val: string) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ[idx] = val;
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ[idx] = val;
      setSettings({...settings, labQuestions: newQ});
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20 relative">
      {toast && (
        <div className={`fixed top-6 right-6 z-[120] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 animate-in slide-in-from-top duration-300 ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl ${settings.isSessionActive ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
              <Power size={24} />
            </div>
            <button onClick={toggleSession} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase transition-all shadow-sm ${
              settings.isSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              {settings.isSessionActive ? 'Live' : 'Stopped'}
            </button>
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Session State</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{settings.isSessionActive ? 'Accepting Form' : 'Portal Closed'}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4">
            <UserCheck size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Faculty Count</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{faculties.length} Records</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4">
            <BookOpen size={24} />
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Subject Registry</h3>
