                <h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2">
                  <BookOpen className="text-blue-600" size={18} /> Subject Node Management
                </h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Configure subjects for specific Dept/Sem slots</p>
              </div>
              <button 
                onClick={() => setIsSubjectModalOpen(true)}
                className="flex items-center gap-3 px-6 py-3 bg-blue-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20"
              >
                <Plus size={18} /> Add Subject Node
              </button>
            </div>

            <div className="flex flex-wrap gap-4 items-center bg-white p-6 rounded-2xl border border-slate-100">
              <div className="flex items-center gap-3">
                <Building2 size={16} className="text-slate-400" />
                <select 
                  value={subjectFilterDept}
                  onChange={(e) => setSubjectFilterDept(e.target.value as Department)}
                  className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-[11px] font-black uppercase outline-none focus:border-blue-600"
