            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-slate-50 text-left border-b border-slate-100">
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Node ID (Alias)</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Subject Name</th>
                  <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Internal Code</th>
                  <th className="p-6 text-right text-[10px] font-black text-slate-400 uppercase tracking-widest">Purge</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredSubjects.length > 0 ? filteredSubjects.map(sub => (
                  <tr key={`${sub.id}-${sub.department}-${sub.semester}`} className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-6"><span className="font-black text-slate-900 text-xs">{sub.id}</span></td>
                    <td className="p-6"><span className="font-semibold text-slate-700 text-sm">{sub.name}</span></td>
                    <td className="p-6"><span className="text-[10px] font-black text-slate-400 uppercase">{sub.code}</span></td>
                    <td className="p-6 text-right">
                      <button 
