      {/* Subject Modal */}
      {isSubjectModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-8 bg-blue-600 text-white flex justify-between items-center">
              <h3 className="font-black text-sm uppercase tracking-[0.2em]">Map Subject to {subjectFilterDept} {subjectFilterSem}</h3>
              <button onClick={() => setIsSubjectModalOpen(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={20} /></button>
            </div>
            <form onSubmit={saveSubject} className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Subject Alias ID</label>
                <div className="relative">
                  <Activity size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" />
                  <input required value={subjectForm.id} onChange={(e) => setSubjectForm({...subjectForm, id: e.target.value.toUpperCase()})} placeholder="e.g. ML, CD, AI" className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black focus:border-blue-600 outline-none" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Academic Title</label>
                <div className="relative">
                  <BookOpen size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" />
                  <input required value={subjectForm.name} onChange={(e) => setSubjectForm({...subjectForm, name: e.target.value})} placeholder="e.g. Machine Learning" className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold focus:border-blue-600 outline-none" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Internal Subject Code</label>
                <div className="relative">
                  <Hash size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" />
                  <input value={subjectForm.code} onChange={(e) => setSubjectForm({...subjectForm, code: e.target.value.toUpperCase()})} placeholder="e.g. CS301" className="w-full pl-12 pr-4 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black focus:border-blue-600 outline-none" />
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-black transition-all">
                Append Node to Ledger
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Faculty Modal */}
      {isFacultyModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 bg-slate-900 text-white flex justify-between items-center">
              <div>
                <h3 className="font-black text-lg uppercase tracking-widest">{editingFaculty ? 'Modify Faculty Identity' : 'Secure Faculty Registration'}</h3>
                <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1 flex items-center gap-2">
                   <Activity size={12} /> Encrypted Registry Node: SRK-{Math.random().toString(36).substr(2, 6).toUpperCase()}
                </p>
              </div>
              <button onClick={() => setIsFacultyModalOpen(false)} className="p-3 hover:bg-white/10 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <form onSubmit={saveFaculty} className="p-10 space-y-8">
              <div className="space-y-3">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Full Legal Name</label>
                <input 
                  type="text" 
                  required
                  value={facultyForm.name} 
                  onChange={(e) => setFacultyForm({...facultyForm, name: e.target.value})}
                  className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold text-slate-800 placeholder:text-slate-300"
                  placeholder="e.g. Dr. G. Padmaja Rao"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-3">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Primary Dept</label>
                  <select 
                    value={facultyForm.department}
                    onChange={(e) => setFacultyForm({...facultyForm, department: e.target.value as Department})}
                    className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold appearance-none cursor-pointer"
                  >
                    {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] ml-2">Node Type</label>
                  <div className="p-5 bg-blue-50 border-2 border-blue-100 rounded-2xl text-[10px] font-black text-blue-600 text-center uppercase">Autonomous Faculty</div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center px-2">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em]">Subject Load Mapping</label>
                  <button type="button" onClick={addSubjectField} className="text-blue-600 font-black text-[11px] uppercase tracking-wider hover:underline flex items-center gap-1.5"><Plus size={16} /> New Subject</button>
                </div>
                <div className="space-y-3 max-h-[180px] overflow-y-auto pr-2 custom-scrollbar">
                  {facultyForm.subjects?.map((sub, idx) => (
                    <div key={idx} className="flex gap-3">
                      <input 
                        type="text" 
                        required
                        value={sub} 
                        onChange={(e) => handleSubjectChange(idx, e.target.value)}
                        className="flex-1 p-4 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-600 transition-all font-bold text-slate-700 uppercase"
                        placeholder="e.g. CD (CS302)"
                      />
                      {facultyForm.subjects!.length > 1 && (
                        <button 
                          type="button" 
                          onClick={() => setFacultyForm({...facultyForm, subjects: facultyForm.subjects?.filter((_, i) => i !== idx)})}
                          className="p-4 bg-red-50 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all"
                        >
                          <Trash2 size={20} />
                        </button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className="pt-8 flex gap-5">
                <button type="button" onClick={() => setIsFacultyModalOpen(false)} className="flex-1 py-5 bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-2xl font-black uppercase tracking-widest text-[11px] transition-all">Discard</button>
                <button type="submit" className="flex-1 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-2xl shadow-slate-900/20 transition-all flex items-center justify-center gap-2">
                   <CheckCircle2 size={18} /> Seal Record
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Footer Audit Message */}
      <div className="flex items-center justify-center gap-6 py-12">
         <div className="h-px bg-slate-200 flex-1"></div>
         <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] flex items-center gap-3">
           <ShieldAlert size={16} className="text-blue-600" /> Administrative Cryptographic Integrity Sealed
         </p>
         <div className="h-px bg-slate-200 flex-1"></div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Users, 
  Power, 
  Plus, 
  Trash2, 
  Edit3, 
  Database, 
  ShieldAlert,
  Save,
  FileSpreadsheet,
  ToggleLeft,
  ToggleRight,
  Activity,
  UserCheck,
  X,
  CheckCircle2,
  AlertCircle,
  RefreshCcw,
  BookOpen,
  CalendarDays,
  Hash,
  // Added missing Building2 icon import
  Building2
} from 'lucide-react';
import { Department, Faculty, AdminSettings, Semester, Subject } from '../types';
import { DEPARTMENTS, SEMESTERS, THEORY_METRICS, LAB_METRICS, FACULTY_DATA as DEFAULT_FACULTIES, SUBJECTS as DEFAULT_SUBJECTS } from '../constants';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ subjects, setSubjects, faculties, setFaculties }) => {
  // --- STATE ---
  const [settings, setSettings] = useState<AdminSettings>({
    isSessionActive: true,
    activeDeptSems: ['CSE-3.1', 'AIDS-3.1', 'IT-2.2'],
    theoryQuestions: THEORY_METRICS,
    labQuestions: LAB_METRICS
  });

  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'dataset'>('control');

  // Notification system
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // Modal State for Subjects
  const [isSubjectModalOpen, setIsSubjectModalOpen] = useState(false);
  const [subjectFilterDept, setSubjectFilterDept] = useState<Department>('CSE');
  const [subjectFilterSem, setSubjectFilterSem] = useState<Semester>('3.1');
  const [subjectForm, setSubjectForm] = useState<Partial<Subject>>({
    id: '',
    name: '',
    code: '',
    department: 'CSE',
    semester: '3.1'
  });

  // Inline Confirmation State
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // --- HANDLERS: SESSION & ACCESS ---
  const toggleSession = () => {
    setSettings(prev => ({ ...prev, isSessionActive: !prev.isSessionActive }));
    setToast({ 
      message: `Global Session ${!settings.isSessionActive ? 'Started' : 'Stopped'}`, 
      type: 'success' 
    });
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSettings(prev => ({
      ...prev,
      activeDeptSems: prev.activeDeptSems.includes(key)
        ? prev.activeDeptSems.filter(k => k !== key)
        : [...prev.activeDeptSems, key]
    }));
  };

  // --- HANDLERS: FACULTY CRUD ---
  const openFacultyModal = (fac?: Faculty) => {
    if (fac) {
      setEditingFaculty(fac);
      setFacultyForm({ ...fac });
    } else {
      setEditingFaculty(null);
      setFacultyForm({ name: '', department: 'CSE', subjects: [''] });
    }
    setIsFacultyModalOpen(true);
  };

  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
      setToast({ message: "Faculty record updated successfully", type: 'success' });
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
      setToast({ message: "New faculty pair registered", type: 'success' });
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    setFaculties(prev => prev.filter(f => f.id !== id));
    setConfirmDeleteId(null);
    setToast({ message: "Faculty record purged from registry", type: 'success' });
  };

  // --- HANDLERS: SUBJECT CRUD ---
  const filteredSubjects = useMemo(() => {
    return subjects.filter(s => s.department === subjectFilterDept && s.semester === subjectFilterSem);
  }, [subjects, subjectFilterDept, subjectFilterSem]);

  const saveSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!subjectForm.id || !subjectForm.name) return;

    const newSub: Subject = {
      id: subjectForm.id!,
      name: subjectForm.name!,
      code: subjectForm.code || subjectForm.id!,
      department: subjectFilterDept,
      semester: subjectFilterSem
    };

    setSubjects(prev => [...prev.filter(s => !(s.id === newSub.id && s.department === newSub.department && s.semester === newSub.semester)), newSub]);
    setToast({ message: "Subject node appended to registry", type: 'success' });
    setIsSubjectModalOpen(false);
    setSubjectForm({ id: '', name: '', code: '' });
  };

  const deleteSubject = (id: string, dept: Department, sem: Semester) => {
    setSubjects(prev => prev.filter(s => !(s.id === id && s.department === dept && s.semester === sem)));
    setToast({ message: "Subject entry deleted", type: 'success' });
  };

  const handleSubjectChange = (idx: number, val: string) => {
    const newSubs = [...(facultyForm.subjects || [])];
    newSubs[idx] = val;
    setFacultyForm({ ...facultyForm, subjects: newSubs });
  };

  const addSubjectField = () => {
    setFacultyForm({ ...facultyForm, subjects: [...(facultyForm.subjects || []), ''] });
  };

  // --- HANDLERS: DATASET (QUESTIONS) ---
  const handleSaveQuestions = (type: 'theory' | 'lab') => {
    setToast({ message: `${type.toUpperCase()} attributes sealed successfully`, type: 'success' });
  };

  const removeQuestion = (type: 'theory' | 'lab', idx: number) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ.splice(idx, 1);
      setSettings({...settings, labQuestions: newQ});
    }
  };

  const addQuestion = (type: 'theory' | 'lab') => {
    if (type === 'theory') {
      setSettings({...settings, theoryQuestions: [...settings.theoryQuestions, 'New Evaluation Metric']});
    } else {
      setSettings({...settings, labQuestions: [...settings.labQuestions, 'New Lab Metric']});
    }
  };

  const updateQuestionText = (type: 'theory' | 'lab', idx: number, val: string) => {
    if (type === 'theory') {
      const newQ = [...settings.theoryQuestions];
      newQ[idx] = val;
      setSettings({...settings, theoryQuestions: newQ});
    } else {
      const newQ = [...settings.labQuestions];
      newQ[idx] = val;
      setSettings({...settings, labQuestions: newQ});
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20 relative">
      {toast && (
        <div className={`fixed top-6 right-6 z-[120] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 animate-in slide-in-from-top duration-300 ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl ${settings.isSessionActive ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
              <Power size={24} />
            </div>
            <button onClick={toggleSession} className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase transition-all shadow-sm ${
              settings.isSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              {settings.isSessionActive ? 'Live' : 'Stopped'}
            </button>
          </div>
          <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Session State</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{settings.isSessionActive ? 'Accepting Form' : 'Portal Closed'}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4">
            <UserCheck size={24} />
          </div>
