const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ onSubmit, onLogout, user, subjects, sessionRegistry }) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  // Dynamic "Interlink" States
  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  // --- INTERLINK LOGIC: Dynamic Fetching ---
  const syncStudentView = async () => {
    // 1. Determine if HOD has enabled the session for this node
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = sessionRegistry[sessionKey] || false;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      // 2. Fetch subjects directly from the global registry (simulating a contract call)
      const filtered = subjects.filter(s => 
        s.department === user.department && s.semester === user.semester
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  };

  // --- INTERLINK LOGIC: Real-time Listener Simulation ---
  useEffect(() => {
    syncStudentView();
    // In a real Web3 environment, we would use contract.on("SessionToggled", ...) here
    // In React, dependency on global state achieves the same "instant update" behavior
  }, [user.department, user.semester, subjects, sessionRegistry]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
