} from 'lucide-react';
import { Department, Faculty, AdminSettings, Semester, Subject, FeedbackType } from '../types';
import { DEPARTMENTS, SEMESTERS, THEORY_METRICS, LAB_METRICS, FACULTY_DATA as DEFAULT_FACULTIES, SUBJECTS as DEFAULT_SUBJECTS } from '../constants';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ subjects, setSubjects, faculties, setFaculties, sessionRegistry, setSessionRegistry }) => {
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'dataset'>('control');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // Modal State for Subjects
  const [isSubjectModalOpen, setIsSubjectModalOpen] = useState(false);
  const [subjectFilterDept, setSubjectFilterDept] = useState<Department>('CSE');
  const [subjectFilterSem, setSubjectFilterSem] = useState<Semester>('3.1');
  const [subjectForm, setSubjectForm] = useState<Partial<Subject>>({ 
    id: '', 
    name: '', 
    code: '', 
    type: FeedbackType.THEORY 
  });

  // --- HANDLERS: SESSION CONTROL ---
  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSessionRegistry(prev => ({
      ...prev,
      [key]: !prev[key]
    }));
    setToast({ 
      message: `${dept} ${sem} Session ${!sessionRegistry[key] ? 'Opened' : 'Closed'}`, 
      type: 'success' 
    });
  };

  const toggleGlobalSession = (status: boolean) => {
    const newRegistry: Record<string, boolean> = {};
    DEPARTMENTS.forEach(d => SEMESTERS.forEach(s => {
      newRegistry[`${d}-${s}`] = status;
    }));
    setSessionRegistry(newRegistry);
    setToast({ message: `Global Sessions ${status ? 'Activated' : 'Suspended'}`, type: 'success' });
  };

  // --- HANDLERS: FACULTY CRUD ---
  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
      setToast({ message: "Faculty updated", type: 'success' });
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
      setToast({ message: "New faculty added", type: 'success' });
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    setFaculties(prev => prev.filter(f => f.id !== id));
    setToast({ message: "Faculty record purged", type: 'success' });
  };

  // --- HANDLERS: SUBJECT CRUD ---
  const filteredSubjects = useMemo(() => {
    return subjects.filter(s => s.department === subjectFilterDept && s.semester === subjectFilterSem);
  }, [subjects, subjectFilterDept, subjectFilterSem]);

  const saveSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!subjectForm.id || !subjectForm.name) return;

    const newSub: Subject = {
      id: subjectForm.id!,
      name: subjectForm.name!,
      code: subjectForm.code || subjectForm.id!,
      department: subjectFilterDept,
      semester: subjectFilterSem,
      type: subjectForm.type || FeedbackType.THEORY
    };

    setSubjects(prev => [...prev.filter(s => !(s.id === newSub.id && s.department === newSub.department && s.semester === newSub.semester && s.type === newSub.type)), newSub]);
    setToast({ message: "Subject node appended", type: 'success' });
    setIsSubjectModalOpen(false);
    setSubjectForm({ id: '', name: '', code: '', type: FeedbackType.THEORY });
  };

  const deleteSubject = (id: string, dept: Department, sem: Semester, type: FeedbackType) => {
    setSubjects(prev => prev.filter(s => !(s.id === id && s.department === dept && s.semester === sem && s.type === type)));
    setToast({ message: "Subject entry deleted", type: 'success' });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20 relative">
      {toast && (
        <div className={`fixed top-6 right-6 z-[120] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 animate-in slide-in-from-top duration-300 ${toast.type === 'success' ? 'border-emerald-500 text-emerald-600 bg-white' : 'border-red-500 text-red-600 bg-white'}`}>
          {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4"><Users size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Faculty Records</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{faculties.length} Profiles</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4"><BookOpen size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Subject Nodes</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{subjects.length} Mapped</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl w-fit mb-4"><ShieldAlert size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Active Sessions</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{Object.values(sessionRegistry).filter(v => v).length} Nodes</p>
        </div>
        <div className="bg-slate-900 p-6 rounded-2xl shadow-xl text-white">
          <div className="p-3 bg-white/10 rounded-xl w-fit mb-4 text-blue-400"><Database size={24} /></div>
          <h3 className="text-slate-400 text-xs font-bold uppercase">Ledger Integrity</h3>
          <div className="flex justify-between items-end"><p className="text-xl font-black mt-1">Immutable</p><button onClick={() => { setFaculties(DEFAULT_FACULTIES); setSubjects(DEFAULT_SUBJECTS); }} className="p-1 hover:bg-white/10 rounded"><RefreshCcw size={14} /></button></div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="flex bg-slate-100 p-1.5 rounded-2xl w-fit border border-slate-200 shadow-inner">
        {[
          { id: 'control', label: 'Access Control', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'subjects', label: 'Subject Registry', icon: BookOpen },
          { id: 'dataset', label: 'Attribute Set', icon: FileSpreadsheet }
        ].map(tab => (
          <button key={tab.id} onClick={() => setActiveSubTab(tab.id as any)} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeSubTab === tab.id ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-slate-700'}`}><tab.icon size={16} /> {tab.label}</button>
        ))}
      </div>

      {/* Access Control View */}
      {activeSubTab === 'control' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-left duration-500">
          <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h3 className="font-black text-slate-900 text-[11px] uppercase tracking-widest flex items-center gap-2"><ShieldAlert className="text-amber-500" size={18} /> Login Permissions By Slice</h3>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">SELECT DEPT-SEM TO ALLOW FEEDBACK</span>
            </div>
            <div className="p-8 grid grid-cols-1 sm:grid-cols-2 gap-6">
              {DEPARTMENTS.map(dept => (
                <div key={dept} className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                  <h4 className="font-black text-xs text-slate-800 mb-4 border-b border-slate-200 pb-2 flex justify-between items-center">{dept} Dept <span className="text-[10px] text-slate-400">Node</span></h4>
                  <div className="flex flex-wrap gap-2">
                    {SEMESTERS.map(sem => {
                      const isActive = sessionRegistry[`${dept}-${sem}`];
                      return (
                        <button key={sem} onClick={() => toggleDeptSemAccess(dept, sem)} className={`px-3 py-1.5 rounded-lg text-[10px] font-black border transition-all ${isActive ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:border-blue-400'}`}>{sem}</button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="bg-slate-900 rounded-3xl p-10 text-white shadow-2xl flex flex-col justify-center text-center">
            <h3 className="text-xl font-black mb-10 uppercase tracking-widest">Global Master Key</h3>
            <div className="space-y-4">
              <button onClick={() => toggleGlobalSession(true)} className="w-full py-5 bg-emerald-600 hover:bg-emerald-700 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-2xl shadow-emerald-500/20"><ToggleRight size={24} /> Enable All Slots</button>
              <button onClick={() => toggleGlobalSession(false)} className="w-full py-5 bg-red-600 hover:bg-red-700 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-2xl shadow-red-500/20"><ToggleLeft size={24} /> Stop All Traffic</button>
            </div>
          </div>
        </div>
      )}

      {/* Subject Registry View */}
      {activeSubTab === 'subjects' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-right duration-500">
          <div className="p-8 border-b border-slate-100 bg-slate-50/50 space-y-6">
            <div className="flex justify-between items-center">
              <div><h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2"><BookOpen className="text-blue-600" size={18} /> Subject Node Management</h3><p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Configure distinct Theory and Lab nodes for Dept/Sem slots.</p></div>
              <button onClick={() => setIsSubjectModalOpen(true)} className="flex items-center gap-3 px-6 py-3 bg-blue-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg"><Plus size={18} /> Add Subject Node</button>
            </div>
            <div className="flex flex-wrap gap-4 items-center bg-white p-6 rounded-2xl border border-slate-100">
              <div className="flex items-center gap-3"><Building2 size={16} className="text-slate-400" /><select value={subjectFilterDept} onChange={(e) => setSubjectFilterDept(e.target.value as Department)} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-[11px] font-black uppercase outline-none focus:border-blue-600">{DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}</select></div>
              <div className="flex items-center gap-3"><CalendarDays size={16} className="text-slate-400" /><select value={subjectFilterSem} onChange={(e) => setSubjectFilterSem(e.target.value as Semester)} className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-[11px] font-black uppercase outline-none focus:border-blue-600">{SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}</select></div>
              <span className="text-[10px] font-black text-blue-600 uppercase bg-blue-50 px-3 py-1 rounded-full">{filteredSubjects.length} Active Nodes</span>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead><tr className="bg-slate-50 text-left border-b border-slate-100"><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Node ID</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Type</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Subject Title</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase text-right">Action</th></tr></thead>
              <tbody className="divide-y divide-slate-100">
                {filteredSubjects.length > 0 ? filteredSubjects.map(sub => (
                  <tr key={`${sub.id}-${sub.department}-${sub.semester}-${sub.type}`} className="hover:bg-slate-50 transition-colors">
                    <td className="p-6 font-black text-xs">{sub.id}</td>
                    <td className="p-6">
                      <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${sub.type === FeedbackType.THEORY ? 'bg-blue-50 text-blue-600' : 'bg-emerald-50 text-emerald-600'}`}>
                        {sub.type}
                      </span>
                    </td>
                    <td className="p-6 font-semibold text-sm">{sub.name}</td>
                    <td className="p-6 text-right"><button onClick={() => deleteSubject(sub.id, sub.department, sub.semester, sub.type)} className="p-2 text-slate-300 hover:text-red-500"><Trash2 size={16} /></button></td>
                  </tr>
                )) : <tr><td colSpan={4} className="p-12 text-center text-slate-300 italic uppercase text-[10px] font-black tracking-widest">No nodes defined for this slice.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Faculty Registry View */}
      {activeSubTab === 'faculty' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-right duration-500">
          <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div><h3 className="font-black text-slate-900 text-sm uppercase tracking-widest flex items-center gap-2"><Users className="text-blue-600" size={18} /> Faculty Identity Pool</h3><p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Register faculty and map them to specific Theory/Lab subject nodes.</p></div>
            <button onClick={() => { setEditingFaculty(null); setFacultyForm({ name: '', department: 'CSE', subjects: [''] }); setIsFacultyModalOpen(true); }} className="px-6 py-3 bg-blue-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-lg"><Plus size={18} /> New Registration</button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead><tr className="bg-slate-50 text-left border-b border-slate-100"><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Full Name</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Dept</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Subject Load Mapping</th><th className="p-6 text-right text-[10px] font-black text-slate-400 uppercase text-right">Actions</th></tr></thead>
              <tbody className="divide-y divide-slate-100">
                {faculties.map(fac => (
                  <tr key={fac.id} className="hover:bg-slate-50/50 group"><td className="p-6 font-bold text-slate-800">{fac.name}</td><td className="p-6"><span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[10px] font-black">{fac.department}</span></td><td className="p-6"><div className="flex gap-2 flex-wrap">{fac.subjects.map(s => <span key={s} className="px-2 py-0.5 bg-blue-50 text-blue-600 text-[9px] font-black rounded uppercase">{s}</span>)}</div></td><td className="p-6 text-right flex justify-end gap-2"><button onClick={() => { setEditingFaculty(fac); setFacultyForm(fac); setIsFacultyModalOpen(true); }} className="p-2.5 bg-slate-100 text-slate-500 hover:bg-blue-600 hover:text-white rounded-xl transition-all"><Edit3 size={16} /></button><button onClick={() => deleteFaculty(fac.id)} className="p-2.5 bg-slate-100 text-slate-500 hover:bg-red-600 hover:text-white rounded-xl transition-all"><Trash2 size={16} /></button></td></tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Subject Modal */}
      {isSubjectModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-8 bg-blue-600 text-white flex justify-between items-center"><h3 className="font-black text-sm uppercase tracking-widest">Map Node to {subjectFilterDept} {subjectFilterSem}</h3><button onClick={() => setIsSubjectModalOpen(false)}><X size={20} /></button></div>
            <form onSubmit={saveSubject} className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase">Subject Type</label>
                <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-100">
                  <button type="button" onClick={() => setSubjectForm({...subjectForm, type: FeedbackType.THEORY})} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${subjectForm.type === FeedbackType.THEORY ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400'}`}>Theory</button>
                  <button type="button" onClick={() => setSubjectForm({...subjectForm, type: FeedbackType.LAB})} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${subjectForm.type === FeedbackType.LAB ? 'bg-white shadow-sm text-emerald-600' : 'text-slate-400'}`}>Laboratory</button>
                </div>
              </div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase">Subject Alias ID</label><input required value={subjectForm.id} onChange={(e) => setSubjectForm({...subjectForm, id: e.target.value.toUpperCase()})} placeholder="e.g. ML, CD, OS" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-blue-600" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase">Academic Title</label><input required value={subjectForm.name} onChange={(e) => setSubjectForm({...subjectForm, name: e.target.value})} placeholder="e.g. Machine Learning" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase">Curriculum Code</label><input value={subjectForm.code} onChange={(e) => setSubjectForm({...subjectForm, code: e.target.value.toUpperCase()})} placeholder="e.g. CS301" className="w-full p-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-black outline-none focus:border-blue-600" /></div>
              <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-black transition-all">Append Subject Node</button>
            </form>
          </div>
        </div>
      )}

      {/* Faculty Modal */}
      {isFacultyModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-10 bg-slate-900 text-white flex justify-between items-center"><h3 className="font-black text-lg uppercase">{editingFaculty ? 'Modify Faculty' : 'Register Faculty'}</h3><button onClick={() => setIsFacultyModalOpen(false)}><X size={24} /></button></div>
            <form onSubmit={saveFaculty} className="p-10 space-y-8">
              <div className="space-y-1"><label className="text-[11px] font-black text-slate-900 uppercase">Legal Name</label><input required value={facultyForm.name} onChange={(e) => setFacultyForm({...facultyForm, name: e.target.value})} className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600" placeholder="e.g. Dr. G. Padmaja" /></div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1"><label className="text-[11px] font-black text-slate-900 uppercase">Primary Dept</label><select value={facultyForm.department} onChange={(e) => setFacultyForm({...facultyForm, department: e.target.value as Department})} className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold appearance-none">{DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}</select></div>
                <div className="space-y-1"><label className="text-[11px] font-black text-slate-900 uppercase">Node Type</label><div className="p-5 bg-blue-50 border-2 border-blue-100 rounded-2xl text-[10px] font-black text-blue-600 text-center">Autonomous Faculty</div></div>
              </div>
              <div className="space-y-4">
                <div className="flex justify-between items-center"><label className="text-[11px] font-black text-slate-900 uppercase">Subject mapping (Nodes)</label><button type="button" onClick={() => setFacultyForm({...facultyForm, subjects: [...(facultyForm.subjects || []), '']})} className="text-blue-600 text-[11px] font-black uppercase hover:underline">+ Add Node</button></div>
                <p className="text-[9px] text-slate-400 font-bold uppercase -mt-2">Map exactly to Node ID (e.g., 'ML' for theory, 'ML-LAB' for lab)</p>
                {facultyForm.subjects?.map((sub, idx) => (
                  <div key={idx} className="flex gap-3"><input value={sub} onChange={(e) => { const newS = [...(facultyForm.subjects || [])]; newS[idx] = e.target.value; setFacultyForm({...facultyForm, subjects: newS}); }} className="flex-1 p-4 bg-slate-50 border-2 border-slate-100 rounded-xl font-bold uppercase" placeholder="e.g. ML or ML-LAB" />{facultyForm.subjects!.length > 1 && <button type="button" onClick={() => setFacultyForm({...facultyForm, subjects: facultyForm.subjects?.filter((_, i) => i !== idx)})} className="p-4 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={20} /></button>}</div>
                ))}
              </div>
              <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-2xl hover:bg-black transition-all">Seal Record</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { 
  FileText, 
  ShieldCheck, 
  BarChart3, 
  Settings, 
  Code,
  Lock
} from 'lucide-react';
import FeedbackPortal from './components/FeedbackPortal';
import AnalysisView from './components/AnalysisView';
import TechnicalRoadmap from './components/TechnicalRoadmap';
import AdminDashboard from './components/AdminDashboard';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Auth from './components/Auth';
import { FeedbackEntry, User, UserRole, Subject, Faculty } from './types';
import { 
  SUBJECTS as INITIAL_SUBJECTS, 
  FACULTY_DATA as INITIAL_FACULTIES,
  THEORY_METRICS as INITIAL_THEORY_METRICS,
  LAB_METRICS as INITIAL_LAB_METRICS
} from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'feedback' | 'analysis' | 'roadmap' | 'admin'>('feedback');
  const [feedbacks, setFeedbacks] = useState<FeedbackEntry[]>([]);
  const [isSidebarOpen, setSidebarOpen] = useState(true);

  // Global Registry State (Single Source of Truth)
  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  // Dynamic Attribute Sets
  const [theoryQuestions, setTheoryQuestions] = useState<string[]>(INITIAL_THEORY_METRICS);
  const [labQuestions, setLabQuestions] = useState<string[]>(INITIAL_LAB_METRICS);

  // Session Registry: Tracks which Dept-Sem combinations are currently open
  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>({
    'CSE-3.1': true,
    'AIDS-3.1': true,
    'IT-2.1': true,
    'ECE-3.1': true
  });

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) {
      setActiveTab('admin');
    } else {
      setActiveTab('feedback');
    }
  };

  const logout = () => {
    setUser(null);
  };

  if (!user) {
    return <Auth onAuthenticate={handleAuth} />;
  }

  const tabs = [
    { id: 'feedback', label: 'Submit Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3, roles: [UserRole.ADMIN] },
    { id: 'admin', label: 'Admin Power', icon: Lock, roles: [UserRole.ADMIN] },
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
        user={user}
        onLogout={logout}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} 
          user={user}
        />

        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-[#fdfdfd]">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={addFeedback} 
                onLogout={logout} 
                user={user} 
                subjects={subjects}
                sessionRegistry={sessionRegistry}
                theoryQuestions={theoryQuestions}
                labQuestions={labQuestions}
              />
            )}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <AdminDashboard 
                subjects={subjects} 
                setSubjects={setSubjects}
                faculties={faculties}
                setFaculties={setFaculties}
                sessionRegistry={sessionRegistry}
                setSessionRegistry={setSessionRegistry}
                theoryQuestions={theoryQuestions}
                setTheoryQuestions={setTheoryQuestions}
                labQuestions={labQuestions}
                setLabQuestions={setLabQuestions}
              />
            )}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  ShieldAlert,
  Calendar,
  UserCheck,
  ExternalLink,
  SearchX,
  Database
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FeedbackType, FeedbackEntry, User, Subject } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: string[];
  labQuestions: string[];
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  const syncStudentView = async () => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = sessionRegistry[sessionKey] || false;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  };

  useEffect(() => {
    syncStudentView();
  }, [user.department, user.semester, subjects, sessionRegistry, type]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity and professional conduct for a college faculty feedback form.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "Academic content moderator. Block insults or harassment."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  const metrics = type === FeedbackType.THEORY ? theoryQuestions : labQuestions;

  const calculateTotal = (subjectId: string): number => {
    const scores = matrixScores[subjectId] || {};
    return (Object.values(scores) as number[]).reduce((a, b) => a + b, 0);
  };

  const calculateSatisfaction = (subjectId: string): number => {
    const total = calculateTotal(subjectId);
    const max = metrics.length * 5;
    if (max === 0) return 0;
    return (total / max) * 100;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen) return alert('This department feedback session is currently closed.');
    if (activeSubjects.length === 0) return alert('No subjects mapped to your node for this type.');

    setAbuseError(null);
    let allFilled = true;
    activeSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please complete all ratings.');
    if (!hasSigned) return alert('Digital signature is required.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Unprofessional language detected.");
      return;
    }

    setIsSubmitting(true);

    try {
      const payload = {
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        satisfaction: activeSubjects.map(s => ({ subject: s.id, percent: calculateSatisfaction(s.id) })),
        studentEmail: user.email,
        timestamp: Date.now()
      };

      const result = await sendGaslessFeedback(payload);
      setLastSubmission(result);

      const batchEntry: FeedbackEntry = {
        id: `batch-${Date.now()}`,
        type,
        facultyId: 'batch-multi',
        subjectId: 'batch-multi',
        department: user.department!,
        semester: user.semester!,
        data: matrixScores as any,
        timestamp: Date.now(),
        encryptedHash: result.ipfsHash
      };

      onSubmit(batchEntry);
      setIsSubmitting(false);
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 8000);
    } catch (error) {
      alert("Submission failed.");
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Recorded</h2>
        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 w-full mb-8 text-left space-y-3 font-mono text-[10px]">
           <div className="flex justify-between items-center"><span className="text-slate-400 uppercase font-black">IPFS CID</span><a href={`https://gateway.pinata.cloud/ipfs/${lastSubmission?.ipfsHash}`} target="_blank" className="text-blue-600 hover:underline">View JSON</a></div>
           <p className="text-slate-700 break-all bg-white p-2 rounded-lg">{lastSubmission?.ipfsHash}</p>
        </div>
        <p className="text-slate-500 mb-8 font-medium">Digital seal applied to <span className="text-blue-600 font-bold">{user.department} {user.semester}</span> ledger.</p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-700">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30">
          <div className="flex flex-col lg:flex-row justify-between items-center gap-8">
            <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
              <div className="flex items-center gap-4 mb-3">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg">SRK</div>
                <div>
                  <h1 className="text-xl font-black text-slate-900">SRK INSTITUTE OF TECHNOLOGY</h1>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Approved by AICTE • NBA & NAAC 'A' grade</p>
                </div>
              </div>
              <div className="mt-2 text-[11px] font-black text-slate-600 uppercase tracking-[0.2em] border-l-4 border-blue-600 pl-4">
                {user.department} Department - {user.semester} Active Node
              </div>
            </div>

            {!isSessionOpen ? (
              <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3 animate-pulse">
                <ShieldAlert className="text-red-500" size={24} />
                <span className="text-xs font-black text-red-600 uppercase tracking-widest">Portal Closed by Admin</span>
              </div>
            ) : (
              <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
                <button type="button" onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.THEORY ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}><BookOpen size={16} /> CLASS</button>
                <button type="button" onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.LAB ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}><FlaskConical size={16} /> LABORATORY</button>
              </div>
            )}
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-20 flex flex-col items-center justify-center text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-[3rem] text-slate-300">
               {activeSubjects.length === 0 ? <SearchX size={80} /> : <Lock size={80} />}
             </div>
             <div>
               <h3 className="text-2xl font-black text-slate-900">{activeSubjects.length === 0 ? 'Registry Undefined' : 'Session Blocked'}</h3>
               <p className="text-slate-500 max-w-md mx-auto mt-2 font-medium">
                 {activeSubjects.length === 0 
                   ? `The subject node for ${user.department} ${user.semester} (${type}) hasn't been configured yet.` 
                   : "The HOD has manually suspended traffic for this department."}
               </p>
             </div>
             <div className="flex gap-4">
                <div className="flex items-center gap-2 px-5 py-2.5 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest border border-blue-100"><ShieldAlert size={14} /> Contact HOD</div>
                <div className="flex items-center gap-2 px-5 py-2.5 bg-slate-50 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-100"><Database size={14} /> Check Mapping</div>
             </div>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-200">
                    <th className="p-8 text-left border-r border-slate-200 min-w-[450px] sticky left-0 bg-slate-50 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)] text-[12px] font-black text-slate-900 uppercase">Attributes for Feedback</th>
                    {activeSubjects.map(s => (
                      <th key={s.id} className="p-8 text-center border-r border-slate-200 min-w-[140px] bg-slate-50">
                        <span className="block text-sm font-black text-slate-900">{s.id}</span>
                        <span className="block text-[8px] font-black text-slate-400 uppercase tracking-tighter">{s.code}</span>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-blue-50/40 transition-colors group">
                      <td className="p-8 border-r border-slate-200 bg-white sticky left-0 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)] text-[13px] font-semibold text-slate-700">
                        <span className="text-xs font-black text-slate-300 mr-4">{(mIdx + 1).toString().padStart(2, '0')}</span>
                        {metric}
                      </td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center border-r border-slate-100">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))} 
                            className={`w-14 h-14 text-center font-black rounded-2xl border-2 appearance-none transition-all outline-none cursor-pointer ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-500/30' : 'bg-slate-50 border-slate-100 text-slate-400 hover:border-blue-300'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                  <tr className="bg-slate-900 text-white font-black uppercase tracking-widest text-[10px]">
                    <td className="p-8 border-r border-slate-800 sticky left-0 bg-slate-900 z-20">Total Satisfaction Level = (Total points / {metrics.length * 5} x 100)</td>
                    {activeSubjects.map(s => (
                      <td key={s.id} className="p-8 text-center bg-slate-900/90 font-mono">
                        <div className="text-blue-400">{calculateTotal(s.id)} / {metrics.length * 5}</div>
                        <div className="text-sm font-black mt-1">{calculateSatisfaction(s.id).toFixed(0)}%</div>
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>

            <div className="p-10 space-y-12 bg-white">
              <div className="space-y-6">
                <label className="text-xs font-black text-slate-900 uppercase tracking-[0.3em] flex items-center gap-3"><MessageSquare size={18} /> Improvements Suggestion:</label>
                <textarea 
                  value={suggestions} 
                  onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} 
                  placeholder="Share constructive feedback regarding curriculum, lab manual clarity, or engagement..." 
                  className={`w-full p-10 bg-slate-50 border-2 rounded-[2.5rem] focus:ring-8 outline-none transition-all min-h-[220px] text-slate-700 font-medium ${abuseError ? 'border-red-500 focus:ring-red-500/10' : 'border-slate-100 focus:ring-blue-500/5'}`} 
                />
                {abuseError && <div className="text-red-600 text-[10px] font-black uppercase tracking-tight flex items-center gap-3 bg-red-50 p-6 rounded-2xl border border-red-100 animate-in shake"><AlertTriangle size={18} /> {abuseError}</div>}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-end pt-8 border-t border-slate-100">
                <div onClick={() => setHasSigned(!hasSigned)} className={`flex items-center gap-6 p-8 rounded-[2rem] border-2 cursor-pointer transition-all ${hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-2xl' : 'bg-slate-50 border-slate-100'}`}>
                  <div className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all ${hasSigned ? 'bg-white text-blue-600' : 'bg-white text-transparent border-slate-300'}`}>{hasSigned && <CheckCircle2 size={24} />}</div>
                  <div className="flex-1">
                    <span className="text-[11px] font-black uppercase tracking-[0.2em] block">Digital Signature Acknowledgment</span>
                    <span className="text-[10px] font-bold opacity-60 flex items-center gap-2 mt-1"><Calendar size={14} /> {new Date().toLocaleDateString()}</span>
                  </div>
                </div>
                <button type="submit" disabled={isSubmitting || isAnalyzing} className="w-full py-8 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-[11px] transition-all flex items-center justify-center gap-4">
                  {isAnalyzing ? <><Loader2 className="animate-spin" /> Verifying Integrity...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Block...</> : <><Send size={20} /> Finalize Submission</>}
                </button>
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

export default FeedbackPortal;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Settings, 
  Users, 
  Power, 
  Plus, 
  Trash2, 
  Edit3, 
  Database, 
  ShieldAlert,
  Save,
  FileSpreadsheet,
  ToggleLeft,
  ToggleRight,
  Activity,
  UserCheck,
  X,
  CheckCircle2,
  AlertCircle,
  RefreshCcw,
  BookOpen,
  CalendarDays,
  Hash,
  Building2
} from 'lucide-react';
import { Department, Faculty, AdminSettings, Semester, Subject, FeedbackType } from '../types';
import { DEPARTMENTS, SEMESTERS, FACULTY_DATA as DEFAULT_FACULTIES, SUBJECTS as DEFAULT_SUBJECTS } from '../constants';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: string[];
  setTheoryQuestions: React.Dispatch<React.SetStateAction<string[]>>;
  labQuestions: string[];
  setLabQuestions: React.Dispatch<React.SetStateAction<string[]>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, setSubjects, 
  faculties, setFaculties, 
  sessionRegistry, setSessionRegistry,
  theoryQuestions, setTheoryQuestions,
  labQuestions, setLabQuestions
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'dataset'>('control');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Modal State for Faculty
  const [isFacultyModalOpen, setIsFacultyModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [facultyForm, setFacultyForm] = useState<Partial<Faculty>>({
    name: '',
    department: 'CSE',
    subjects: ['']
  });

  // Modal State for Subjects
  const [isSubjectModalOpen, setIsSubjectModalOpen] = useState(false);
  const [subjectFilterDept, setSubjectFilterDept] = useState<Department>('CSE');
  const [subjectFilterSem, setSubjectFilterSem] = useState<Semester>('3.1');
  const [subjectForm, setSubjectForm] = useState<Partial<Subject>>({ 
    id: '', 
    name: '', 
    code: '', 
    type: FeedbackType.THEORY 
  });

  // --- HANDLERS: SESSION CONTROL ---
  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSessionRegistry(prev => ({
      ...prev,
      [key]: !prev[key]
    }));
    setToast({ 
      message: `${dept} ${sem} Session ${!sessionRegistry[key] ? 'Opened' : 'Closed'}`, 
      type: 'success' 
    });
  };

  const toggleGlobalSession = (status: boolean) => {
    const newRegistry: Record<string, boolean> = {};
    DEPARTMENTS.forEach(d => SEMESTERS.forEach(s => {
      newRegistry[`${d}-${s}`] = status;
    }));
    setSessionRegistry(newRegistry);
    setToast({ message: `Global Sessions ${status ? 'Activated' : 'Suspended'}`, type: 'success' });
  };

  // --- HANDLERS: FACULTY CRUD ---
  const saveFaculty = (e: React.FormEvent) => {
    e.preventDefault();
    if (!facultyForm.name || !facultyForm.department) return;

    if (editingFaculty) {
      setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? { ...f, ...facultyForm } as Faculty : f));
      setToast({ message: "Faculty updated", type: 'success' });
    } else {
      const newFac: Faculty = {
        id: `f-${Date.now()}`,
        name: facultyForm.name!,
        department: facultyForm.department as Department,
        subjects: facultyForm.subjects || []
      };
      setFaculties(prev => [...prev, newFac]);
      setToast({ message: "New faculty added", type: 'success' });
    }
    setIsFacultyModalOpen(false);
  };

  const deleteFaculty = (id: string) => {
    setFaculties(prev => prev.filter(f => f.id !== id));
    setToast({ message: "Faculty record purged", type: 'success' });
  };

  // --- HANDLERS: SUBJECT CRUD ---
  const filteredSubjects = useMemo(() => {
    return subjects.filter(s => s.department === subjectFilterDept && s.semester === subjectFilterSem);
  }, [subjects, subjectFilterDept, subjectFilterSem]);

  const saveSubject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!subjectForm.id || !subjectForm.name) return;

    const newSub: Subject = {
      id: subjectForm.id!,
      name: subjectForm.name!,
      code: subjectForm.code || subjectForm.id!,
      department: subjectFilterDept,
      semester: subjectFilterSem,
      type: subjectForm.type || FeedbackType.THEORY
    };

    setSubjects(prev => [...prev.filter(s => !(s.id === newSub.id && s.department === newSub.department && s.semester === newSub.semester && s.type === newSub.type)), newSub]);
    setToast({ message: "Subject node appended", type: 'success' });
    setIsSubjectModalOpen(false);
    setSubjectForm({ id: '', name: '', code: '', type: FeedbackType.THEORY });
  };

  const deleteSubject = (id: string, dept: Department, sem: Semester, type: FeedbackType) => {
    setSubjects(prev => prev.filter(s => !(s.id === id && s.department === dept && s.semester === sem && s.type === type)));
    setToast({ message: "Subject entry deleted", type: 'success' });
  };

  // --- HANDLERS: DATASET (QUESTIONS) ---
  const handleQuestionEdit = (type: FeedbackType, index: number, value: string) => {
    if (type === FeedbackType.THEORY) {
      const newQ = [...theoryQuestions];
      newQ[index] = value;
      setTheoryQuestions(newQ);
    } else {
      const newQ = [...labQuestions];
      newQ[index] = value;
      setLabQuestions(newQ);
    }
  };

  const addQuestion = (type: FeedbackType) => {
    if (type === FeedbackType.THEORY) {
      setTheoryQuestions([...theoryQuestions, "New assessment criteria..."]);
    } else {
      setLabQuestions([...labQuestions, "New laboratory criteria..."]);
    }
    setToast({ message: "New criteria field appended", type: 'success' });
  };

  const removeQuestion = (type: FeedbackType, index: number) => {
    if (type === FeedbackType.THEORY) {
      setTheoryQuestions(theoryQuestions.filter((_, i) => i !== index));
    } else {
      setLabQuestions(labQuestions.filter((_, i) => i !== index));
    }
    setToast({ message: "Criteria field removed", type: 'error' });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20 relative">
      {toast && (
        <div className={`fixed top-6 right-6 z-[120] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 animate-in slide-in-from-top duration-300 ${toast.type === 'success' ? 'border-emerald-500 text-emerald-600 bg-white' : 'border-red-500 text-red-600 bg-white'}`}>
          {toast.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
          <span className="text-sm font-black uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Top Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl w-fit mb-4"><Users size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Faculty Records</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{faculties.length} Profiles</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl w-fit mb-4"><BookOpen size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Subject Nodes</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{subjects.length} Mapped</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl w-fit mb-4"><ShieldAlert size={24} /></div>
