  const [subjects, setSubjects] = useState<Subject[]>(INITIAL_SUBJECTS);
  const [faculties, setFaculties] = useState<Faculty[]>(INITIAL_FACULTIES);

  // Department-Specific Attribute Sets (Maps)
  // Initialize every department with the default set to ensure visibility across all branches
  const [theoryQuestions, setTheoryQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_THEORY_METRICS] }), {} as Record<Department, string[]>)
  );
  const [labQuestions, setLabQuestions] = useState<Record<Department, string[]>>(
    DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept]: [...INITIAL_LAB_METRICS] }), {} as Record<Department, string[]>)
  );

  // Session Registry: Tracks which Dept-Sem combinations are currently open
  const [sessionRegistry, setSessionRegistry] = useState<Record<string, boolean>>({
    'CSE-3.1': true,
    'AIDS-3.1': true,
    'IT-2.1': true,
    'ECE-3.1': true
  });

  const addFeedback = (entry: FeedbackEntry) => {
    setFeedbacks(prev => [...prev, entry]);
  };

  const handleAuth = (authenticatedUser: User) => {
    setUser(authenticatedUser);
    if (authenticatedUser.role === UserRole.ADMIN) {
      setActiveTab('admin');
    } else {
      setActiveTab('feedback');
    }
  };

  const logout = () => {
    setUser(null);
  };

  if (!user) {
    return <Auth onAuthenticate={handleAuth} />;
  }

  const tabs = [
    { id: 'feedback', label: 'Submit Feedback', icon: FileText, roles: [UserRole.STUDENT] },
    { id: 'analysis', label: 'HOD Analysis', icon: BarChart3, roles: [UserRole.ADMIN] },
    { id: 'admin', label: 'Admin Power', icon: Lock, roles: [UserRole.ADMIN] },
    { id: 'roadmap', label: 'Architecture', icon: Code },
  ].filter(tab => !tab.roles || tab.roles.includes(user.role));

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        tabs={tabs} 
        isOpen={isSidebarOpen}
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)}
        user={user}
        onLogout={logout}
      />

      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header 
          activeTab={tabs.find(t => t.id === activeTab)?.label || 'SRK-IT'} 
          user={user}
        />

        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-[#fdfdfd]">
          <div className="max-w-7xl mx-auto space-y-6">
            {activeTab === 'feedback' && (
              <FeedbackPortal 
                onSubmit={addFeedback} 
                onLogout={logout} 
                user={user} 
                subjects={subjects}
                sessionRegistry={sessionRegistry}
                theoryQuestions={theoryQuestions}
                labQuestions={labQuestions}
              />
            )}
            {activeTab === 'analysis' && <AnalysisView feedbacks={feedbacks} user={user} />}
            {activeTab === 'admin' && (
              <AdminDashboard 
                subjects={subjects} 
                setSubjects={setSubjects}
                faculties={faculties}
                setFaculties={setFaculties}
                sessionRegistry={sessionRegistry}
                setSessionRegistry={setSessionRegistry}
                theoryQuestions={theoryQuestions}
                setTheoryQuestions={setTheoryQuestions}
                labQuestions={labQuestions}
                setLabQuestions={setLabQuestions}
              />
            )}
            {activeTab === 'roadmap' && <TechnicalRoadmap />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  ShieldAlert,
  Calendar,
  UserCheck,
  ExternalLink,
  SearchX,
  Database
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FeedbackType, FeedbackEntry, User, Subject, Department } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  const syncStudentView = async () => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = sessionRegistry[sessionKey] || false;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  };

  useEffect(() => {
    syncStudentView();
  }, [user.department, user.semester, subjects, sessionRegistry, type]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };

    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity and professional conduct for a college faculty feedback form.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          },
          systemInstruction: "Academic content moderator. Block insults or harassment."
        }
      });

      const result = JSON.parse(response.text || '{"isAbusive": false}');
      return result;
    } catch (error) {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Safe retrieval with fallback to avoid "unexpected error" if a department is missing keys
  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    return type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const calculateTotal = (subjectId: string): number => {
    const scores = matrixScores[subjectId] || {};
    return (Object.values(scores) as number[]).reduce((a, b) => a + b, 0);
  };

  const calculateSatisfaction = (subjectId: string): number => {
    const total = calculateTotal(subjectId);
    const max = metrics.length * 5;
    if (max === 0) return 0;
    return (total / max) * 100;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen) return alert('This department feedback session is currently closed.');
    if (activeSubjects.length === 0) return alert('No subjects mapped to your node for this type.');

    setAbuseError(null);
    let allFilled = true;
    activeSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please complete all ratings.');
    if (!hasSigned) return alert('Digital signature is required.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Unprofessional language detected.");
      return;
    }

    setIsSubmitting(true);

    try {
      const payload = {
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        satisfaction: activeSubjects.map(s => ({ subject: s.id, percent: calculateSatisfaction(s.id) })),
        studentEmail: user.email,
        timestamp: Date.now()
      };

      const result = await sendGaslessFeedback(payload);
      setLastSubmission(result);

      const batchEntry: FeedbackEntry = {
        id: `batch-${Date.now()}`,
        type,
        facultyId: 'batch-multi',
        subjectId: 'batch-multi',
        department: user.department!,
        semester: user.semester!,
        data: matrixScores as any,
        timestamp: Date.now(),
        encryptedHash: result.ipfsHash
      };

      onSubmit(batchEntry);
      setIsSubmitting(false);
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 8000);
    } catch (error) {
      alert("Submission failed.");
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Recorded</h2>
        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 w-full mb-8 text-left space-y-3 font-mono text-[10px]">
           <div className="flex justify-between items-center"><span className="text-slate-400 uppercase font-black">IPFS CID</span><a href={`https://gateway.pinata.cloud/ipfs/${lastSubmission?.ipfsHash}`} target="_blank" className="text-blue-600 hover:underline">View JSON</a></div>
           <p className="text-slate-700 break-all bg-white p-2 rounded-lg">{lastSubmission?.ipfsHash}</p>
        </div>
        <p className="text-slate-500 mb-8 font-medium">Digital seal applied to <span className="text-blue-600 font-bold">{user.department} {user.semester}</span> ledger.</p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in slide-in-from-bottom duration-700">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30">
          <div className="flex flex-col lg:flex-row justify-between items-center gap-8">
            <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
              <div className="flex items-center gap-4 mb-3">
                <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg">SRK</div>
                <div>
                  <h1 className="text-xl font-black text-slate-900">SRK INSTITUTE OF TECHNOLOGY</h1>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Approved by AICTE • NBA & NAAC 'A' grade</p>
                </div>
              </div>
              <div className="mt-2 text-[11px] font-black text-slate-600 uppercase tracking-[0.2em] border-l-4 border-blue-600 pl-4">
                {user.department} Department - {user.semester} Active Node
              </div>
            </div>

            {!isSessionOpen ? (
              <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3 animate-pulse">
                <ShieldAlert className="text-red-500" size={24} />
                <span className="text-xs font-black text-red-600 uppercase tracking-widest">Portal Closed by Admin</span>
              </div>
            ) : (
              <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
                <button type="button" onClick={() => { setType(FeedbackType.THEORY); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.THEORY ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}><BookOpen size={16} /> CLASS</button>
                <button type="button" onClick={() => { setType(FeedbackType.LAB); setMatrixScores({}); }} className={`flex items-center gap-2 px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${type === FeedbackType.LAB ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}><FlaskConical size={16} /> LABORATORY</button>
              </div>
            )}
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-20 flex flex-col items-center justify-center text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-[3rem] text-slate-300">
               {activeSubjects.length === 0 ? <SearchX size={80} /> : <Lock size={80} />}
             </div>
             <div>
               <h3 className="text-2xl font-black text-slate-900">{activeSubjects.length === 0 ? 'Registry Undefined' : 'Session Blocked'}</h3>
               <p className="text-slate-500 max-w-md mx-auto mt-2 font-medium">
                 {activeSubjects.length === 0 
                   ? `The subject node for ${user.department} ${user.semester} (${type}) hasn't been configured yet.` 
                   : "The HOD has manually suspended traffic for this department."}
               </p>
             </div>
             <div className="flex gap-4">
                <div className="flex items-center gap-2 px-5 py-2.5 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase tracking-widest border border-blue-100"><ShieldAlert size={14} /> Contact HOD</div>
                <div className="flex items-center gap-2 px-5 py-2.5 bg-slate-50 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-100"><Database size={14} /> Check Mapping</div>
             </div>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-200">
                    <th className="p-8 text-left border-r border-slate-200 min-w-[450px] sticky left-0 bg-slate-50 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)] text-[12px] font-black text-slate-900 uppercase">Attributes for Feedback</th>
                    {activeSubjects.map(s => (
                      <th key={s.id} className="p-8 text-center border-r border-slate-200 min-w-[140px] bg-slate-50">
                        <span className="block text-sm font-black text-slate-900">{s.id}</span>
                        <span className="block text-[8px] font-black text-slate-400 uppercase tracking-tighter">{s.code}</span>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-blue-50/40 transition-colors group">
                      <td className="p-8 border-r border-slate-200 bg-white sticky left-0 z-20 shadow-[4px_0_15px_rgba(0,0,0,0.03)] text-[13px] font-semibold text-slate-700">
                        <span className="text-xs font-black text-slate-300 mr-4">{(mIdx + 1).toString().padStart(2, '0')}</span>
                        {metric}
                      </td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center border-r border-slate-100">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))} 
                            className={`w-14 h-14 text-center font-black rounded-2xl border-2 appearance-none transition-all outline-none cursor-pointer ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-xl shadow-blue-500/30' : 'bg-slate-50 border-slate-100 text-slate-400 hover:border-blue-300'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                  <tr className="bg-slate-900 text-white font-black uppercase tracking-widest text-[10px]">
                    <td className="p-8 border-r border-slate-800 sticky left-0 bg-slate-900 z-20">Total Satisfaction Level = (Total points / {metrics.length * 5} x 100)</td>
                    {activeSubjects.map(s => (
                      <td key={s.id} className="p-8 text-center bg-slate-900/90 font-mono">
                        <div className="text-blue-400">{calculateTotal(s.id)} / {metrics.length * 5}</div>
                        <div className="text-sm font-black mt-1">{calculateSatisfaction(s.id).toFixed(0)}%</div>
                      </td>
                    ))}
                  </tr>
                </tbody>
              </table>
            </div>

            <div className="p-10 space-y-12 bg-white">
              <div className="space-y-6">
                <label className="text-xs font-black text-slate-900 uppercase tracking-[0.3em] flex items-center gap-3"><MessageSquare size={18} /> Improvements Suggestion:</label>
                <textarea 
                  value={suggestions} 
                  onChange={(e) => { setSuggestions(e.target.value); setAbuseError(null); }} 
                  placeholder="Share constructive feedback regarding curriculum, lab manual clarity, or engagement..." 
                  className={`w-full p-10 bg-slate-50 border-2 rounded-[2.5rem] focus:ring-8 outline-none transition-all min-h-[220px] text-slate-700 font-medium ${abuseError ? 'border-red-500 focus:ring-red-500/10' : 'border-slate-100 focus:ring-blue-500/5'}`} 
                />
                {abuseError && <div className="text-red-600 text-[10px] font-black uppercase tracking-tight flex items-center gap-3 bg-red-50 p-6 rounded-2xl border border-red-100 animate-in shake"><AlertTriangle size={18} /> {abuseError}</div>}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-end pt-8 border-t border-slate-100">
                <div onClick={() => setHasSigned(!hasSigned)} className={`flex items-center gap-6 p-8 rounded-[2rem] border-2 cursor-pointer transition-all ${hasSigned ? 'bg-blue-600 border-blue-600 text-white shadow-2xl' : 'bg-slate-50 border-slate-100'}`}>
                  <div className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all ${hasSigned ? 'bg-white text-blue-600' : 'bg-white text-transparent border-slate-300'}`}>{hasSigned && <CheckCircle2 size={24} />}</div>
                  <div className="flex-1">
                    <span className="text-[11px] font-black uppercase tracking-[0.2em] block">Digital Signature Acknowledgment</span>
                    <span className="text-[10px] font-bold opacity-60 flex items-center gap-2 mt-1"><Calendar size={14} /> {new Date().toLocaleDateString()}</span>
                  </div>
                </div>
                <button type="submit" disabled={isSubmitting || isAnalyzing} className="w-full py-8 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black uppercase tracking-[0.3em] text-[11px] transition-all flex items-center justify-center gap-4">
                  {isAnalyzing ? <><Loader2 className="animate-spin" /> Verifying Integrity...</> : isSubmitting ? <><Loader2 className="animate-spin" /> Sealing Block...</> : <><Send size={20} /> Finalize Submission</>}
                </button>
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

