        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl w-fit mb-4"><ShieldAlert size={24} /></div>
          <h3 className="text-slate-500 text-xs font-bold uppercase">Active Sessions</h3>
          <p className="text-xl font-black text-slate-900 mt-1">{Object.values(sessionRegistry).filter(v => v).length} Nodes</p>
