          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead><tr className="bg-slate-50 text-left border-b border-slate-100"><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Full Name</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Dept</th><th className="p-6 text-[10px] font-black text-slate-400 uppercase">Subject Load Mapping</th><th className="p-6 text-right text-[10px] font-black text-slate-400 uppercase text-right">Actions</th></tr></thead>
              <tbody className="divide-y divide-slate-100">
                {faculties.map(fac => (
                  <tr key={fac.id} className="hover:bg-slate-50/50 group"><td className="p-6 font-bold text-slate-800">{fac.name}</td><td className="p-6"><span className="px-3 py-1 bg-white border border-slate-200 rounded-lg text-[10px] font-black">{fac.department}</span></td><td className="p-6"><div className="flex gap-2 flex-wrap">{fac.subjects.map(s => <span key={s} className="px-2 py-0.5 bg-blue-50 text-blue-600 text-[9px] font-black rounded uppercase">{s}</span>)}</div></td><td className="p-6 text-right flex justify-end gap-2"><button onClick={() => { setEditingFaculty(fac); setFacultyForm(fac); setIsFacultyModalOpen(true); }} className="p-2.5 bg-slate-100 text-slate-500 hover:bg-blue-600 hover:text-white rounded-xl transition-all"><Edit3 size={16} /></button><button onClick={() => deleteFaculty(fac.id)} className="p-2.5 bg-slate-100 text-slate-500 hover:bg-red-600 hover:text-white rounded-xl transition-all"><Trash2 size={16} /></button></td></tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Attribute Set (Dataset) View - Multi-Branch Support Added */}
      {activeSubTab === 'dataset' && (
        <div className="space-y-6 animate-in zoom-in duration-500">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 flex items-center justify-between shadow-sm">
             <div className="flex items-center gap-3">
               <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><Building2 size={20} /></div>
               <div>
                 <h3 className="text-sm font-black text-slate-900 uppercase">Branch-Specific Attribute Config</h3>
                 <p className="text-[10px] text-slate-400 font-bold uppercase">Configure metrics for {datasetDept} Department</p>
               </div>
             </div>
             <select 
               value={datasetDept} 
               onChange={(e) => setDatasetDept(e.target.value as Department)} 
               className="bg-slate-50 border-2 border-slate-100 rounded-xl px-4 py-2 text-[11px] font-black uppercase outline-none focus:border-blue-600 cursor-pointer"
             >
               {DEPARTMENTS.map(d => <option key={d} value={d}>{d} Branch</option>)}
             </select>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {[
              { type: FeedbackType.THEORY, title: `${datasetDept} Theory Metrics`, questions: theoryQuestions[datasetDept] || [], color: 'blue' },
              { type: FeedbackType.LAB, title: `${datasetDept} Laboratory Metrics`, questions: labQuestions[datasetDept] || [], color: 'emerald' }
            ].map(set => (
              <div key={set.type} className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[600px]">
