                        <input 
                          value={q} 
                          onChange={(e) => handleQuestionEdit(set.type, i, e.target.value)}
                          className="flex-1 bg-transparent text-[13px] font-semibold text-slate-700 outline-none"
                          placeholder="Enter criteria description..."
                        />
                        <button 
                          onClick={() => removeQuestion(set.type, i)}
                          className="p-1.5 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
