                    <div className="h-full flex flex-col items-center justify-center text-center opacity-40 py-20">
                      <Hash size={48} className="mb-4" />
                      <p className="text-[10px] font-black uppercase tracking-widest">No criteria defined for {datasetDept}</p>
                    </div>
                  )}
                </div>
                <div className="p-4 bg-slate-50 border-t border-slate-100">
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-center italic">Changes for {datasetDept} are live immediately.</p>
