  CheckCircle2
} from 'lucide-react';
import { UserRole, User as UserType, Department, Semester } from '../types';
import { DEPARTMENTS, SEMESTERS, HOD_LIST } from '../constants';

const GOOGLE_CLIENT_ID = "642029720812-i7s7uba0d4csckjr67ug489u4deci2ok.apps.googleusercontent.com";

interface AuthProps {
  onAuthenticate: (user: UserType) => void;
}

declare global {
  interface Window {
    google: any;
  }
}

const Auth: React.FC<AuthProps> = ({ onAuthenticate }) => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [isLogin, setIsLogin] = useState(true);
  const [dept, setDept] = useState<Department>('CSE');
  const [sem, setSem] = useState<Semester>('3.1');
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    fullName: '',
    identifier: '',
    password: ''
  });

  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://accounts.google.com/gsi/client';
    script.async = true;
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
      window.google.accounts.id.initialize({
        client_id: GOOGLE_CLIENT_ID,
        callback: handleGoogleResponse,
      });
    };

    return () => {
      if (document.body.contains(script)) {
        document.body.removeChild(script);
      }
    };
  }, [role]); // Re-render Google button if role changes and we are in the form

  useEffect(() => {
    if (role && isLogin) {
      const btn = document.getElementById('google-login-btn');
      if (btn && window.google) {
        window.google.accounts.id.renderButton(btn, { 
          theme: 'outline', 
          size: 'large', 
          width: '100%', 
          text: 'signin_with', 
          shape: 'pill' 
        });
      }
    }
  }, [role, isLogin]);

  const handleGoogleResponse = (response: any) => {
    try {
      const base64Url = response.credential.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const payload = JSON.parse(window.atob(base64));

      const email = payload.email;

      if (!email.endsWith('@srkit.ac.in') && !email.endsWith('@gmail.com')) {
        setError("Unauthorized domain. Please use your @srkit.ac.in academic email.");
        return;
      }

      // Strict HOD Validation for Google Login
      if (role === UserRole.ADMIN) {
        const designatedHod = HOD_LIST[dept];
        if (payload.name.toLowerCase().trim() !== designatedHod.toLowerCase().trim()) {
          setError(`Security Breach: Only ${designatedHod} is authorized to access the ${dept} HOD Node.`);
          return;
        }
      }

      onAuthenticate({
        fullName: payload.name,
        email: email,
        role: role!,
        department: dept,
        semester: sem,
        facultyId: role === UserRole.FACULTY ? 'f1' : undefined
      });
    } catch (err) {
      setError("Authentication failed.");
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Strict HOD Validation for ID Login
    if (role === UserRole.ADMIN) {
      const designatedHod = HOD_LIST[dept];
      if (formData.fullName.toLowerCase().trim() !== designatedHod.toLowerCase().trim()) {
        setError(`Access Denied: Only ${designatedHod} can act as HOD for ${dept}.`);
        return;
      }
    }

    onAuthenticate({
      fullName: formData.fullName,
      email: formData.identifier,
      role: role!,
      department: dept,
      semester: sem,
      facultyId: role === UserRole.FACULTY ? 'f1' : undefined
    });
  };

  const renderRoleSelector = () => (
    <div className="space-y-8 animate-in fade-in zoom-in duration-500">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-black text-slate-900 tracking-tight">Welcome to SRK-IT</h2>
        <p className="text-slate-500 font-medium">Please select your access role to continue</p>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {[
          { id: UserRole.STUDENT, label: 'Academic Student', icon: GraduationCap, desc: 'Submit feedback for your current semester', color: 'blue' },
          { id: UserRole.FACULTY, label: 'Faculty Member', icon: Presentation, desc: 'View your performance results and feedback', color: 'emerald' },
          { id: UserRole.ADMIN, label: 'Head of Dept (HOD)', icon: Users, desc: 'Manage department feedback and analysis', color: 'indigo' },
        ].map((r) => (
          <button
            key={r.id}
            onClick={() => setRole(r.id)}
            className="group flex items-center gap-6 p-6 bg-white border-2 border-slate-100 rounded-[2rem] hover:border-blue-500 hover:shadow-xl transition-all text-left"
          >
            <div className={`w-16 h-16 rounded-2xl bg-${r.color}-50 text-${r.color}-600 flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform`}>
              <r.icon size={32} />
            </div>
            <div className="flex-1">
              <h3 className="text-lg font-black text-slate-900">{r.label}</h3>
              <p className="text-xs text-slate-500 font-medium mt-1">{r.desc}</p>
            </div>
            <ChevronRight className="text-slate-300 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" size={24} />
          </button>
        ))}
      </div>

      <div className="pt-8 text-center border-t border-slate-100">
        <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
          <Shield size={12} /> Powered by Blockchain Architecture
        </p>
      </div>
    </div>
  );

  const renderAuthForm = () => (
    <div className="space-y-6 animate-in slide-in-from-right duration-500">
      <button 
        onClick={() => { setRole(null); setError(null); }}
        className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-2 hover:translate-x-[-4px] transition-transform"
      >
        ← Back to Role Selection
      </button>

      <div className="text-center space-y-2">
        <div className="inline-flex items-center gap-2 px-3 py-1 bg-slate-100 rounded-full text-slate-600 text-[10px] font-black uppercase tracking-widest mb-2">
          {role === UserRole.ADMIN ? <Users size={12}/> : role === UserRole.FACULTY ? <Presentation size={12}/> : <GraduationCap size={12}/>}
          {role?.replace('_', ' ')} Portal
        </div>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">
          {isLogin ? 'Sign In' : 'Register'}
        </h2>
      </div>

      <div className="bg-slate-100 p-1 rounded-2xl flex border border-slate-200">
        <button onClick={() => setIsLogin(true)} className={`flex-1 py-3 text-xs font-black uppercase tracking-[0.1em] rounded-xl transition-all ${isLogin ? 'bg-white shadow-lg text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign In</button>
        <button onClick={() => setIsLogin(false)} className={`flex-1 py-3 text-xs font-black uppercase tracking-[0.1em] rounded-xl transition-all ${!isLogin ? 'bg-white shadow-lg text-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Register</button>
      </div>

      {error && (
        <div className="p-4 bg-red-50 border-l-4 border-red-500 rounded-xl flex items-start gap-3 text-red-700 text-xs font-bold animate-in shake">
          <ShieldAlert size={20} className="shrink-0 mt-0.5" />
          <div>
            <p className="uppercase tracking-widest mb-1 text-[8px] opacity-70">Security Alert</p>
            {error}
          </div>
        </div>
      )}

      <div className="space-y-4">
         {isLogin && <div id="google-login-btn" className="w-full"></div>}

         <div className="relative">
            <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100"></div></div>
            <div className="relative flex justify-center text-xs uppercase"><span className="bg-white px-2 text-slate-400 font-bold tracking-widest">Credentials</span></div>
         </div>

         <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">
                {role === UserRole.ADMIN ? 'HOD Official Name' : 'Full Academic Name'}
              </label>
              <div className="relative group">
                <User size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600" />
                <input 
                  type="text" 
                  required 
                  value={formData.fullName} 
                  onChange={(e) => setFormData({...formData, fullName: e.target.value})} 
                  placeholder={role === UserRole.ADMIN ? `e.g. ${HOD_LIST[dept]}` : "e.g. Rahul Sharma"} 
                  className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-semibold" 
                />
              </div>
            </div>

            <div className={`grid ${role === UserRole.STUDENT ? 'grid-cols-2' : 'grid-cols-1'} gap-4`}>
              <div className="space-y-1">
