import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  Signature,
  AlertTriangle,
  ShieldAlert,
  Calendar,
  UserCheck,
  SearchX,
  Database
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FeedbackType, FeedbackEntry, User, Subject, Department } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [abuseError, setAbuseError] = useState<string | null>(null);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  useEffect(() => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = sessionRegistry[sessionKey] || false;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      // Dynamic Interlink: Filter subjects based on student Branch and Semester
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  }, [user.department, user.semester, subjects, sessionRegistry, type]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const validateSuggestions = async (text: string): Promise<{ isAbusive: boolean; reason?: string }> => {
    if (!text.trim()) return { isAbusive: false };
    try {
      setIsAnalyzing(true);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze: "${text}" for toxicity/conduct for faculty feedback.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isAbusive: { type: Type.BOOLEAN },
              reason: { type: Type.STRING }
            },
            required: ["isAbusive"]
          }
        }
      });
      return JSON.parse(response.text || '{"isAbusive": false}');
    } catch {
      return { isAbusive: false };
    } finally {
      setIsAnalyzing(false);
    }
  };

  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    // Theory: 10 attributes, Lab: 5 attributes as per requirement
    const list = type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
    return type === FeedbackType.THEORY ? list.slice(0, 10) : list.slice(0, 5);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const calculateTotal = (subjectId: string): number => {
    const scores = matrixScores[subjectId] || {};
    return Object.values(scores).reduce((a, b) => a + b, 0);
  };

  const calculateSatisfaction = (subjectId: string): number => {
    const total = calculateTotal(subjectId);
    const max = metrics.length * 5;
    return max === 0 ? 0 : (total / max) * 100;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen) return;
    if (activeSubjects.length === 0) return;

    let allFilled = true;
    activeSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please complete all ratings.');
    if (!hasSigned) return alert('Digital signature required.');

    const moderation = await validateSuggestions(suggestions);
    if (moderation.isAbusive) {
      setAbuseError(moderation.reason || "Unprofessional language.");
      return;
    }

    setIsSubmitting(true);
    try {
      const result = await sendGaslessFeedback({
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        timestamp: Date.now()
      });
      setLastSubmission(result);
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 8000);
    } catch {
      alert("Submission failed.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Sealed</h2>
        <p className="text-slate-500 mb-8">Digital ledger hash: {lastSubmission?.txHash.slice(0, 20)}...</p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black">SRK</div>
            <div>
              <h1 className="text-lg font-black">{user.department} NODE</h1>
              <p className="text-[10px] font-black uppercase text-slate-500">Semester {user.semester} • Protocol Level 1</p>
            </div>
          </div>
          <div className="flex bg-slate-200 p-1.5 rounded-2xl">
            <button onClick={() => setType(FeedbackType.THEORY)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.THEORY ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}>Theory (10 Attr)</button>
            <button onClick={() => setType(FeedbackType.LAB)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.LAB ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>Lab (5 Attr)</button>
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-20 text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-full w-fit mx-auto text-slate-300"><SearchX size={64} /></div>
             <h3 className="text-2xl font-black">No Registry Mapped</h3>
             <p className="text-slate-500 max-w-sm mx-auto">This department node has no active {type} subjects for your semester.</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-100">
                    <th className="p-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-widest min-w-[350px]">Assessment Metric</th>
                    {activeSubjects.map(s => <th key={s.id} className="p-8 text-center"><span className="block text-sm font-black">{s.id}</span></th>)}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx}>
                      <td className="p-8 text-sm font-bold text-slate-700">{metric}</td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))}
                            className={`w-14 h-14 rounded-2xl border-2 text-center font-black transition-all ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-10 bg-white border-t border-slate-100 space-y-10">
              <textarea 
                value={suggestions} 
                onChange={(e) => setSuggestions(e.target.value)} 
                placeholder="Submit encrypted suggestions..." 
                className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2rem] min-h-[150px] font-bold"
              />
              <div className="flex flex-col md:flex-row gap-6">
                <button type="button" onClick={() => setHasSigned(!hasSigned)} className={`flex-1 p-8 rounded-[2rem] border-2 transition-all flex items-center gap-4 ${hasSigned ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                  <CheckCircle2 /> <span className="text-[10px] font-black uppercase">ACKNOWLEDGE DIGITAL SEAL</span>
                </button>
