  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: Record<Department, string[]>;
  setTheoryQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  labQuestions: Record<Department, string[]>;
  setLabQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, setSubjects, 
  faculties, setFaculties, 
  sessionRegistry, setSessionRegistry
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'bulk'>('control');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const processBulkFile = (file: File) => {
    setIsBulkProcessing(true);
    const reader = new FileReader();

    reader.onload = (e) => {
      const content = e.target?.result as string;

      if (file.type === "application/json" || file.name.endsWith('.json')) {
        try {
          const data = JSON.parse(content);
          mapAndSetData(data);
        } catch (err) {
          setToast({ message: "Invalid JSON Format", type: 'error' });
          setIsBulkProcessing(false);
        }
      } else {
        // CSV Parsing
        Papa.parse(content, {
          header: true,
          skipEmptyLines: true,
          complete: (results) => {
            mapAndSetData(results.data);
          },
          error: () => {
            setToast({ message: "CSV Parsing Failed", type: 'error' });
            setIsBulkProcessing(false);
          }
        });
      }
    };

    reader.readAsText(file);
  };

  const mapAndSetData = (rawData: any[]) => {
    try {
      const newFaculties: Faculty[] = [];
      const newSubjects: Subject[] = [];

      rawData.forEach((row: any) => {
        const facId = row.FacultyID || row.facultyId || row.id;
        const facName = row.FacultyName || row.name;
        const subCode = row.SubjectCode || row.code;
        const subName = row.SubjectName || row.subject;
        const branch = row.Branch || row.department || row.dept;
        const rawSem = (row.Semester || row.sem || "").toString().replace('-', '.');
        const type = (row.Type || row.type || "Theory").toLowerCase().includes('lab') ? FeedbackType.LAB : FeedbackType.THEORY;

        if (facId && facName && subCode && branch) {
          // Add Faculty
          let faculty = newFaculties.find(f => f.id === facId);
          if (!faculty) {
            faculty = { id: facId, name: facName, department: branch as Department, subjects: [] };
            newFaculties.push(faculty);
          }
          if (!faculty.subjects.includes(subCode)) {
            faculty.subjects.push(subCode);
          }

          // Add Subject
          newSubjects.push({
            id: subCode,
            code: subCode,
            name: subName || subCode,
            department: branch as Department,
            semester: rawSem as any,
            type: type
          });
        }
      });

      if (newFaculties.length > 0) {
        setFaculties(newFaculties);
        setSubjects(newSubjects);
        setToast({ message: `Sequenced ${newFaculties.length} Faculty & ${newSubjects.length} Subjects`, type: 'success' });
      } else {
        throw new Error("No valid records found");
      }
    } catch (err) {
      setToast({ message: "Data Mapping Error: Check Column Headers", type: 'error' });
    } finally {
      setIsBulkProcessing(false);
    }
  };

