import React, { useState, useEffect, useRef } from 'react';
import Papa from 'papaparse';
import { 
  Settings, 
  Users, 
  Database, 
  FileSpreadsheet,
  CheckCircle2,
  BookOpen,
  Zap,
  Upload,
  Loader2,
  AlertCircle,
  FileCode,
  FileJson,
  Layers,
  ShieldCheck,
  Building2,
  RefreshCcw,
  FileText
} from 'lucide-react';
import { Department, Faculty, Subject, FeedbackType, Semester } from '../types';
import { DEPARTMENTS, SEMESTERS } from '../constants';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: Record<Department, string[]>;
  setTheoryQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  labQuestions: Record<Department, string[]>;
  setLabQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, setSubjects, 
  faculties, setFaculties, 
  sessionRegistry, setSessionRegistry
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'bulk'>('bulk');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsBulkProcessing(true);
    const reader = new FileReader();

    reader.onload = (event) => {
      const content = event.target?.result as string;

      if (file.type === "application/json" || file.name.endsWith('.json')) {
        try {
          const data = JSON.parse(content);
          mapAndSyncData(Array.isArray(data) ? data : [data]);
        } catch (err) {
          setToast({ message: "Invalid JSON format detected.", type: 'error' });
          setIsBulkProcessing(false);
        }
      } else {
        // High-performance CSV Parsing
        Papa.parse(content, {
          header: true,
          skipEmptyLines: true,
          dynamicTyping: true,
          complete: (results) => {
            mapAndSyncData(results.data);
          },
          error: (err) => {
            setToast({ message: "CSV parsing failed: " + err.message, type: 'error' });
            setIsBulkProcessing(false);
          }
        });
      }
    };

    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const mapAndSyncData = (rawData: any[]) => {
    try {
      if (!rawData || rawData.length === 0) throw new Error("File is empty.");

      const newFaculties: Faculty[] = [];
      const newSubjects: Subject[] = [];

      rawData.forEach((row: any, index: number) => {
        // Smart Header Identification Logic
        const facId = (row.FacultyID || row.facultyId || row.FID || row.id || `F${index}`).toString();
        const facName = row.FacultyName || row.name || row.Faculty || "Unknown Faculty";
        const subCode = (row.SubjectCode || row.code || row.SubjectID || row.SID || `S${index}`).toString();
        const subName = row.SubjectName || row.subject || row.SubjectTitle || subCode;
        const branch = (row.Branch || row.department || row.dept || "CSE").toUpperCase();
        const rawSem = (row.Semester || row.sem || "1.1").toString().replace('-', '.');
        const typeStr = (row.Type || row.type || "Theory").toLowerCase();
        const type = typeStr.includes('lab') ? FeedbackType.LAB : FeedbackType.THEORY;

        if (facId && subCode) {
          // Process Faculty State
          let faculty = newFaculties.find(f => f.id === facId);
          if (!faculty) {
            faculty = { 
              id: facId, 
              name: facName, 
              department: branch as Department, 
              subjects: [] 
            };
            newFaculties.push(faculty);
          }
          if (!faculty.subjects.includes(subCode)) {
            faculty.subjects.push(subCode);
          }

          // Process Subject State
          newSubjects.push({
            id: subCode,
            code: subCode,
            name: subName,
            department: branch as Department,
            semester: rawSem as Semester,
            type: type
          });
        }
      });

      if (newFaculties.length > 0) {
        setFaculties(newFaculties);
        setSubjects(newSubjects);
        setToast({ 
          message: `Success: Integrated ${newFaculties.length} Faculty & ${newSubjects.length} Subjects.`, 
          type: 'success' 
        });
      } else {
        throw new Error("Mapping failed: No valid data structures found.");
      }
    } catch (err: any) {
      setToast({ message: err.message || "Mapping error: Check file headers.", type: 'error' });
    } finally {
      setIsBulkProcessing(false);
    }
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    const key = `${dept}-${sem}`;
    setSessionRegistry(prev => ({ ...prev, [key]: !prev[key] }));
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {/* Dynamic Notification Hub */}
      {toast && (
        <div className={`fixed top-8 right-8 z-[200] flex items-center gap-4 px-6 py-4 rounded-[1.5rem] shadow-2xl border-2 animate-in slide-in-from-right duration-300 ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
          <div>
            <p className="text-[10px] font-black uppercase tracking-widest opacity-60">System Registry Update</p>
            <p className="text-sm font-black uppercase tracking-tight">{toast.message}</p>
          </div>
        </div>
      )}

      {/* Admin Command Center Tabs */}
      <div className="flex bg-slate-900 p-2 rounded-[2rem] w-fit border border-slate-800 shadow-2xl">
        {[
          { id: 'bulk', label: 'Bulk Stream', icon: Zap },
          { id: 'control', label: 'Node Access', icon: Settings },
          { id: 'faculty', label: 'Faculty Audit', icon: Users },
          { id: 'subjects', label: 'Protocol Map', icon: BookOpen },
        ].map(tab => (
          <button 
            key={tab.id} 
            onClick={() => setActiveSubTab(tab.id as any)} 
            className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === 'bulk' && (
        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl space-y-12 animate-in zoom-in duration-300 relative overflow-hidden">
           {/* Abstract Data Background Decor */}
           <div className="absolute -top-20 -right-20 p-12 opacity-[0.02] pointer-events-none">
             <Layers size={450} />
           </div>

           <div className="flex flex-col md:flex-row justify-between items-start gap-10 relative z-10">
             <div className="max-w-2xl">
               <div className="flex items-center gap-4 mb-6">
                 <div className="w-16 h-16 bg-blue-600 text-white rounded-[1.5rem] flex items-center justify-center shadow-xl">
                   <Upload size={32} />
                 </div>
                 <div>
                   <h3 className="text-3xl font-black text-slate-900 tracking-tight">Unified Data Bridge</h3>
                   <p className="text-[10px] font-black uppercase text-blue-600 tracking-widest">Protocol v2.4 • Bulk Registry Injection</p>
                 </div>
               </div>
               <p className="text-slate-500 font-medium leading-relaxed text-lg">
                 Directly modify the application's core dataset by uploading any standard CSV or JSON document. 
                 The "Smart Registry Parser" will automatically map your records into the blockchain-ready <strong>SRK-IT State</strong>.
               </p>
               <div className="flex gap-4 mt-8">
                 <div className="px-4 py-2 bg-slate-50 border border-slate-100 rounded-xl flex items-center gap-2 text-[10px] font-black text-slate-400">
                   <FileText size={14} /> CSV SUPPORTED
                 </div>
                 <div className="px-4 py-2 bg-slate-50 border border-slate-100 rounded-xl flex items-center gap-2 text-[10px] font-black text-slate-400">
                   <FileJson size={14} /> JSON SUPPORTED
                 </div>
               </div>
             </div>

             <div className="w-full md:w-auto flex flex-col items-center">
               <input 
                 type="file" 
                 ref={fileInputRef} 
                 onChange={handleFileUpload}
                 className="hidden" 
                 accept=".csv,.json"
               />
               <button 
                 onClick={() => fileInputRef.current?.click()}
                 disabled={isBulkProcessing}
                 className="group relative w-full md:w-72 h-72 rounded-[3rem] border-4 border-dashed border-slate-200 hover:border-blue-500 hover:bg-blue-50/30 transition-all flex flex-col items-center justify-center gap-4 disabled:opacity-50 overflow-hidden"
               >
                 <div className="absolute inset-0 bg-blue-600 translate-y-full group-hover:translate-y-[90%] transition-transform duration-500 opacity-10"></div>
                 {isBulkProcessing ? (
                   <Loader2 className="animate-spin text-blue-600" size={64} />
                 ) : (
                   <>
                     <div className="p-6 bg-slate-100 text-slate-400 rounded-full group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                       <Database size={40} />
                     </div>
                     <div className="text-center">
                       <p className="text-xs font-black uppercase tracking-widest text-slate-900">Push to Ledger</p>
                       <p className="text-[10px] text-slate-400 font-bold mt-1">Select Local Document</p>
                     </div>
                   </>
                 )}
               </button>
             </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 pt-12 border-t border-slate-100 relative z-10">
             {[
               { label: 'Integrity Seal', val: 'Verified', icon: ShieldCheck, color: 'emerald' },
               { label: 'Stream Speed', val: '4.8ms/entry', icon: Zap, color: 'amber' },
               { label: 'Registry Map', val: 'Dynamic v2', icon: Layers, color: 'blue' },
               { label: 'Active Node', val: 'Mainnet', icon: RefreshCcw, color: 'indigo' }
             ].map((stat, i) => (
               <div key={i} className="p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100 hover:border-blue-200 transition-all group">
                 <div className={`p-4 bg-${stat.color}-500/10 text-${stat.color}-600 rounded-2xl w-fit mb-4 group-hover:scale-110 transition-transform`}>
                   <stat.icon size={24} />
                 </div>
                 <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">{stat.label}</p>
                 <p className="text-xl font-black text-slate-900 mt-1">{stat.val}</p>
               </div>
             ))}
           </div>
        </div>
      )}

      {activeSubTab === 'control' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-left duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex justify-between items-end">
            <div>
              <h3 className="font-black text-3xl uppercase tracking-tighter text-slate-900">Node Permissions</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Toggle student portal availability per department slot</p>
            </div>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {DEPARTMENTS.map(dept => (
              <div key={dept} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 space-y-6 hover:shadow-xl transition-all">
                <div className="flex items-center justify-between border-b border-slate-200 pb-4">
                  <h4 className="font-black text-xl text-slate-900">{dept} BRANCH</h4>
                  <Building2 size={20} className="text-slate-300" />
                </div>
                <div className="flex flex-wrap gap-2.5">
                  {SEMESTERS.map(sem => {
                    const active = sessionRegistry[`${dept}-${sem}`];
                    return (
                      <button 
                        key={sem} 
                        onClick={() => toggleDeptSemAccess(dept, sem)} 
                        className={`px-5 py-3 rounded-2xl text-[10px] font-black border transition-all ${
                          active 
                            ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-500/20' 
                            : 'bg-white border-slate-200 text-slate-400 hover:border-blue-600 hover:text-blue-600'
                        }`}
                      >
                        {sem}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {(activeSubTab === 'faculty' || activeSubTab === 'subjects') && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-500">
          <div className="p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div>
              <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">
                {activeSubTab === 'faculty' ? 'Global Faculty Audit' : 'Subject Protocol Mapping'}
              </h3>
              <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">
                Verification for {activeSubTab === 'faculty' ? faculties.length : subjects.length} entries in local state
              </p>
            </div>
            <div className="flex gap-2">
               <div className="w-12 h-12 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-blue-600 transition-colors cursor-pointer">
                 <RefreshCcw size={20} />
               </div>
            </div>
          </div>
          <div className="overflow-x-auto">
             <table className="w-full">
               <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 text-left">
                 {activeSubTab === 'faculty' ? (
                   <tr><th className="p-10">ID</th><th className="p-10">Name</th><th className="p-10">Branch</th><th className="p-10">Registry Mapping</th></tr>
                 ) : (
                   <tr><th className="p-10">Code</th><th className="p-10">Title</th><th className="p-10">Semester</th><th className="p-10">Type</th></tr>
                 )}
               </thead>
               <tbody className="divide-y divide-slate-100 text-[13px] font-bold text-slate-700">
                 {activeSubTab === 'faculty' ? faculties.map(f => (
                   <tr key={f.id} className="hover:bg-slate-50/50 transition-colors group">
                     <td className="p-10 font-black text-blue-600 uppercase tracking-tighter">{f.id}</td>
                     <td className="p-10 text-slate-900">{f.name}</td>
                     <td className="p-10"><span className="px-4 py-1.5 bg-slate-100 rounded-xl uppercase text-[10px] font-black">{f.department}</span></td>
                     <td className="p-10">
                       <div className="flex gap-2 flex-wrap">
                         {f.subjects.map(s => <span key={s} className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-[9px] font-black border border-blue-100 uppercase">{s}</span>)}
                       </div>
                     </td>
                   </tr>
                 )) : subjects.map((s, idx) => (
                   <tr key={`${s.id}-${idx}`} className="hover:bg-slate-50/50 transition-colors">
                     <td className="p-10 font-black text-indigo-600 uppercase tracking-tighter">{s.code}</td>
                     <td className="p-10 text-slate-900">{s.name}</td>
                     <td className="p-10 font-black text-slate-400">{s.semester}</td>
                     <td className="p-10">
                       <span className={`px-4 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest border ${
                         s.type === FeedbackType.THEORY ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-emerald-50 text-emerald-600 border-emerald-100'
                       }`}>
                         {s.type}
                       </span>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
             {((activeSubTab === 'faculty' && faculties.length === 0) || (activeSubTab === 'subjects' && subjects.length === 0)) && (
               <div className="p-24 text-center space-y-4">
                 <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-full flex items-center justify-center mx-auto"><AlertCircle size={40} /></div>
