  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // CRUD State
  const [editingDept, setEditingDept] = useState<Department>('CSE');

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsBulkProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (file.type === "application/json" || file.name.endsWith('.json')) {
        try {
          const data = JSON.parse(content);
          mapAndSyncData(Array.isArray(data) ? data : [data]);
        } catch (err) {
          setToast({ message: "Invalid JSON format.", type: 'error' });
          setIsBulkProcessing(false);
        }
      } else {
        Papa.parse(content, {
          header: true,
          skipEmptyLines: true,
          dynamicTyping: true,
          complete: (results) => mapAndSyncData(results.data),
          error: (err) => {
            setToast({ message: "CSV parsing failed.", type: 'error' });
            setIsBulkProcessing(false);
          }
        });
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const mapAndSyncData = (rawData: any[]) => {
    try {
      if (!rawData || rawData.length === 0) throw new Error("File empty");
      const newFaculties: Faculty[] = [];
      const newSubjects: Subject[] = [];
      rawData.forEach((row: any, index: number) => {
        const facId = (row.FacultyID || row.facultyId || row.id || `F${index}`).toString();
        const facName = row.FacultyName || row.name || "Unknown Faculty";
        const subCode = (row.SubjectCode || row.code || `S${index}`).toString();
        const subName = row.SubjectName || row.subject || subCode;
        const branch = (row.Branch || row.department || "CSE").toUpperCase() as Department;
        const rawSem = (row.Semester || row.sem || "1.1").toString().replace('-', '.') as Semester;
        const typeStr = (row.Type || row.type || "Theory").toLowerCase();
        const type = typeStr.includes('lab') ? FeedbackType.LAB : FeedbackType.THEORY;

        let faculty = newFaculties.find(f => f.id === facId);
        if (!faculty) {
          faculty = { id: facId, name: facName, department: branch, subjects: [] };
          newFaculties.push(faculty);
        }
        if (!faculty.subjects.includes(subCode)) faculty.subjects.push(subCode);
        newSubjects.push({ id: subCode, code: subCode, name: subName, department: branch, semester: rawSem, type });
      });
      setFaculties(newFaculties);
      setSubjects(newSubjects);
      setToast({ message: `Integrated ${newFaculties.length} Faculty Records.`, type: 'success' });
    } catch (err: any) {
      setToast({ message: "Data mapping failed.", type: 'error' });
    } finally {
      setIsBulkProcessing(false);
    }
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    setSessionRegistry(prev => ({ ...prev, [`${dept}-${sem}`]: !prev[`${dept}-${sem}`] }));
  };

  const updateQuestion = (type: 'theory' | 'lab', dept: Department, index: number, val: string) => {
    if (type === 'theory') {
      const updated = [...theoryQuestions[dept]];
      updated[index] = val;
      setTheoryQuestions(prev => ({ ...prev, [dept]: updated }));
    } else {
      const updated = [...labQuestions[dept]];
      updated[index] = val;
      setLabQuestions(prev => ({ ...prev, [dept]: updated }));
    }
    setToast({ message: "Attribute protocol updated.", type: 'success' });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {toast && (
        <div className={`fixed top-8 right-8 z-[200] flex items-center gap-4 px-6 py-4 rounded-[1.5rem] shadow-2xl border-2 animate-in slide-in-from-right ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
          <p className="text-sm font-black uppercase tracking-tight">{toast.message}</p>
        </div>
      )}

      {/* Control Strip */}
      <div className="flex flex-wrap items-center gap-4 bg-slate-900 p-2 rounded-[2rem] border border-slate-800 shadow-2xl">
        {[
          { id: 'bulk', label: 'Bulk Stream', icon: Zap },
          { id: 'control', label: 'Access Matrix', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'subjects', label: 'Protocol Map', icon: BookOpen },
          { id: 'questions', label: 'Dataset Management', icon: Database },
        ].map(tab => (
          <button 
            key={tab.id} 
            onClick={() => setActiveSubTab(tab.id as any)} 
            className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
        <div className="h-8 w-[1px] bg-slate-800 mx-2 hidden md:block"></div>
        <button 
          onClick={() => setIsGlobalSessionActive(!isGlobalSessionActive)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
            isGlobalSessionActive ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
          }`}
        >
          <Power size={16} /> {isGlobalSessionActive ? 'Global Active' : 'Global Stopped'}
        </button>
      </div>

      {activeSubTab === 'bulk' && (
        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl space-y-12 animate-in zoom-in duration-300">
           <div className="flex flex-col md:flex-row justify-between items-start gap-10">
             <div className="max-w-2xl">
               <h3 className="text-3xl font-black text-slate-900 tracking-tight">Bulk Registry Injection</h3>
               <p className="text-slate-500 font-medium leading-relaxed mt-4">
                 Upload your 64-record faculty dataset. The system will auto-sync Branch-Semester interlinks 
                 and prepare the blockchain-ready Registry State.
               </p>
             </div>
             <div className="flex flex-col gap-4">
               <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".csv,.json" />
               <button onClick={() => fileInputRef.current?.click()} className="px-10 py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-2xl flex items-center gap-4">
                 {isBulkProcessing ? <Loader2 className="animate-spin" /> : <Database size={20} />}
                 Upload Dataset
               </button>
             </div>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-4 gap-6 pt-12 border-t border-slate-100">
             {[
               { label: 'Blockchain', val: 'Verified', icon: ShieldCheck, color: 'emerald' },
               { label: 'Mapping', val: 'Dynamic', icon: Layers, color: 'blue' },
               { label: 'Status', val: isGlobalSessionActive ? 'Open' : 'Stopped', icon: Activity, color: isGlobalSessionActive ? 'emerald' : 'red' },
               { label: 'Latency', val: '4.8ms', icon: Zap, color: 'amber' }
             ].map((stat, i) => (
               <div key={i} className="p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100">
                 <stat.icon size={22} className={`text-${stat.color}-600 mb-4`} />
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{stat.label}</p>
                 <p className="text-xl font-black text-slate-900">{stat.val}</p>
               </div>
             ))}
           </div>
        </div>
      )}

      {activeSubTab === 'control' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-left duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Student Access Matrix</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Enable/Disable login gateways per Dept-Sem cohort</p>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {DEPARTMENTS.map(dept => (
              <div key={dept} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 space-y-6">
                <h4 className="font-black text-xl text-slate-900 border-b border-slate-200 pb-2">{dept}</h4>
                <div className="flex flex-wrap gap-2.5">
                  {SEMESTERS.map(sem => {
                    const active = sessionRegistry[`${dept}-${sem}`];
                    return (
                      <button 
                        key={sem} 
                        onClick={() => toggleDeptSemAccess(dept, sem)} 
                        className={`px-5 py-3 rounded-2xl text-[10px] font-black border transition-all ${
                          active ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400'
                        }`}
                      >
                        {sem}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'questions' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <div>
              <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Question Set Management</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Modify the 10 Theory / 5 Lab Assessment Protocols</p>
            </div>
            <select 
              value={editingDept} 
              onChange={(e) => setEditingDept(e.target.value as Department)}
              className="px-6 py-3 bg-white border-2 border-slate-200 rounded-2xl font-black text-[10px] uppercase outline-none"
            >
              {DEPARTMENTS.map(d => <option key={d} value={d}>{d} Branch</option>)}
            </select>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <h4 className="font-black text-xs uppercase tracking-[0.2em] text-blue-600 flex items-center gap-2">
                <FileText size={16} /> Theory Protocol (10 Attributes)
              </h4>
              <div className="space-y-3">
                {theoryQuestions[editingDept].map((q, i) => (
                  <div key={i} className="flex gap-4">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('theory', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium" 
                    />
                  </div>
                ))}
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="font-black text-xs uppercase tracking-[0.2em] text-emerald-600 flex items-center gap-2">
                <FlaskConical size={16} /> Lab Protocol (5 Attributes)
              </h4>
              <div className="space-y-3">
                {labQuestions[editingDept].map((q, i) => (
                  <div key={i} className="flex gap-4">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('lab', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium" 
                    />
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {(activeSubTab === 'faculty' || activeSubTab === 'subjects') && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden">
          <div className="p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Registry Verification</h3>
            <button className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase flex items-center gap-2">
              <Plus size={16} /> Add Entry
            </button>
          </div>
          <div className="overflow-x-auto">
             <table className="w-full">
               <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 text-left">
                 {activeSubTab === 'faculty' ? (
                   <tr><th className="p-10">ID</th><th className="p-10">Name</th><th className="p-10">Branch</th><th className="p-10">Actions</th></tr>
                 ) : (
                   <tr><th className="p-10">Code</th><th className="p-10">Title</th><th className="p-10">Semester</th><th className="p-10">Actions</th></tr>
                 )}
               </thead>
               <tbody className="divide-y divide-slate-100 text-[13px] font-bold text-slate-700">
                 {activeSubTab === 'faculty' ? faculties.map(f => (
                   <tr key={f.id} className="hover:bg-slate-50/50">
                     <td className="p-10 font-black text-blue-600">{f.id}</td>
                     <td className="p-10">{f.name}</td>
                     <td className="p-10"><span className="px-4 py-1.5 bg-slate-100 rounded-xl uppercase text-[10px] font-black">{f.department}</span></td>
                     <td className="p-10 flex items-center gap-2">
                       <button className="p-2 text-slate-400 hover:text-blue-600"><Edit3 size={18} /></button>
                       <button className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 )) : subjects.map((s, idx) => (
                   <tr key={idx} className="hover:bg-slate-50/50">
                     <td className="p-10 font-black text-indigo-600">{s.code}</td>
                     <td className="p-10">{s.name}</td>
                     <td className="p-10 font-black text-slate-400">{s.semester}</td>
                     <td className="p-10 flex items-center gap-2">
                       <button className="p-2 text-slate-400 hover:text-blue-600"><Edit3 size={18} /></button>
                       <button className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Send, 
  CheckCircle2, 
  BookOpen, 
  FlaskConical,
  Lock,
  Loader2,
  MessageSquare,
  ShieldCheck,
  SearchX,
  ShieldAlert,
  AlertTriangle
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FeedbackType, FeedbackEntry, User, Subject, Department } from '../types';
import { sendGaslessFeedback, SimulationResult } from '../services/web3Service';

interface FeedbackPortalProps {
  onSubmit: (entry: FeedbackEntry) => void;
  onLogout: () => void;
  user: User;
  subjects: Subject[];
  sessionRegistry: Record<string, boolean>;
  theoryQuestions: Record<Department, string[]>;
  labQuestions: Record<Department, string[]>;
  isGlobalSessionActive: boolean;
}

const FeedbackPortal: React.FC<FeedbackPortalProps> = ({ 
  onSubmit, 
  onLogout, 
  user, 
  subjects, 
  sessionRegistry,
  theoryQuestions,
  labQuestions,
  isGlobalSessionActive
}) => {
  const [type, setType] = useState<FeedbackType>(FeedbackType.THEORY);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [suggestions, setSuggestions] = useState('');
  const [hasSigned, setHasSigned] = useState(false);
  const [lastSubmission, setLastSubmission] = useState<SimulationResult | null>(null);
  const [matrixScores, setMatrixScores] = useState<Record<string, Record<number, number>>>({});

  const [activeSubjects, setActiveSubjects] = useState<Subject[]>([]);
  const [isSessionOpen, setIsSessionOpen] = useState(false);

  useEffect(() => {
    const sessionKey = `${user.department}-${user.semester}`;
    const isOpen = (sessionRegistry[sessionKey] || false) && isGlobalSessionActive;
    setIsSessionOpen(isOpen);

    if (isOpen) {
      const filtered = subjects.filter(s => 
        s.department === user.department && 
        s.semester === user.semester &&
        s.type === type
      );
      setActiveSubjects(filtered);
    } else {
      setActiveSubjects([]);
    }
  }, [user.department, user.semester, subjects, sessionRegistry, type, isGlobalSessionActive]);

  const handleScoreChange = (subjectId: string, metricIdx: number, val: number) => {
    setMatrixScores(prev => ({
      ...prev,
      [subjectId]: {
        ...(prev[subjectId] || {}),
        [metricIdx]: val
      }
    }));
  };

  const metrics = useMemo(() => {
    const dept = user.department || 'CSE';
    const list = type === FeedbackType.THEORY ? (theoryQuestions[dept] || []) : (labQuestions[dept] || []);
    return type === FeedbackType.THEORY ? list.slice(0, 10) : list.slice(0, 5);
  }, [type, user.department, theoryQuestions, labQuestions]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSessionOpen) return;

    let allFilled = true;
    activeSubjects.forEach(s => {
      metrics.forEach((_, idx) => {
        if (!matrixScores[s.id]?.[idx]) allFilled = false;
      });
    });

    if (!allFilled) return alert('Please complete all ratings.');
    if (!hasSigned) return alert('Digital signature acknowledgment required.');

    setIsSubmitting(true);
    try {
      const result = await sendGaslessFeedback({
        matrixScores,
        suggestions,
        department: user.department,
        semester: user.semester,
        type,
        bundleSize: activeSubjects.length,
        timestamp: Date.now()
      });
      setLastSubmission(result);
      setIsSubmitted(true);
      setTimeout(() => onLogout(), 8000);
    } catch {
      alert("Submission failed. Network node error.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isGlobalSessionActive) {
    return (
      <div className="bg-white p-20 rounded-[3rem] border-4 border-red-100 shadow-2xl text-center max-w-3xl mx-auto animate-in fade-in duration-500">
        <div className="w-24 h-24 bg-red-100 text-red-600 rounded-full flex items-center justify-center mb-8 mx-auto">
          <ShieldAlert size={48} />
        </div>
        <h2 className="text-4xl font-black text-slate-900 mb-4 uppercase tracking-tighter">Portal Restricted</h2>
        <p className="text-slate-500 text-lg leading-relaxed font-medium">
          The Academic Council has globally suspended feedback sessions. Submissions are no longer being anchored to the blockchain.
        </p>
        <button onClick={onLogout} className="mt-10 px-10 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Logout Session</button>
      </div>
    );
  }

  if (isSubmitted) {
    return (
      <div className="bg-white p-12 rounded-[3rem] border border-slate-200 shadow-2xl text-center max-w-2xl mx-auto animate-in zoom-in duration-500">
        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 mx-auto animate-bounce">
          <CheckCircle2 size={48} />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2">Feedback Sealed</h2>
        <p className="text-slate-500 mb-8">Digital ledger hash: {lastSubmission?.txHash.slice(0, 20)}...</p>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden"><div className="bg-blue-600 h-full animate-[progress_8s_linear_forwards]"></div></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
        <div className="p-8 md:p-12 border-b-2 border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black">SRK</div>
            <div>
              <h1 className="text-lg font-black">{user.department} NODE</h1>
              <p className="text-[10px] font-black uppercase text-slate-500">Semester {user.semester} • Protocol Level 1</p>
            </div>
          </div>
          <div className="flex bg-slate-200 p-1.5 rounded-2xl">
            <button onClick={() => setType(FeedbackType.THEORY)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.THEORY ? 'bg-white shadow-md text-blue-600' : 'text-slate-500'}`}>Theory (10 Attr)</button>
            <button onClick={() => setType(FeedbackType.LAB)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${type === FeedbackType.LAB ? 'bg-white shadow-md text-emerald-600' : 'text-slate-500'}`}>Lab (5 Attr)</button>
          </div>
        </div>

        {(!isSessionOpen || activeSubjects.length === 0) ? (
          <div className="p-24 text-center space-y-6">
             <div className="p-10 bg-slate-50 rounded-full w-fit mx-auto text-slate-300"><SearchX size={64} /></div>
             <h3 className="text-2xl font-black">Cohort Restricted</h3>
             <p className="text-slate-500 max-w-sm mx-auto">This department node has not activated feedback for Semester {user.semester}.</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-slate-50 border-y border-slate-100">
                    <th className="p-8 text-left text-[11px] font-black text-slate-400 uppercase tracking-widest min-w-[350px]">Assessment Metric</th>
                    {activeSubjects.map(s => <th key={s.id} className="p-8 text-center"><span className="block text-sm font-black">{s.id}</span></th>)}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {metrics.map((metric, mIdx) => (
                    <tr key={mIdx} className="hover:bg-slate-50/50">
                      <td className="p-8 text-sm font-bold text-slate-700">{metric}</td>
                      {activeSubjects.map(s => (
                        <td key={s.id} className="p-6 text-center">
                          <select 
                            value={matrixScores[s.id]?.[mIdx] || ''} 
                            onChange={(e) => handleScoreChange(s.id, mIdx, parseInt(e.target.value))}
                            className={`w-14 h-14 rounded-2xl border-2 text-center font-black transition-all ${matrixScores[s.id]?.[mIdx] ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                          >
                            <option value="">-</option>
                            {[5, 4, 3, 2, 1].map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="p-10 bg-white border-t border-slate-100 space-y-10">
              <textarea 
                value={suggestions} 
                onChange={(e) => setSuggestions(e.target.value)} 
                placeholder="Submit encrypted suggestions to the decentralized node..." 
                className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2rem] min-h-[150px] font-bold outline-none focus:border-blue-600 transition-all"
              />
              <div className="flex flex-col md:flex-row gap-6">
