    setNewSub({ id: '', code: '', name: '', department: 'CSE', semester: '1.1', type: FeedbackType.THEORY });
    setIsAddingSubject(false);
    setToast({ message: "Subject added to map.", type: 'success' });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {toast && (
        <div className={`fixed top-8 right-8 z-[200] flex items-center gap-4 px-6 py-4 rounded-[1.5rem] shadow-2xl border-2 animate-in slide-in-from-right ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
          <p className="text-sm font-black uppercase tracking-tight">{toast.message}</p>
        </div>
      )}

      {/* Control Strip */}
      <div className="flex flex-wrap items-center gap-4 bg-slate-900 p-2 rounded-[2rem] border border-slate-800 shadow-2xl">
        {[
          { id: 'bulk', label: 'Bulk Stream', icon: Zap },
          { id: 'control', label: 'Access Matrix', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'subjects', label: 'Protocol Map', icon: BookOpen },
          { id: 'questions', label: 'Dataset Management', icon: Database },
        ].map(tab => (
          <button 
            key={tab.id} 
            onClick={() => setActiveSubTab(tab.id as any)} 
            className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
        <div className="h-8 w-[1px] bg-slate-800 mx-2 hidden md:block"></div>
        <button 
          onClick={() => setIsGlobalSessionActive(!isGlobalSessionActive)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
            isGlobalSessionActive ? 'bg-emerald-600 text-white shadow-lg' : 'bg-red-600 text-white shadow-lg'
          }`}
        >
          <Power size={16} /> {isGlobalSessionActive ? 'Global Active' : 'Global Stopped'}
        </button>
      </div>

      {activeSubTab === 'bulk' && (
        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl space-y-12 animate-in zoom-in duration-300">
           <div className="flex flex-col md:flex-row justify-between items-start gap-10">
             <div className="max-w-2xl">
               <h3 className="text-3xl font-black text-slate-900 tracking-tight">Bulk Registry Injection</h3>
               <p className="text-slate-500 font-medium leading-relaxed mt-4">
                 Upload your 64-record faculty dataset. The system will auto-sync Branch-Semester interlinks 
                 and anchor the state to the blockchain ledger.
               </p>
               {lastBulkResult && (
                 <div className="mt-6 p-4 bg-blue-50 border border-blue-100 rounded-2xl flex items-center gap-3">
                   <ShieldCheck className="text-blue-600" />
                   <div className="flex flex-col">
                     <span className="text-[10px] font-black uppercase text-blue-400">Ledger Anchor Success</span>
                     <span className="text-[11px] font-mono font-bold text-blue-900 truncate max-w-[400px]">IPFS: {lastBulkResult.ipfsHash}</span>
                   </div>
                 </div>
               )}
             </div>
             <div className="flex flex-col gap-4">
               <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".csv,.json" />
               <button onClick={() => fileInputRef.current?.click()} className="px-10 py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-2xl flex items-center gap-4 transition-all hover:bg-black active:scale-95">
                 {isBulkProcessing ? <Loader2 className="animate-spin" /> : <Database size={20} />}
                 Upload & Push Dataset
               </button>
             </div>
           </div>
        </div>
      )}

      {activeSubTab === 'control' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-left duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Student Access Matrix</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Enable/Disable login gateways per Dept-Sem cohort</p>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {DEPARTMENTS.map(dept => (
              <div key={dept} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 space-y-6">
                <h4 className="font-black text-xl text-slate-900 border-b border-slate-200 pb-2">{dept}</h4>
                <div className="flex flex-wrap gap-2.5">
                  {SEMESTERS.map(sem => {
                    const active = sessionRegistry[`${dept}-${sem}`];
                    return (
                      <button 
                        key={sem} 
                        onClick={() => toggleDeptSemAccess(dept, sem)} 
                        className={`px-5 py-3 rounded-2xl text-[10px] font-black border transition-all ${
                          active ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:border-blue-600'
                        }`}
                      >
                        {sem}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'questions' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <div>
              <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Question Set Management</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Modify the 10 Theory / 5 Lab Assessment Protocols</p>
            </div>
            <select 
              value={editingDept} 
              onChange={(e) => setEditingDept(e.target.value as Department)}
              className="px-6 py-3 bg-white border-2 border-slate-200 rounded-2xl font-black text-[10px] uppercase outline-none"
            >
              {DEPARTMENTS.map(d => <option key={d} value={d}>{d} Branch</option>)}
            </select>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <h4 className="font-black text-xs uppercase tracking-[0.2em] text-blue-600 flex items-center gap-2">
                <FileText size={16} /> Theory Protocol
              </h4>
              <div className="space-y-3">
                {theoryQuestions[editingDept]?.map((q, i) => (
                  <div key={i} className="flex gap-4">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('theory', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium" 
                    />
                  </div>
                ))}
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="font-black text-xs uppercase tracking-[0.2em] text-emerald-600 flex items-center gap-2">
                <FlaskConical size={16} /> Lab Protocol
              </h4>
              <div className="space-y-3">
                {labQuestions[editingDept]?.map((q, i) => (
                  <div key={i} className="flex gap-4">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('lab', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium" 
                    />
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {(activeSubTab === 'faculty' || activeSubTab === 'subjects') && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-up duration-500">
          <div className="p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Registry Verification</h3>
            <button 
              onClick={() => activeSubTab === 'faculty' ? setIsAddingFaculty(true) : setIsAddingSubject(true)} 
              className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase flex items-center gap-2 hover:bg-black"
            >
              <Plus size={16} /> {activeSubTab === 'faculty' ? 'Add Faculty' : 'Add Subject'}
            </button>
          </div>

          {/* Inline Add Forms */}
          {(isAddingFaculty || isAddingSubject) && (
            <div className="p-10 bg-blue-50/50 border-b border-slate-100 space-y-6 animate-in slide-in-from-top duration-300">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {activeSubTab === 'faculty' ? (
                  <>
                    <input type="text" placeholder="Faculty ID" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.id} onChange={e => setNewFac({...newFac, id: e.target.value})} />
                    <input type="text" placeholder="Name" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.name} onChange={e => setNewFac({...newFac, name: e.target.value})} />
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.department} onChange={e => setNewFac({...newFac, department: e.target.value as Department})}>
                      {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                    <div className="flex gap-2">
                      <button onClick={addFaculty} className="flex-1 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase">Confirm</button>
                      <button onClick={() => setIsAddingFaculty(false)} className="p-3 bg-white border border-slate-200 rounded-xl text-slate-400"><X size={18} /></button>
                    </div>
                  </>
                ) : (
                  <>
                    <input type="text" placeholder="Code" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.code} onChange={e => setNewSub({...newSub, code: e.target.value})} />
                    <input type="text" placeholder="Name" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.name} onChange={e => setNewSub({...newSub, name: e.target.value})} />
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.department} onChange={e => setNewSub({...newSub, department: e.target.value as Department})}>
                      {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.semester} onChange={e => setNewSub({...newSub, semester: e.target.value as Semester})}>
                      {SEMESTERS.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                    <div className="flex gap-2 col-span-1 md:col-span-4 justify-end mt-4">
                      <button onClick={addSubject} className="px-8 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase">Add Subject</button>
                      <button onClick={() => setIsAddingSubject(false)} className="px-4 bg-white border border-slate-200 rounded-xl text-slate-400 font-black text-[10px] uppercase">Cancel</button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          <div className="overflow-x-auto">
             <table className="w-full">
               <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 text-left">
                 {activeSubTab === 'faculty' ? (
                   <tr><th className="p-10">ID</th><th className="p-10">Name</th><th className="p-10">Branch</th><th className="p-10 text-right">Actions</th></tr>
                 ) : (
                   <tr><th className="p-10">Code</th><th className="p-10">Title</th><th className="p-10">Semester</th><th className="p-10 text-right">Actions</th></tr>
                 )}
               </thead>
               <tbody className="divide-y divide-slate-100 text-[13px] font-bold text-slate-700">
                 {activeSubTab === 'faculty' ? faculties.map(f => (
                   <tr key={f.id} className="hover:bg-slate-50/50 group">
                     <td className="p-10 font-black text-blue-600">{f.id}</td>
                     <td className="p-10">{f.name}</td>
                     <td className="p-10"><span className="px-4 py-1.5 bg-slate-100 rounded-xl uppercase text-[10px] font-black">{f.department}</span></td>
                     <td className="p-10 text-right space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                       <button className="p-2 text-slate-400 hover:text-blue-600"><Edit3 size={18} /></button>
                       <button onClick={() => deleteFaculty(f.id)} className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 )) : subjects.map((s, idx) => (
                   <tr key={idx} className="hover:bg-slate-50/50 group">
                     <td className="p-10 font-black text-indigo-600">{s.code}</td>
                     <td className="p-10">{s.name}</td>
                     <td className="p-10 font-black text-slate-400">{s.semester}</td>
                     <td className="p-10 text-right space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                       <button className="p-2 text-slate-400 hover:text-blue-600"><Edit3 size={18} /></button>
                       <button onClick={() => deleteSubject(s.id)} className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useRef } from 'react';
import Papa from 'papaparse';
import { 
  Settings, 
  Users, 
  Database, 
  CheckCircle2,
  BookOpen,
  Zap,
  Upload,
  Loader2,
  AlertCircle,
  Layers,
  ShieldCheck,
  Building2,
  RefreshCcw,
  FileText,
  Power,
  Edit3,
  Plus,
  Trash2,
  Save,
  Activity,
  FlaskConical,
  X,
  Check,
  SaveAll
} from 'lucide-react';
import { Department, Faculty, Subject, FeedbackType, Semester } from '../types';
import { DEPARTMENTS, SEMESTERS } from '../constants';
import { bulkUpdateRegistry, SimulationResult } from '../services/web3Service';

interface AdminDashboardProps {
  subjects: Subject[];
  setSubjects: React.Dispatch<React.SetStateAction<Subject[]>>;
  faculties: Faculty[];
  setFaculties: React.Dispatch<React.SetStateAction<Faculty[]>>;
  sessionRegistry: Record<string, boolean>;
  setSessionRegistry: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  theoryQuestions: Record<Department, string[]>;
  setTheoryQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  labQuestions: Record<Department, string[]>;
  setLabQuestions: React.Dispatch<React.SetStateAction<Record<Department, string[]>>>;
  isGlobalSessionActive: boolean;
  setIsGlobalSessionActive: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  subjects, setSubjects, 
  faculties, setFaculties, 
  sessionRegistry, setSessionRegistry,
  theoryQuestions, setTheoryQuestions,
  labQuestions, setLabQuestions,
  isGlobalSessionActive, setIsGlobalSessionActive
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'control' | 'faculty' | 'subjects' | 'bulk' | 'questions'>('bulk');
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [isBulkProcessing, setIsBulkProcessing] = useState(false);
  const [lastBulkResult, setLastBulkResult] = useState<SimulationResult | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Edit States
  const [editingDept, setEditingDept] = useState<Department>('CSE');
  const [isAddingFaculty, setIsAddingFaculty] = useState(false);
  const [isAddingSubject, setIsAddingSubject] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
  const [editingSubject, setEditingSubject] = useState<Subject | null>(null);

  // New Form States
  const [newFac, setNewFac] = useState<Partial<Faculty>>({ id: '', name: '', department: 'CSE', subjects: [] });
  const [newSub, setNewSub] = useState<Partial<Subject>>({ id: '', code: '', name: '', department: 'CSE', semester: '1.1', type: FeedbackType.THEORY });

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsBulkProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (file.type === "application/json" || file.name.endsWith('.json')) {
        try {
          const data = JSON.parse(content);
          mapAndSyncData(Array.isArray(data) ? data : [data]);
        } catch (err) {
          setToast({ message: "Invalid JSON format.", type: 'error' });
          setIsBulkProcessing(false);
        }
      } else {
        Papa.parse(content, {
          header: true,
          skipEmptyLines: true,
          dynamicTyping: true,
          complete: (results) => mapAndSyncData(results.data),
          error: (err) => {
            setToast({ message: "CSV parsing failed.", type: 'error' });
            setIsBulkProcessing(false);
          }
        });
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const mapAndSyncData = async (rawData: any[]) => {
    try {
      if (!rawData || rawData.length === 0) throw new Error("File empty");
      const newFaculties: Faculty[] = [];
      const newSubjects: Subject[] = [];

      rawData.forEach((row: any, index: number) => {
        const facId = (row.FacultyID || row.facultyId || row.id || `F${index}`).toString();
        const facName = row.FacultyName || row.name || "Unknown Faculty";
        const subCode = (row.SubjectCode || row.code || `S${index}`).toString();
        const subName = row.SubjectName || row.subject || subCode;
        const branch = (row.Branch || row.department || "CSE").toUpperCase() as Department;
        const rawSem = (row.Semester || row.sem || "1.1").toString().replace('-', '.') as Semester;
        const typeStr = (row.Type || row.type || "Theory").toLowerCase();
        const type = typeStr.includes('lab') ? FeedbackType.LAB : FeedbackType.THEORY;

        let faculty = newFaculties.find(f => f.id === facId);
        if (!faculty) {
          faculty = { id: facId, name: facName, department: branch, subjects: [] };
          newFaculties.push(faculty);
        }
        if (!faculty.subjects.includes(subCode)) faculty.subjects.push(subCode);
        newSubjects.push({ id: subCode, code: subCode, name: subName, department: branch, semester: rawSem, type });
      });

      const res = await bulkUpdateRegistry(newFaculties, newSubjects);
      setLastBulkResult(res);
      setFaculties(newFaculties);
      setSubjects(newSubjects);
      setToast({ message: `Anchored ${newFaculties.length} Faculty to Ledger.`, type: 'success' });
    } catch (err: any) {
      setToast({ message: "Data mapping failed.", type: 'error' });
    } finally {
      setIsBulkProcessing(false);
    }
  };

  const toggleDeptSemAccess = (dept: string, sem: string) => {
    setSessionRegistry(prev => ({ ...prev, [`${dept}-${sem}`]: !prev[`${dept}-${sem}`] }));
  };

  const updateQuestion = (type: 'theory' | 'lab', dept: Department, index: number, val: string) => {
    if (type === 'theory') {
      const updated = [...(theoryQuestions[dept] || [])];
      updated[index] = val;
      setTheoryQuestions(prev => ({ ...prev, [dept]: updated }));
    } else {
      const updated = [...(labQuestions[dept] || [])];
      updated[index] = val;
      setLabQuestions(prev => ({ ...prev, [dept]: updated }));
    }
    // Note: We don't toast on every keystroke to avoid spam
  };

  const deleteFaculty = (id: string) => {
    setFaculties(prev => prev.filter(f => f.id !== id));
    setToast({ message: "Faculty record purged.", type: 'success' });
  };

  const deleteSubject = (id: string) => {
    setSubjects(prev => prev.filter(s => s.id !== id));
    setToast({ message: "Subject protocol purged.", type: 'success' });
  };

  const addFaculty = () => {
    if (!newFac.id || !newFac.name) return setToast({ message: "ID and Name required.", type: 'error' });
    const faculty: Faculty = {
      id: newFac.id,
      name: newFac.name,
      department: newFac.department as Department,
      subjects: []
    };
    setFaculties(prev => [...prev, faculty]);
    setNewFac({ id: '', name: '', department: 'CSE', subjects: [] });
    setIsAddingFaculty(false);
    setToast({ message: "Faculty added to registry.", type: 'success' });
  };

  const addSubject = () => {
    if (!newSub.code || !newSub.name) return setToast({ message: "Code and Name required.", type: 'error' });
    const subject: Subject = {
      id: newSub.code,
      code: newSub.code,
      name: newSub.name,
      department: newSub.department as Department,
      semester: newSub.semester as Semester,
      type: newSub.type as FeedbackType
    };
    setSubjects(prev => [...prev, subject]);
    setNewSub({ id: '', code: '', name: '', department: 'CSE', semester: '1.1', type: FeedbackType.THEORY });
    setIsAddingSubject(false);
    setToast({ message: "Subject added to map.", type: 'success' });
  };

  const saveEditedFaculty = () => {
    if (!editingFaculty) return;
    setFaculties(prev => prev.map(f => f.id === editingFaculty.id ? editingFaculty : f));
    setEditingFaculty(null);
    setToast({ message: "Faculty record updated.", type: 'success' });
  };

  const saveEditedSubject = () => {
    if (!editingSubject) return;
    setSubjects(prev => prev.map(s => s.id === editingSubject.id ? editingSubject : s));
    setEditingSubject(null);
    setToast({ message: "Subject protocol updated.", type: 'success' });
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      {toast && (
        <div className={`fixed top-8 right-8 z-[200] flex items-center gap-4 px-6 py-4 rounded-[1.5rem] shadow-2xl border-2 animate-in slide-in-from-right ${
          toast.type === 'success' ? 'bg-white border-emerald-500 text-emerald-600' : 'bg-white border-red-500 text-red-600'
        }`}>
          {toast.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
          <p className="text-sm font-black uppercase tracking-tight">{toast.message}</p>
        </div>
      )}

      {/* Edit Faculty Modal */}
      {editingFaculty && (
        <div className="fixed inset-0 z-[300] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-10 space-y-8 animate-in zoom-in duration-300">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Edit Faculty</h3>
              <button onClick={() => setEditingFaculty(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X /></button>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Faculty Name</label>
                <input 
                  type="text" 
                  value={editingFaculty.name} 
                  onChange={e => setEditingFaculty({...editingFaculty, name: e.target.value})}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Department Branch</label>
                <select 
                  value={editingFaculty.department} 
                  onChange={e => setEditingFaculty({...editingFaculty, department: e.target.value as Department})}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
                >
                  {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>
            </div>
            <div className="flex gap-4">
              <button onClick={() => setEditingFaculty(null)} className="flex-1 px-8 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-[10px] tracking-widest">Cancel</button>
              <button onClick={saveEditedFaculty} className="flex-1 px-8 py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl flex items-center justify-center gap-2">
                <Save size={16} /> Save Changes
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Edit Subject Modal */}
      {editingSubject && (
        <div className="fixed inset-0 z-[300] bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-10 space-y-8 animate-in zoom-in duration-300">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Edit Subject</h3>
              <button onClick={() => setEditingSubject(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X /></button>
            </div>
            <div className="grid grid-cols-1 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Subject Title</label>
                <input 
                  type="text" 
                  value={editingSubject.name} 
                  onChange={e => setEditingSubject({...editingSubject, name: e.target.value})}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Semester</label>
                  <select 
                    value={editingSubject.semester} 
                    onChange={e => setEditingSubject({...editingSubject, semester: e.target.value as Semester})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
                  >
                    {SEMESTERS.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Type</label>
                  <select 
                    value={editingSubject.type} 
                    onChange={e => setEditingSubject({...editingSubject, type: e.target.value as FeedbackType})}
                    className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl font-bold outline-none focus:border-blue-600"
                  >
                    <option value={FeedbackType.THEORY}>Theory</option>
                    <option value={FeedbackType.LAB}>Lab</option>
                  </select>
                </div>
              </div>
            </div>
            <div className="flex gap-4 pt-4">
              <button onClick={() => setEditingSubject(null)} className="flex-1 px-8 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-[10px] tracking-widest">Cancel</button>
              <button onClick={saveEditedSubject} className="flex-1 px-8 py-5 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl flex items-center justify-center gap-2">
                <Save size={16} /> Update Protocol
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Control Strip */}
      <div className="flex flex-wrap items-center gap-4 bg-slate-900 p-2 rounded-[2rem] border border-slate-800 shadow-2xl">
        {[
          { id: 'bulk', label: 'Bulk Stream', icon: Zap },
          { id: 'control', label: 'Access Matrix', icon: Settings },
          { id: 'faculty', label: 'Faculty Registry', icon: Users },
          { id: 'subjects', label: 'Protocol Map', icon: BookOpen },
          { id: 'questions', label: 'Dataset Management', icon: Database },
        ].map(tab => (
          <button 
            key={tab.id} 
            onClick={() => setActiveSubTab(tab.id as any)} 
            className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeSubTab === tab.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            <tab.icon size={16} /> {tab.label}
          </button>
        ))}
        <div className="h-8 w-[1px] bg-slate-800 mx-2 hidden md:block"></div>
        <button 
          onClick={() => setIsGlobalSessionActive(!isGlobalSessionActive)}
          className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
            isGlobalSessionActive ? 'bg-emerald-600 text-white shadow-lg' : 'bg-red-600 text-white shadow-lg'
          }`}
        >
          <Power size={16} /> {isGlobalSessionActive ? 'Global Active' : 'Global Stopped'}
        </button>
      </div>

      {activeSubTab === 'bulk' && (
        <div className="bg-white p-12 rounded-[3.5rem] border border-slate-200 shadow-2xl space-y-12 animate-in zoom-in duration-300">
           <div className="flex flex-col md:flex-row justify-between items-start gap-10">
             <div className="max-w-2xl">
               <h3 className="text-3xl font-black text-slate-900 tracking-tight">Bulk Registry Injection</h3>
               <p className="text-slate-500 font-medium leading-relaxed mt-4">
                 Upload your faculty dataset. The system will auto-sync Branch-Semester interlinks 
                 and anchor the state to the blockchain ledger.
               </p>
               {lastBulkResult && (
                 <div className="mt-6 p-4 bg-blue-50 border border-blue-100 rounded-2xl flex items-center gap-3">
                   <ShieldCheck className="text-blue-600" />
                   <div className="flex flex-col">
                     <span className="text-[10px] font-black uppercase text-blue-400">Ledger Anchor Success</span>
                     <span className="text-[11px] font-mono font-bold text-blue-900 truncate max-w-[400px]">IPFS: {lastBulkResult.ipfsHash}</span>
                   </div>
                 </div>
               )}
             </div>
             <div className="flex flex-col gap-4">
               <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".csv,.json" />
               <button onClick={() => fileInputRef.current?.click()} className="px-10 py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-2xl flex items-center gap-4 transition-all hover:bg-black active:scale-95">
                 {isBulkProcessing ? <Loader2 className="animate-spin" /> : <Database size={20} />}
                 Upload & Push Dataset
               </button>
             </div>
           </div>
        </div>
      )}

      {activeSubTab === 'control' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-left duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Student Access Matrix</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Enable/Disable login gateways per Dept-Sem cohort</p>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {DEPARTMENTS.map(dept => (
              <div key={dept} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 space-y-6">
                <h4 className="font-black text-xl text-slate-900 border-b border-slate-200 pb-2">{dept}</h4>
                <div className="flex flex-wrap gap-2.5">
                  {SEMESTERS.map(sem => {
                    const active = sessionRegistry[`${dept}-${sem}`];
                    return (
                      <button 
                        key={sem} 
                        onClick={() => toggleDeptSemAccess(dept, sem)} 
                        className={`px-5 py-3 rounded-2xl text-[10px] font-black border transition-all ${
                          active ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:border-blue-600'
                        }`}
                      >
                        {sem}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'questions' && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-500">
          <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
            <div>
              <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Question Set Management</h3>
              <p className="text-[10px] text-slate-400 font-black uppercase mt-1 tracking-widest">Modify the 10 Theory / 5 Lab Assessment Protocols</p>
            </div>
            <select 
              value={editingDept} 
              onChange={(e) => setEditingDept(e.target.value as Department)}
              className="px-6 py-3 bg-white border-2 border-slate-200 rounded-2xl font-black text-[10px] uppercase outline-none"
            >
              {DEPARTMENTS.map(d => <option key={d} value={d}>{d} Branch</option>)}
            </select>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h4 className="font-black text-xs uppercase tracking-[0.2em] text-blue-600 flex items-center gap-2">
                  <FileText size={16} /> Theory Protocol
                </h4>
                <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Autosaving...</span>
              </div>
              <div className="space-y-3">
                {(theoryQuestions[editingDept] || []).map((q, i) => (
                  <div key={i} className="flex gap-4 group">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-400 transition-colors">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('theory', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium focus:bg-white focus:border-blue-400 outline-none transition-all" 
                    />
                  </div>
                ))}
              </div>
            </div>
            <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h4 className="font-black text-xs uppercase tracking-[0.2em] text-emerald-600 flex items-center gap-2">
                  <FlaskConical size={16} /> Lab Protocol
                </h4>
                <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Autosaving...</span>
              </div>
              <div className="space-y-3">
                {(labQuestions[editingDept] || []).map((q, i) => (
                  <div key={i} className="flex gap-4 group">
                    <span className="w-8 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:bg-emerald-50 group-hover:text-emerald-400 transition-colors">{i+1}</span>
                    <input 
                      type="text" 
                      value={q} 
                      onChange={(e) => updateQuestion('lab', editingDept, i, e.target.value)}
                      className="flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-medium focus:bg-white focus:border-emerald-400 outline-none transition-all" 
                    />
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {(activeSubTab === 'faculty' || activeSubTab === 'subjects') && (
        <div className="bg-white rounded-[3.5rem] border border-slate-200 shadow-sm overflow-hidden animate-in slide-up duration-500">
          <div className="p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-2xl uppercase tracking-tighter text-slate-900">Registry Verification</h3>
            <button 
              onClick={() => activeSubTab === 'faculty' ? setIsAddingFaculty(true) : setIsAddingSubject(true)} 
              className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase flex items-center gap-2 hover:bg-black transition-all active:scale-95 shadow-xl"
            >
              <Plus size={16} /> {activeSubTab === 'faculty' ? 'Add Faculty' : 'Add Subject'}
            </button>
          </div>

          {/* Inline Add Forms */}
          {(isAddingFaculty || isAddingSubject) && (
            <div className="p-10 bg-blue-50/50 border-b border-slate-100 space-y-6 animate-in slide-in-from-top duration-300">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {activeSubTab === 'faculty' ? (
                  <>
                    <input type="text" placeholder="Faculty ID" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.id} onChange={e => setNewFac({...newFac, id: e.target.value})} />
                    <input type="text" placeholder="Name" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.name} onChange={e => setNewFac({...newFac, name: e.target.value})} />
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newFac.department} onChange={e => setNewFac({...newFac, department: e.target.value as Department})}>
                      {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                    <div className="flex gap-2">
                      <button onClick={addFaculty} className="flex-1 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg hover:bg-blue-700 transition-colors">Confirm</button>
                      <button onClick={() => setIsAddingFaculty(false)} className="p-3 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-red-500 transition-colors"><X size={18} /></button>
                    </div>
                  </>
                ) : (
                  <>
                    <input type="text" placeholder="Code" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.code} onChange={e => setNewSub({...newSub, code: e.target.value})} />
                    <input type="text" placeholder="Name" className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.name} onChange={e => setNewSub({...newSub, name: e.target.value})} />
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.department} onChange={e => setNewSub({...newSub, department: e.target.value as Department})}>
                      {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                    <select className="px-4 py-3 border-2 border-slate-200 rounded-xl font-bold" value={newSub.semester} onChange={e => setNewSub({...newSub, semester: e.target.value as Semester})}>
                      {SEMESTERS.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                    <div className="flex gap-2 col-span-1 md:col-span-4 justify-end mt-4">
                      <button onClick={addSubject} className="px-8 py-3 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase shadow-lg">Add Subject</button>
                      <button onClick={() => setIsAddingSubject(false)} className="px-6 py-3 bg-white border border-slate-200 rounded-xl text-slate-400 font-black text-[10px] uppercase hover:bg-slate-100">Cancel</button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          <div className="overflow-x-auto">
             <table className="w-full">
               <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 text-left">
                 {activeSubTab === 'faculty' ? (
                   <tr><th className="p-10">ID</th><th className="p-10">Name</th><th className="p-10">Branch</th><th className="p-10 text-right">Actions</th></tr>
                 ) : (
                   <tr><th className="p-10">Code</th><th className="p-10">Title</th><th className="p-10">Semester</th><th className="p-10 text-right">Actions</th></tr>
                 )}
               </thead>
               <tbody className="divide-y divide-slate-100 text-[13px] font-bold text-slate-700">
                 {activeSubTab === 'faculty' ? faculties.map(f => (
                   <tr key={f.id} className="hover:bg-slate-50/50 group transition-colors">
                     <td className="p-10 font-black text-blue-600">{f.id}</td>
                     <td className="p-10">{f.name}</td>
                     <td className="p-10"><span className="px-4 py-1.5 bg-slate-100 rounded-xl uppercase text-[10px] font-black text-slate-500">{f.department}</span></td>
                     <td className="p-10 text-right space-x-2 opacity-0 group-hover:opacity-100 transition-all transform group-hover:translate-x-0 translate-x-4">
                       <button onClick={() => setEditingFaculty(f)} className="p-3 bg-white shadow-sm border border-slate-100 rounded-xl text-slate-400 hover:text-blue-600 hover:shadow-md transition-all"><Edit3 size={18} /></button>
                       <button onClick={() => deleteFaculty(f.id)} className="p-3 bg-white shadow-sm border border-slate-100 rounded-xl text-slate-400 hover:text-red-600 hover:shadow-md transition-all"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 )) : subjects.map((s, idx) => (
                   <tr key={idx} className="hover:bg-slate-50/50 group transition-colors">
                     <td className="p-10 font-black text-indigo-600">{s.code}</td>
                     <td className="p-10">{s.name}</td>
                     <td className="p-10 font-black text-slate-400">{s.semester}</td>
                     <td className="p-10 text-right space-x-2 opacity-0 group-hover:opacity-100 transition-all transform group-hover:translate-x-0 translate-x-4">
                       <button onClick={() => setEditingSubject(s)} className="p-3 bg-white shadow-sm border border-slate-100 rounded-xl text-slate-400 hover:text-blue-600 hover:shadow-md transition-all"><Edit3 size={18} /></button>
                       <button onClick={() => deleteSubject(s.id)} className="p-3 bg-white shadow-sm border border-slate-100 rounded-xl text-slate-400 hover:text-red-600 hover:shadow-md transition-all"><Trash2 size={18} /></button>
                     </td>
                   </tr>
                 ))}
               </tbody>
             </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
